@dataclass
class OptimizationParams:
    """Parámetros de optimización."""
    energy_weight: float = 0.3
    time_weight: float = 0.3
    smoothness_weight: float = 0.2
    safety_weight: float = 0.2
    collision_penalty: float = 1000.0
    adaptive_learning: bool = True
    cache_enabled: bool = True
    max_iterations: int = 100
    convergence_threshold: float = 1e-6


class TrajectoryOptimizer:
    """
    Optimizador de trayectorias usando Reinforcement Learning.
    
    Características:
    - Optimización de energía
    - Minimización de tiempo
    - Suavizado de movimientos
    - Evasión de colisiones
    - Compensación de vibraciones
    """
    
    def __init__(
        self,
        optimization_params: Optional[OptimizationParams] = None,
        model_path: Optional[str] = None
    ):
        """
        Inicializar optimizador de trayectorias.
        
        Args:
            optimization_params: Parámetros de optimización
            model_path: Ruta al modelo RL pre-entrenado
        """
        self.params = optimization_params or OptimizationParams()
        self.model_path = model_path
        self.model = None
        
        # Estado del optimizador
        self.learning_rate = DEFAULT_LEARNING_RATE
        self.discount_factor = DEFAULT_DISCOUNT_FACTOR
        self.epsilon = DEFAULT_EPSILON
        self.epsilon_decay = DEFAULT_EPSILON_DECAY
        self.min_epsilon = MIN_EPSILON
        
        # Historial para aprendizaje
        self.trajectory_history: List[List[TrajectoryPoint]] = []
        self.reward_history: List[float] = []
        self.experience_buffer: deque = deque(maxlen=EXPERIENCE_BUFFER_SIZE)
        
        # Caché de trayectorias optimizadas
        self.trajectory_cache: Dict[str, List[TrajectoryPoint]] = {}
        self.cache_hits = 0
        self.cache_misses = 0
        
        # Estadísticas de aprendizaje adaptativo
        self.performance_window: deque = deque(maxlen=PERFORMANCE_WINDOW_SIZE)
        self.adaptive_params = self.params.__dict__.copy()
        
        # Algoritmos disponibles
        self.algorithm: OptimizationAlgorithm = OptimizationAlgorithm.PPO
        self._algorithms = {
            OptimizationAlgorithm.PPO: PPOAlgorithm(learning_rate=self.learning_rate),
            OptimizationAlgorithm.DQN: DQNAlgorithm(),
            OptimizationAlgorithm.SAC: SACAlgorithm(learning_rate=self.learning_rate),
            OptimizationAlgorithm.TD3: TD3Algorithm(learning_rate=self.learning_rate),
            OptimizationAlgorithm.A_STAR: AStarAlgorithm(),
            OptimizationAlgorithm.RRT: RRTAlgorithm(),
            OptimizationAlgorithm.HEURISTIC: HeuristicAlgorithm(),
        }
        
        # Cargar modelo si existe
        if model_path:
            self._load_model()
        
        logger.info("Trajectory Optimizer initialized with advanced RL capabilities")
    
    def _load_model(self):
        """Cargar modelo RL pre-entrenado."""
        try:
            # Aquí se cargaría el modelo RL (DQN, PPO, etc.)
            # Por ahora, implementación placeholder
            logger.info(f"Loading RL model from {self.model_path}")
            # self.model = load_rl_model(self.model_path)
            logger.info("RL model loaded successfully")
        except Exception as e:
            logger.warning(f"Could not load RL model: {e}. Using default optimization.")
    
    @log_execution_time
    @handle_robot_errors
    def optimize_trajectory(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        constraints: Optional[Dict[str, Any]] = None
    ) -> List[TrajectoryPoint]:
        """
        Optimizar trayectoria desde punto inicial a objetivo.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos (bounding boxes)
            constraints: Restricciones adicionales
            
        Returns:
            Trayectoria optimizada
            
        Raises:
            TrajectoryEmptyError: Si no se puede generar trayectoria
            TrajectoryCollisionError: Si la trayectoria colisiona
            TrajectoryInvalidError: Si la trayectoria es inválida
            AlgorithmNotFoundError: Si el algoritmo no existe
        """
        cache_key = self._generate_cache_key(start, goal, obstacles, constraints)
        if self.params.cache_enabled and cache_key in self.trajectory_cache:
            self.cache_hits += 1
            return self.trajectory_cache[cache_key]
        
        validate_trajectory_point(start)
        validate_trajectory_point(goal)
        if obstacles:
            validate_obstacles(obstacles)
        
        if logger.isEnabledFor(logging.INFO):
            logger.info(f"Optimizing trajectory from {start.position} to {goal.position}")
        
        increment_counter("trajectory_optimization.requests")
        self.cache_misses += 1
        increment_counter("trajectory_optimization.cache_misses")
        
        # Inicializar trayectoria básica
        trajectory = self._generate_initial_trajectory(start, goal)
        
        # Aplicar optimización iterativa
        best_trajectory = trajectory
        best_reward = float('-inf')
        
        with measure_time("trajectory_optimization.total_time", {"algorithm": self.algorithm.value}):
            for iteration in range(self.params.max_iterations):
                # Aplicar optimización según algoritmo seleccionado
                algorithm_instance = self._algorithms.get(self.algorithm)
                if algorithm_instance:
                    try:
                        trajectory = algorithm_instance.optimize(
                            start,
                            goal,
                            obstacles,
                            constraints,
                            initial_trajectory=trajectory
                        )
                    except Exception as e:
                        logger.warning(f"Algorithm {self.algorithm.value} failed: {e}, using fallback")
                        algorithm_instance = self._algorithms[OptimizationAlgorithm.HEURISTIC]
                        trajectory = algorithm_instance.optimize(
                            start,
                            goal,
                            obstacles,
                            constraints,
                            initial_trajectory=trajectory
                        )
                else:
                    raise AlgorithmNotFoundError(self.algorithm.value)
                
                # Aplicar optimización de energía
                if self.params.energy_weight > 0:
                    trajectory = self._optimize_energy(trajectory)
                
                # Aplicar compensación de vibraciones
                trajectory = self._compensate_vibrations(trajectory)
                
                # Calcular recompensa
                reward = self.calculate_reward(trajectory, obstacles)
                
                # Guardar mejor trayectoria
                if reward > best_reward:
                    best_reward = reward
                    best_trajectory = trajectory.copy()
                
                # Verificar convergencia
                if iteration > 0:
                    reward_diff = abs(reward - best_reward)
                    if reward_diff < self.params.convergence_threshold:
                        logger.debug(f"Converged at iteration {iteration}")
                        break
        
        trajectory = best_trajectory
        
        # Validar trayectoria
        self._validate_trajectory(trajectory, obstacles)
        
        # Guardar en caché
        if self.params.cache_enabled:
            self.trajectory_cache[cache_key] = trajectory
            # Limpiar caché si es muy grande
            if len(self.trajectory_cache) > CACHE_CLEANUP_THRESHOLD:
                # Eliminar porcentaje más antiguos
                num_to_remove = int(len(self.trajectory_cache) * CACHE_CLEANUP_PERCENTAGE)
                keys_to_remove = list(self.trajectory_cache.keys())[:num_to_remove]
                for key in keys_to_remove:
                    del self.trajectory_cache[key]
        
        # Guardar en historial y experiencia
        self.trajectory_history.append(trajectory)
        self.reward_history.append(best_reward)
        self.performance_window.append(best_reward)
        
        # Registrar métricas
        record_value("trajectory_optimization.reward", best_reward)
        record_value("trajectory_optimization.trajectory_length", len(trajectory))
        if len(trajectory) > 0:
            from .utils.trajectory_utils import calculate_trajectory_distance
            distance = calculate_trajectory_distance(trajectory)
            record_value("trajectory_optimization.distance", distance)
        
        # Emitir evento
        emitter = get_event_emitter()
        emitter.emit(
            EventType.TRAJECTORY_OPTIMIZED,
            data={
                "trajectory_length": len(trajectory),
                "reward": best_reward,
                "algorithm": self.algorithm.value,
                "distance": distance if len(trajectory) > 0 else 0.0
            },
            source="trajectory_optimizer"
        )
        
        # Aprendizaje adaptativo
        if self.params.adaptive_learning:
            self._adaptive_learning_update()
        
        # Actualizar epsilon para exploración
        self.epsilon = max(self.min_epsilon, self.epsilon * self.epsilon_decay)
        
        return trajectory
    
    def _generate_cache_key(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]],
        constraints: Optional[Dict[str, Any]]
    ) -> str:
        """Generar clave única para caché."""
        key_data = {
            "start_pos": start.position.tolist(),
            "goal_pos": goal.position.tolist(),
            "obstacles": [obs.tolist() if isinstance(obs, np.ndarray) else obs for obs in (obstacles or [])],
            "constraints": constraints or {}
        }
        key_str = json.dumps(key_data, sort_keys=True)
        return hashlib.md5(key_str.encode()).hexdigest()
    
    def _generate_initial_trajectory(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        num_points: int = DEFAULT_TRAJECTORY_POINTS
    ) -> List[TrajectoryPoint]:
        """Generar trayectoria inicial (interpolación lineal)."""
        return generate_linear_trajectory(start, goal, num_points)
    
    
    
    def _adaptive_learning_update(self):
        """Actualizar parámetros adaptativamente basado en rendimiento."""
        if len(self.performance_window) < 10:
            return
        
        # Calcular rendimiento promedio reciente
        recent_performance = np.mean(list(self.performance_window)[-10:])
        older_performance = np.mean(list(self.performance_window)[-20:-10]) if len(self.performance_window) >= 20 else recent_performance
        
        # Si el rendimiento está mejorando, mantener parámetros
        # Si está empeorando, ajustar pesos
        if recent_performance < older_performance * 0.9:
            # Rendimiento empeorando, ajustar pesos
            logger.debug("Performance decreasing, adjusting optimization parameters")
            
            # Aumentar peso de seguridad
            self.adaptive_params['safety_weight'] = min(
                self.adaptive_params['safety_weight'] * 1.1,
                0.5
            )
            
            # Reducir peso de tiempo (priorizar seguridad)
            self.adaptive_params['time_weight'] = max(
                self.adaptive_params['time_weight'] * 0.9,
                0.1
            )
        elif recent_performance > older_performance * 1.1:
            # Rendimiento mejorando, podemos ser más agresivos
            logger.debug("Performance improving, optimizing for speed")
            
            # Aumentar peso de tiempo
            self.adaptive_params['time_weight'] = min(
                self.adaptive_params['time_weight'] * 1.05,
                0.5
            )
    
    
    def _optimize_energy(self, trajectory: List[TrajectoryPoint]) -> List[TrajectoryPoint]:
        """Optimizar trayectoria para minimizar consumo de energía."""
        logger.debug("Optimizing energy consumption")
        
        # Reducir aceleraciones bruscas
        optimized = []
        
        for i, point in enumerate(trajectory):
            if i == 0 or i == len(trajectory) - 1:
                optimized.append(point)
                continue
            
            # Reducir aceleración si es muy alta
            if point.acceleration is not None:
                accel_magnitude = np.linalg.norm(point.acceleration)
                if accel_magnitude > 2.0:  # m/s²
                    # Reducir aceleración gradualmente
                    scale_factor = 2.0 / accel_magnitude
                    new_accel = point.acceleration * scale_factor
                    
                    optimized_point = TrajectoryPoint(
                        position=point.position,
                        orientation=point.orientation,
                        velocity=point.velocity,
                        acceleration=new_accel,
                        timestamp=point.timestamp
                    )
                    optimized.append(optimized_point)
                else:
                    optimized.append(point)
            else:
                optimized.append(point)
        
        return optimized
    
    def _compensate_vibrations(self, trajectory: List[TrajectoryPoint]) -> List[TrajectoryPoint]:
        """Compensar vibraciones en la trayectoria."""
        logger.debug("Compensating vibrations")
        
        # Aplicar filtro de paso bajo para reducir vibraciones de alta frecuencia
        compensated = []
        
        for i, point in enumerate(trajectory):
            if i < 2 or i >= len(trajectory) - 2:
                compensated.append(point)
                continue
            
            # Filtro de media móvil para posición
            window = trajectory[max(0, i-2):min(len(trajectory), i+3)]
            avg_position = np.mean([p.position for p in window], axis=0)
            
            compensated_point = TrajectoryPoint(
                position=avg_position,
                orientation=point.orientation,
                velocity=point.velocity,
                acceleration=point.acceleration,
                timestamp=point.timestamp
            )
            compensated.append(compensated_point)
        
        return compensated
    
    def _validate_trajectory(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]]
    ):
        """
        Validar que la trayectoria es segura y factible.
        
        Raises:
            TrajectoryEmptyError: Si la trayectoria está vacía
            TrajectoryCollisionError: Si hay colisiones
            TrajectoryInvalidError: Si la trayectoria es inválida
        """
        # Usar validador centralizado
        try:
            validate_trajectory(trajectory)
        except TrajectoryInvalidError as e:
            raise e
        
        # Verificar colisiones con obstáculos
        if obstacles:
            for point in trajectory:
                for obstacle in obstacles:
                    if point_in_obstacle(point.position, obstacle):
                        raise TrajectoryCollisionError(point.position, obstacle)
    
    def calculate_reward(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]] = None
    ) -> float:
        """
        Calcular recompensa para aprendizaje por refuerzo.
        
        Returns:
            Valor de recompensa (mayor es mejor)
        """
        reward = 0.0
        
        # Recompensa por tiempo (más rápido es mejor)
        total_time = trajectory[-1].timestamp - trajectory[0].timestamp
        time_reward = 1.0 / (total_time + 0.1)
        reward += self.params.time_weight * time_reward
        
        # Recompensa por suavidad
        smoothness = self._calculate_smoothness(trajectory)
        reward += self.params.smoothness_weight * smoothness
        
        # Recompensa por eficiencia energética
        energy_efficiency = self._calculate_energy_efficiency(trajectory)
        reward += self.params.energy_weight * energy_efficiency
        
        # Penalización por colisiones
        if obstacles:
            collision_penalty = self._check_collisions(trajectory, obstacles)
            reward -= collision_penalty * self.params.collision_penalty
        
        return reward
    
    def _calculate_smoothness(self, trajectory: List[TrajectoryPoint]) -> float:
        """Calcular suavidad de la trayectoria."""
        if len(trajectory) < 2:
            return 0.0
        
        # Usar utilidad para calcular curvatura
        avg_curvature = calculate_trajectory_curvature(trajectory)
        smoothness = 1.0 / (1.0 + avg_curvature)  # Invertir: menor curvatura = mayor suavidad
        return smoothness
    
    def _calculate_energy_efficiency(self, trajectory: List[TrajectoryPoint]) -> float:
        """Calcular eficiencia energética."""
        if not trajectory:
            return 0.0
        
        total_energy = 0.0
        
        if USE_PERFORMANCE_UTILS:
            try:
                from .performance import euclidean_distance_fast
                for point in trajectory:
                    if point.velocity is not None and point.acceleration is not None:
                        kinetic = 0.5 * (euclidean_distance_fast(point.velocity, np.zeros_like(point.velocity)) ** 2)
                        accel_energy = euclidean_distance_fast(point.acceleration, np.zeros_like(point.acceleration))
                        total_energy += kinetic + accel_energy
            except Exception:
                for point in trajectory:
                    if point.velocity is not None and point.acceleration is not None:
                        kinetic = 0.5 * np.linalg.norm(point.velocity) ** 2
                        accel_energy = np.linalg.norm(point.acceleration)
                        total_energy += kinetic + accel_energy
        else:
            for point in trajectory:
                if point.velocity is not None and point.acceleration is not None:
                    kinetic = 0.5 * np.linalg.norm(point.velocity) ** 2
                    accel_energy = np.linalg.norm(point.acceleration)
                    total_energy += kinetic + accel_energy
        
        efficiency = 1.0 / (total_energy + 0.1)
        return min(efficiency, 1.0)
    
    def _check_collisions(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: List[np.ndarray]
    ) -> float:
        """Verificar colisiones y retornar penalización."""
        if not obstacles or not trajectory:
            return 0.0
        
        if USE_PERFORMANCE_UTILS:
            try:
                traj_len = len(trajectory)
                obs_len = len(obstacles)
                if traj_len > 0 and obs_len > 0:
                    trajectory_array = np.empty((traj_len, 3), dtype=np.float64)
                    for i, p in enumerate(trajectory):
                        trajectory_array[i] = p.position
                    obstacles_array = np.array(obstacles, dtype=np.float64)
                    collisions = check_trajectory_collisions(trajectory_array, obstacles_array)
                    return float(np.sum(collisions))
            except Exception:
                pass
        
        collision_count = 0.0
        for point in trajectory:
            for obstacle in obstacles:
                if point_in_obstacle(point.position, obstacle):
                    collision_count += 1.0
                    break
        
        return collision_count
    
    def get_statistics(self) -> Dict[str, Any]:
        """Obtener estadísticas del optimizador."""
        cache_hit_rate = (
            self.cache_hits / (self.cache_hits + self.cache_misses)
            if (self.cache_hits + self.cache_misses) > 0
            else 0.0
        )
        
        avg_reward = (
            np.mean(self.reward_history) if self.reward_history else 0.0
        )
        
        return {
            "cache_hits": self.cache_hits,
            "cache_misses": self.cache_misses,
            "cache_hit_rate": cache_hit_rate,
            "cache_size": len(self.trajectory_cache),
            "total_trajectories": len(self.trajectory_history),
            "average_reward": avg_reward,
            "recent_performance": (
                np.mean(list(self.performance_window)) if self.performance_window else 0.0
            ),
            "epsilon": self.epsilon,
            "algorithm": self.algorithm.value,
            "adaptive_params": self.adaptive_params.copy()
        }
    
    def reset_statistics(self):
        """Resetear estadísticas."""
        self.cache_hits = 0
        self.cache_misses = 0
        self.performance_window.clear()
        logger.info("Optimizer statistics reset")
    
    def optimize_with_astar(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        grid_resolution: Optional[float] = None
    ) -> List[TrajectoryPoint]:
        """
        Optimizar trayectoria usando algoritmo A*.
        
        A* es un algoritmo de búsqueda en grafos que encuentra el camino
        más corto entre dos puntos considerando obstáculos.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            grid_resolution: Resolución del grid para discretización
            
        Returns:
            Trayectoria optimizada
        """
        logger.debug("Using A* algorithm for trajectory optimization")
        
        # Usar algoritmo A* del módulo de algoritmos
        astar_algorithm = self._algorithms[OptimizationAlgorithm.A_STAR]
        if grid_resolution is not None:
            astar_algorithm = AStarAlgorithm(grid_resolution=grid_resolution)
        
        return astar_algorithm.optimize(start, goal, obstacles, constraints)
    
    def optimize_with_rrt(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        max_iterations: Optional[int] = None,
        step_size: Optional[float] = None
    ) -> List[TrajectoryPoint]:
        """
        Optimizar trayectoria usando Rapidly-exploring Random Tree (RRT).
        
        RRT es útil para espacios con muchos obstáculos.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            max_iterations: Máximo de iteraciones
            step_size: Tamaño del paso
            
        Returns:
            Trayectoria optimizada
        """
        logger.debug("Using RRT algorithm for trajectory optimization")
        
        # Usar algoritmo RRT del módulo de algoritmos
        rrt_algorithm = self._algorithms[OptimizationAlgorithm.RRT]
        if max_iterations is not None or step_size is not None:
            rrt_algorithm = RRTAlgorithm(
                max_iterations=max_iterations or DEFAULT_RRT_MAX_ITERATIONS,
                step_size=step_size or DEFAULT_RRT_STEP_SIZE
            )
        
        return rrt_algorithm.optimize(start, goal, obstacles, constraints)
    
    def analyze_trajectory(self, trajectory: List[TrajectoryPoint]) -> Dict[str, Any]:
        """
        Analizar trayectoria y retornar métricas detalladas.
        
        Returns:
            Diccionario con análisis completo
        """
        if not trajectory:
            return {}
        
        # Calcular métricas usando utilidades
        total_distance = calculate_trajectory_distance(trajectory)
        avg_curvature = calculate_trajectory_curvature(trajectory)
        
        # Calcular velocidades y aceleraciones
        max_velocity = 0.0
        max_acceleration = 0.0
        
        for point in trajectory:
            if point.velocity is not None:
                velocity = np.linalg.norm(point.velocity)
                max_velocity = max(max_velocity, velocity)
            
            if point.acceleration is not None:
                acceleration = np.linalg.norm(point.acceleration)
                max_acceleration = max(max_acceleration, acceleration)
        
        duration = trajectory[-1].timestamp - trajectory[0].timestamp
        avg_speed = total_distance / duration if duration > 0 else 0.0
        
        return {
            "total_distance": total_distance,
            "duration": duration,
            "average_speed": avg_speed,
            "max_velocity": max_velocity,
            "max_acceleration": max_acceleration,
            "average_curvature": avg_curvature,
            "smoothness": self._calculate_smoothness(trajectory),
            "energy_efficiency": self._calculate_energy_efficiency(trajectory),
            "num_points": len(trajectory),
            "start_position": trajectory[0].position.tolist(),
            "goal_position": trajectory[-1].position.tolist()
        }
    
    def export_trajectory(
        self,
        trajectory: List[TrajectoryPoint],
        filepath: str,
        format: str = "json"
    ) -> bool:
        """
        Exportar trayectoria a archivo.
        
        Args:
            trajectory: Trayectoria a exportar
            filepath: Ruta del archivo
            format: Formato ("json", "csv")
            
        Returns:
            True si se exportó exitosamente
        """
        try:
            if format == "json":
                import json
                data = {
                    "points": [
                        {
                            "position": p.position.tolist(),
                            "orientation": p.orientation.tolist(),
                            "velocity": p.velocity.tolist() if p.velocity is not None else None,
                            "acceleration": p.acceleration.tolist() if p.acceleration is not None else None,
                            "timestamp": p.timestamp
                        }
                        for p in trajectory
                    ],
                    "analysis": self.analyze_trajectory(trajectory)
                }
                with open(filepath, 'w') as f:
                    json.dump(data, f, indent=2)
            
            elif format == "csv":
                import csv
                with open(filepath, 'w', newline='') as f:
                    writer = csv.writer(f)
                    writer.writerow([
                        "timestamp", "x", "y", "z",
                        "qx", "qy", "qz", "qw",
                        "vx", "vy", "vz",
                        "ax", "ay", "az"
                    ])
                    for p in trajectory:
                        writer.writerow([
                            p.timestamp,
                            *p.position.tolist(),
                            *p.orientation.tolist(),
                            *(p.velocity.tolist() if p.velocity is not None else [0, 0, 0]),
                            *(p.acceleration.tolist() if p.acceleration is not None else [0, 0, 0])
                        ])
            
            logger.info(f"Trajectory exported to {filepath}")
            return True
        
        except Exception as e:
            logger.error(f"Error exporting trajectory: {e}", exc_info=True)
            return False
    
    def import_trajectory(self, filepath: str) -> Optional[List[TrajectoryPoint]]:
        """
        Importar trayectoria desde archivo.
        
        Args:
            filepath: Ruta del archivo
            
        Returns:
            Trayectoria importada o None si falla
        """
        try:
            import json
            
            with open(filepath, 'r') as f:
                data = json.load(f)
            
            trajectory = []
            for point_data in data.get("points", []):
                point = TrajectoryPoint(
                    position=np.array(point_data["position"]),
                    orientation=np.array(point_data["orientation"]),
                    velocity=np.array(point_data["velocity"]) if point_data.get("velocity") else None,
                    acceleration=np.array(point_data["acceleration"]) if point_data.get("acceleration") else None,
                    timestamp=point_data.get("timestamp", 0.0)
                )
                trajectory.append(point)
            
            logger.info(f"Trajectory imported from {filepath}")
            return trajectory
        
        except Exception as e:
            logger.error(f"Error importing trajectory: {e}", exc_info=True)
            return None
    
    def optimize_multi_objective(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        objectives: Optional[Dict[str, float]] = None
    ) -> List[TrajectoryPoint]:
        """
        Optimización multi-objetivo usando algoritmo NSGA-II simplificado.
        
        Optimiza múltiples objetivos simultáneamente:
        - Tiempo
        - Energía
        - Suavidad
        - Seguridad
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Obstáculos
            objectives: Pesos de objetivos personalizados
            
        Returns:
            Mejor trayectoria según objetivos
        """
        logger.debug("Using multi-objective optimization")
        
        if objectives is None:
            objectives = {
                "time": 0.25,
                "energy": 0.25,
                "smoothness": 0.25,
                "safety": 0.25
            }
        
        # Generar múltiples trayectorias candidatas
        candidates = []
        for _ in range(10):  # 10 candidatos
            trajectory = self.optimize_trajectory(start, goal, obstacles)
            candidates.append(trajectory)
        
        # Evaluar cada candidato
        scores = []
        for traj in candidates:
            score = 0.0
            
            # Tiempo (inverso)
            duration = traj[-1].timestamp - traj[0].timestamp
            time_score = 1.0 / (duration + 0.1)
            score += objectives.get("time", 0.25) * time_score
            
            # Energía (eficiencia)
            energy_score = self._calculate_energy_efficiency(traj)
            score += objectives.get("energy", 0.25) * energy_score
            
            # Suavidad
            smoothness_score = self._calculate_smoothness(traj)
            score += objectives.get("smoothness", 0.25) * smoothness_score
            
            # Seguridad (distancia a obstáculos)
            safety_score = 1.0
            if obstacles:
                min_distances = []
                for point in traj:
                    for obstacle in obstacles:
                        obstacle_center = (obstacle[:3] + obstacle[3:]) / 2
                        dist = np.linalg.norm(point.position - obstacle_center)
                        min_distances.append(dist)
                if min_distances:
                    min_dist = min(min_distances)
                    safety_score = min(1.0, min_dist / 0.2)  # Normalizar a 20cm
            score += objectives.get("safety", 0.25) * safety_score
            
            scores.append(score)
        
        # Seleccionar mejor candidato
        best_idx = np.argmax(scores)
        return candidates[best_idx]
    
    def optimize_with_splines(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        waypoints: Optional[List[TrajectoryPoint]] = None,
        obstacles: Optional[List[np.ndarray]] = None,
        smoothness: float = 0.5
    ) -> List[TrajectoryPoint]:
        """
        Optimizar trayectoria usando splines cúbicos para suavidad.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            waypoints: Puntos intermedios opcionales
            obstacles: Lista de obstáculos
            smoothness: Factor de suavidad (0-1)
            
        Returns:
            Trayectoria optimizada con splines
        """
        logger.debug("Using spline-based trajectory optimization")
        
        try:
            from scipy.interpolate import CubicSpline
        except ImportError:
            logger.warning("scipy not available, using linear interpolation")
            return self._generate_initial_trajectory(start, goal)
        
        # Construir lista de puntos
        points = [start]
        if waypoints:
            points.extend(waypoints)
        points.append(goal)
        
        # Extraer posiciones
        positions = np.array([p.position for p in points])
        
        # Crear parámetro de arco
        distances = np.zeros(len(positions))
        for i in range(1, len(positions)):
            distances[i] = distances[i-1] + np.linalg.norm(positions[i] - positions[i-1])
        
        # Normalizar
        if distances[-1] > 0:
            distances = distances / distances[-1]
        
        # Crear splines para cada dimensión
        num_points = DEFAULT_TRAJECTORY_POINTS
        t_new = np.linspace(0, 1, num_points)
        
        trajectory = []
        for dim in range(3):
            cs = CubicSpline(distances, positions[:, dim], bc_type='natural')
            positions_new = cs(t_new)
            
            if dim == 0:
                x_positions = positions_new
            elif dim == 1:
                y_positions = positions_new
            else:
                z_positions = positions_new
        
        # Construir trayectoria
        for i in range(num_points):
            position = np.array([x_positions[i], y_positions[i], z_positions[i]])
            
            # Interpolación de orientación
            alpha = i / (num_points - 1)
            orientation = quaternion_slerp(start.orientation, goal.orientation, alpha)
            
            # Calcular velocidades (derivada del spline)
            if i < num_points - 1:
                velocity = (np.array([x_positions[i+1], y_positions[i+1], z_positions[i+1]]) - position) / DEFAULT_TIMESTEP
            else:
                velocity = np.zeros(3)
            
            point = TrajectoryPoint(
                position=position,
                orientation=orientation,
                velocity=velocity,
                acceleration=np.zeros(3),
                timestamp=i * DEFAULT_TIMESTEP
            )
            trajectory.append(point)
        
        # Aplicar optimizaciones adicionales
        trajectory = self._compensate_vibrations(trajectory)
        if obstacles:
            trajectory = self._avoid_obstacles(trajectory, obstacles)
        
        return trajectory
    
    def _avoid_obstacles(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: List[np.ndarray],
        safety_margin: float = 0.1
    ) -> List[TrajectoryPoint]:
        """Ajustar trayectoria para evitar obstáculos con margen de seguridad."""
        adjusted = []
        
        for point in trajectory:
            adjusted_point = point
            min_distance = float('inf')
            
            for obstacle in obstacles:
                obstacle_center = (obstacle[:3] + obstacle[3:]) / 2
                distance = np.linalg.norm(point.position - obstacle_center)
                min_distance = min(min_distance, distance)
                
                # Si está muy cerca, ajustar posición
                if distance < safety_margin:
                    direction = (point.position - obstacle_center)
                    if np.linalg.norm(direction) > 0:
                        direction = direction / np.linalg.norm(direction)
                        new_position = obstacle_center + direction * safety_margin
                        
                        adjusted_point = TrajectoryPoint(
                            position=new_position,
                            orientation=point.orientation,
                            velocity=point.velocity,
                            acceleration=point.acceleration,
                            timestamp=point.timestamp
                        )
            
            adjusted.append(adjusted_point)
        
        return adjusted
    
    def compare_trajectories(
        self,
        trajectory1: List[TrajectoryPoint],
        trajectory2: List[TrajectoryPoint]
    ) -> Dict[str, Any]:
        """
        Comparar dos trayectorias y retornar métricas comparativas.
        
        Args:
            trajectory1: Primera trayectoria
            trajectory2: Segunda trayectoria
            
        Returns:
            Diccionario con comparación
        """
        analysis1 = self.analyze_trajectory(trajectory1)
        analysis2 = self.analyze_trajectory(trajectory2)
        
        return {
            "trajectory1": analysis1,
            "trajectory2": analysis2,
            "comparison": {
                "distance_diff": analysis1["total_distance"] - analysis2["total_distance"],
                "duration_diff": analysis1["duration"] - analysis2["duration"],
                "speed_diff": analysis1["average_speed"] - analysis2["average_speed"],
                "smoothness_diff": analysis1["smoothness"] - analysis2["smoothness"],
                "energy_efficiency_diff": analysis1["energy_efficiency"] - analysis2["energy_efficiency"],
                "better_distance": "trajectory2" if analysis2["total_distance"] < analysis1["total_distance"] else "trajectory1",
                "better_time": "trajectory2" if analysis2["duration"] < analysis1["duration"] else "trajectory1",
                "better_smoothness": "trajectory2" if analysis2["smoothness"] > analysis1["smoothness"] else "trajectory1"
            }
        }
    
    def optimize_batch(
        self,
        tasks: List[Tuple[TrajectoryPoint, TrajectoryPoint, Optional[List[np.ndarray]]]],
        parallel: bool = False,
        max_workers: Optional[int] = None
    ) -> List[List[TrajectoryPoint]]:
        """
        Optimizar múltiples trayectorias en lote.
        
        Args:
            tasks: Lista de tuplas (start, goal, obstacles)
            parallel: Si usar procesamiento paralelo
            max_workers: Número máximo de workers
            
        Returns:
            Lista de trayectorias optimizadas
        """
        if parallel:
            try:
                from concurrent.futures import ThreadPoolExecutor, as_completed
                
                def optimize_task(task):
                    start, goal, obstacles = task
                    return self.optimize_trajectory(start, goal, obstacles)
                
                results = []
                with ThreadPoolExecutor(max_workers=max_workers) as executor:
                    futures = {executor.submit(optimize_task, task): task for task in tasks}
                    
                    for future in as_completed(futures):
                        try:
                            result = future.result()
                            results.append(result)
                        except Exception as e:
                            logger.error(f"Error in parallel optimization: {e}", exc_info=True)
                            results.append([])
                
                return results
            except ImportError:
                logger.warning("concurrent.futures not available, using sequential processing")
                parallel = False
        
        # Procesamiento secuencial
        results = []
        for start, goal, obstacles in tasks:
            try:
                trajectory = self.optimize_trajectory(start, goal, obstacles)
                results.append(trajectory)
            except Exception as e:
                logger.error(f"Error optimizing trajectory: {e}", exc_info=True)
                results.append([])
        
        return results
    
    def refine_trajectory(
        self,
        trajectory: List[TrajectoryPoint],
        iterations: int = 5,
        obstacles: Optional[List[np.ndarray]] = None
    ) -> List[TrajectoryPoint]:
        """
        Refinar una trayectoria existente mediante optimización iterativa.
        
        Args:
            trajectory: Trayectoria inicial
            iterations: Número de iteraciones de refinamiento
            obstacles: Lista de obstáculos
            
        Returns:
            Trayectoria refinada
        """
        if not trajectory or len(trajectory) < 2:
            return trajectory
        
        refined = trajectory.copy()
        
        for iteration in range(iterations):
            # Aplicar suavizado
            refined = self._compensate_vibrations(refined)
            
            # Optimizar energía
            refined = self._optimize_energy(refined)
            
            # Evitar obstáculos si existen
            if obstacles:
                refined = self._avoid_obstacles(refined, obstacles)
            
            # Verificar mejora
            current_reward = self.calculate_reward(refined, obstacles)
            if iteration > 0:
                prev_reward = self.calculate_reward(trajectory, obstacles)
                if current_reward <= prev_reward:
                    logger.debug(f"Refinement converged at iteration {iteration}")
                    break
        
        return refined
    
    def calculate_safety_metrics(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]] = None
    ) -> Dict[str, float]:
        """
        Calcular métricas de seguridad de la trayectoria.
        
        Args:
            trajectory: Trayectoria a analizar
            obstacles: Lista de obstáculos
            
        Returns:
            Diccionario con métricas de seguridad
        """
        metrics = {
            "min_distance_to_obstacle": float('inf'),
            "avg_distance_to_obstacle": 0.0,
            "collision_risk": 0.0,
            "safety_margin": 0.0
        }
        
        if not obstacles or not trajectory:
            return metrics
        
        distances = []
        collision_points = 0
        
        for point in trajectory:
            min_dist = float('inf')
            for obstacle in obstacles:
                obstacle_center = (obstacle[:3] + obstacle[3:]) / 2
                dist = np.linalg.norm(point.position - obstacle_center)
                min_dist = min(min_dist, dist)
                
                if point_in_obstacle(point.position, obstacle):
                    collision_points += 1
            
            distances.append(min_dist)
            metrics["min_distance_to_obstacle"] = min(
                metrics["min_distance_to_obstacle"],
                min_dist
            )
        
        if distances:
            metrics["avg_distance_to_obstacle"] = np.mean(distances)
            metrics["collision_risk"] = collision_points / len(trajectory)
            metrics["safety_margin"] = metrics["min_distance_to_obstacle"] / 0.2  # Normalizar
        
        return metrics
    
    def export_trajectory_3d(
        self,
        trajectory: List[TrajectoryPoint],
        filepath: str,
        format: str = "obj"
    ) -> bool:
        """
        Exportar trayectoria en formato 3D para visualización.
        
        Args:
            trajectory: Trayectoria a exportar
            filepath: Ruta del archivo
            format: Formato ("obj", "ply")
            
        Returns:
            True si se exportó exitosamente
        """
        try:
            if format == "obj":
                with open(filepath, 'w') as f:
                    f.write("# Trajectory OBJ file\n")
                    f.write(f"# Points: {len(trajectory)}\n\n")
                    
                    # Escribir vértices
                    for i, point in enumerate(trajectory):
                        pos = point.position
                        f.write(f"v {pos[0]:.6f} {pos[1]:.6f} {pos[2]:.6f}\n")
                    
                    # Escribir línea
                    f.write("\n")
                    f.write("l")
                    for i in range(1, len(trajectory) + 1):
                        f.write(f" {i}")
                    f.write("\n")
                
                logger.info(f"3D trajectory exported to {filepath}")
                return True
            
            elif format == "ply":
                with open(filepath, 'w') as f:
                    f.write("ply\n")
                    f.write("format ascii 1.0\n")
                    f.write(f"element vertex {len(trajectory)}\n")
                    f.write("property float x\n")
                    f.write("property float y\n")
                    f.write("property float z\n")
                    f.write(f"element edge {len(trajectory) - 1}\n")
                    f.write("property int vertex1\n")
                    f.write("property int vertex2\n")
                    f.write("end_header\n")
                    
                    # Vértices
                    for point in trajectory:
                        pos = point.position
                        f.write(f"{pos[0]:.6f} {pos[1]:.6f} {pos[2]:.6f}\n")
                    
                    # Aristas
                    for i in range(len(trajectory) - 1):
                        f.write(f"{i} {i+1}\n")
                
                logger.info(f"3D trajectory exported to {filepath}")
                return True
            
            else:
                logger.error(f"Unsupported 3D format: {format}")
                return False
                
        except Exception as e:
            logger.error(f"Error exporting 3D trajectory: {e}", exc_info=True)
            return False
    
    def get_optimization_report(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]] = None
    ) -> Dict[str, Any]:
        """
        Generar reporte completo de optimización.
        
        Args:
            trajectory: Trayectoria optimizada
            obstacles: Lista de obstáculos
            
        Returns:
            Diccionario con reporte completo
        """
        analysis = self.analyze_trajectory(trajectory)
        safety = self.calculate_safety_metrics(trajectory, obstacles)
        reward = self.calculate_reward(trajectory, obstacles)
        
        return {
            "trajectory_analysis": analysis,
            "safety_metrics": safety,
            "reward": reward,
            "optimization_params": {
                "algorithm": self.algorithm.value,
                "energy_weight": self.params.energy_weight,
                "time_weight": self.params.time_weight,
                "smoothness_weight": self.params.smoothness_weight,
                "safety_weight": self.params.safety_weight
            },
            "statistics": self.get_statistics(),
            "recommendations": self._generate_recommendations(analysis, safety, reward)
        }
    
    def _generate_recommendations(
        self,
        analysis: Dict[str, Any],
        safety: Dict[str, float],
        reward: float
    ) -> List[str]:
        """Generar recomendaciones basadas en análisis."""
        recommendations = []
        
        if safety.get("collision_risk", 0) > 0:
            recommendations.append("⚠️ Trayectoria tiene riesgo de colisión - revisar obstáculos")
        
        if safety.get("min_distance_to_obstacle", float('inf')) < 0.1:
            recommendations.append("⚠️ Distancia mínima a obstáculos muy baja - aumentar margen de seguridad")
        
        if analysis.get("max_acceleration", 0) > 5.0:
            recommendations.append("⚠️ Aceleración máxima muy alta - considerar suavizar trayectoria")
        
        if analysis.get("smoothness", 0) < 0.5:
            recommendations.append("💡 Trayectoria podría ser más suave - usar splines")
        
        if analysis.get("energy_efficiency", 0) < 0.3:
            recommendations.append("💡 Eficiencia energética baja - optimizar aceleraciones")
        
        if reward < 0:
            recommendations.append("❌ Recompensa negativa - trayectoria necesita optimización")
        
        if not recommendations:
            recommendations.append("✅ Trayectoria optimizada correctamente")
        
        return recommendations
    
    def visualize_trajectory_data(
        self,
        trajectory: List[TrajectoryPoint],
        save_path: Optional[str] = None
    ) -> Optional[Dict[str, Any]]:
        """
        Generar datos para visualización de trayectoria.
        
        Args:
            trajectory: Trayectoria a visualizar
            save_path: Ruta opcional para guardar datos
            
        Returns:
            Diccionario con datos de visualización
        """
        if not trajectory:
            return None
        
        # Extraer datos
        positions = np.array([p.position for p in trajectory])
        velocities = np.array([p.velocity if p.velocity is not None else np.zeros(3) for p in trajectory])
        accelerations = np.array([p.acceleration if p.acceleration is not None else np.zeros(3) for p in trajectory])
        timestamps = np.array([p.timestamp for p in trajectory])
        
        visualization_data = {
            "positions": positions.tolist(),
            "velocities": velocities.tolist(),
            "accelerations": accelerations.tolist(),
            "timestamps": timestamps.tolist(),
            "distance": calculate_trajectory_distance(trajectory),
            "duration": timestamps[-1] - timestamps[0] if len(timestamps) > 1 else 0.0,
            "num_points": len(trajectory)
        }
        
        if save_path:
            try:
                import json
                with open(save_path, 'w') as f:
                    json.dump(visualization_data, f, indent=2)
                logger.info(f"Visualization data saved to {save_path}")
            except Exception as e:
                logger.error(f"Error saving visualization data: {e}", exc_info=True)
        
        return visualization_data
    
    def optimize_with_dynamic_obstacles(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        obstacle_velocities: Optional[List[np.ndarray]] = None,
        time_horizon: float = 5.0
    ) -> List[TrajectoryPoint]:
        """
        Optimizar trayectoria considerando obstáculos dinámicos.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos (posiciones iniciales)
            obstacle_velocities: Velocidades de los obstáculos
            time_horizon: Horizonte temporal para predicción
            
        Returns:
            Trayectoria optimizada que evita obstáculos dinámicos
        """
        logger.debug("Optimizing trajectory with dynamic obstacles")
        
        if not obstacles or not obstacle_velocities:
            return self.optimize_trajectory(start, goal, obstacles)
        
        # Generar trayectoria inicial
        trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        # Ajustar para obstáculos dinámicos
        adjusted_trajectory = []
        for i, point in enumerate(trajectory):
            adjusted_point = point
            t = point.timestamp
            
            # Predecir posiciones de obstáculos en tiempo t
            dynamic_obstacles = []
            for j, obstacle in enumerate(obstacles):
                if j < len(obstacle_velocities):
                    velocity = obstacle_velocities[j]
                    # Predicción lineal de posición
                    predicted_center = (obstacle[:3] + obstacle[3:]) / 2 + velocity * t
                    # Crear bounding box predicho
                    size = obstacle[3:] - obstacle[:3]
                    predicted_obstacle = np.concatenate([
                        predicted_center - size / 2,
                        predicted_center + size / 2
                    ])
                    dynamic_obstacles.append(predicted_obstacle)
            
            # Verificar colisión con obstáculos dinámicos
            for dyn_obstacle in dynamic_obstacles:
                if point_in_obstacle(point.position, dyn_obstacle):
                    # Ajustar posición para evitar colisión
                    obstacle_center = (dyn_obstacle[:3] + dyn_obstacle[3:]) / 2
                    direction = (point.position - obstacle_center)
                    if np.linalg.norm(direction) > 0:
                        direction = direction / np.linalg.norm(direction)
                        safety_margin = 0.15
                        new_position = obstacle_center + direction * safety_margin
                        
                        adjusted_point = TrajectoryPoint(
                            position=new_position,
                            orientation=point.orientation,
                            velocity=point.velocity,
                            acceleration=point.acceleration,
                            timestamp=point.timestamp
                        )
            
            adjusted_trajectory.append(adjusted_point)
        
        # Suavizar trayectoria ajustada
        return self._compensate_vibrations(adjusted_trajectory)
    
    def optimize_with_joint_limits(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        joint_limits: Optional[Dict[str, Tuple[float, float]]] = None,
        obstacles: Optional[List[np.ndarray]] = None
    ) -> List[TrajectoryPoint]:
        """
        Optimizar trayectoria considerando límites de articulaciones.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            joint_limits: Diccionario con límites de articulaciones
            obstacles: Lista de obstáculos
            
        Returns:
            Trayectoria optimizada respetando límites de articulaciones
        """
        logger.debug("Optimizing trajectory with joint limits")
        
        # Generar trayectoria base
        trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        if not joint_limits:
            return trajectory
        
        # Ajustar trayectoria para respetar límites
        # Esto requeriría cinemática inversa, por ahora es placeholder
        adjusted_trajectory = []
        for point in trajectory:
            # Verificar límites (simplificado)
            # En implementación real, usar cinemática inversa
            adjusted_trajectory.append(point)
        
        return adjusted_trajectory
    
    def optimize_with_velocity_constraints(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        max_velocity: float = 2.0,
        max_acceleration: float = 5.0,
        obstacles: Optional[List[np.ndarray]] = None
    ) -> List[TrajectoryPoint]:
        """
        Optimizar trayectoria con restricciones de velocidad y aceleración.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            max_velocity: Velocidad máxima permitida
            max_acceleration: Aceleración máxima permitida
            obstacles: Lista de obstáculos
            
        Returns:
            Trayectoria optimizada respetando restricciones
        """
        logger.debug(f"Optimizing trajectory with velocity constraints (max_v={max_velocity}, max_a={max_acceleration})")
        
        # Generar trayectoria base
        trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        # Ajustar velocidades y aceleraciones
        constrained_trajectory = []
        for i, point in enumerate(trajectory):
            # Limitar velocidad
            if point.velocity is not None:
                velocity_magnitude = np.linalg.norm(point.velocity)
                if velocity_magnitude > max_velocity:
                    point.velocity = point.velocity / velocity_magnitude * max_velocity
            
            # Limitar aceleración
            if point.acceleration is not None:
                accel_magnitude = np.linalg.norm(point.acceleration)
                if accel_magnitude > max_acceleration:
                    point.acceleration = point.acceleration / accel_magnitude * max_acceleration
            
            constrained_trajectory.append(point)
        
        return constrained_trajectory
    
    def optimize_with_time_constraints(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        max_time: float,
        obstacles: Optional[List[np.ndarray]] = None
    ) -> List[TrajectoryPoint]:
        """
        Optimizar trayectoria con restricción de tiempo máximo.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            max_time: Tiempo máximo permitido
            obstacles: Lista de obstáculos
            
        Returns:
            Trayectoria optimizada que cumple restricción de tiempo
        """
        logger.debug(f"Optimizing trajectory with time constraint (max_time={max_time}s)")
        
        # Generar trayectoria base
        trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        # Calcular tiempo actual
        current_time = trajectory[-1].timestamp - trajectory[0].timestamp
        
        if current_time <= max_time:
            return trajectory
        
        # Ajustar velocidades para cumplir restricción
        time_scale = current_time / max_time
        adjusted_trajectory = []
        
        for i, point in enumerate(trajectory):
            # Escalar tiempo
            new_timestamp = point.timestamp / time_scale
            
            # Ajustar velocidades proporcionalmente
            new_velocity = point.velocity * time_scale if point.velocity is not None else None
            new_acceleration = point.acceleration * (time_scale ** 2) if point.acceleration is not None else None
            
            adjusted_point = TrajectoryPoint(
                position=point.position,
                orientation=point.orientation,
                velocity=new_velocity,
                acceleration=new_acceleration,
                timestamp=new_timestamp
            )
            adjusted_trajectory.append(adjusted_point)
        
        return adjusted_trajectory
    
    def find_optimal_waypoints(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        num_waypoints: int = 3,
        obstacles: Optional[List[np.ndarray]] = None
    ) -> List[TrajectoryPoint]:
        """
        Encontrar waypoints óptimos entre inicio y objetivo.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            num_waypoints: Número de waypoints a encontrar
            obstacles: Lista de obstáculos
            
        Returns:
            Lista de waypoints óptimos
        """
        logger.debug(f"Finding {num_waypoints} optimal waypoints")
        
        # Generar waypoints iniciales (distribución uniforme)
        waypoints = []
        for i in range(1, num_waypoints + 1):
            alpha = i / (num_waypoints + 1)
            position = start.position + alpha * (goal.position - start.position)
            orientation = quaternion_slerp(start.orientation, goal.orientation, alpha)
            
            waypoint = TrajectoryPoint(
                position=position,
                orientation=orientation,
                velocity=None,
                acceleration=None,
                timestamp=0.0
            )
            waypoints.append(waypoint)
        
        # Optimizar waypoints iterativamente
        for iteration in range(10):  # Máximo 10 iteraciones
            improved = False
            
            for i, waypoint in enumerate(waypoints):
                # Intentar mover waypoint para mejorar trayectoria
                best_waypoint = waypoint
                best_reward = float('-inf')
                
                # Probar variaciones del waypoint
                for dx in [-0.1, 0, 0.1]:
                    for dy in [-0.1, 0, 0.1]:
                        for dz in [-0.1, 0, 0.1]:
                            variation = np.array([dx, dy, dz])
                            new_position = waypoint.position + variation
                            
                            # Crear trayectoria con waypoint modificado
                            test_waypoints = waypoints.copy()
                            test_waypoints[i] = TrajectoryPoint(
                                position=new_position,
                                orientation=waypoint.orientation,
                                velocity=None,
                                acceleration=None,
                                timestamp=0.0
                            )
                            
                            # Evaluar trayectoria
                            test_trajectory = self.optimize_with_splines(
                                start, goal, test_waypoints, obstacles
                            )
                            reward = self.calculate_reward(test_trajectory, obstacles)
                            
                            if reward > best_reward:
                                best_reward = reward
                                best_waypoint = test_waypoints[i]
                                improved = True
                
                waypoints[i] = best_waypoint
            
            if not improved:
                break
        
        return waypoints
    
    def optimize_with_energy_budget(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        energy_budget: float,
        obstacles: Optional[List[np.ndarray]] = None
    ) -> Optional[List[TrajectoryPoint]]:
        """
        Optimizar trayectoria con presupuesto de energía limitado.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            energy_budget: Presupuesto de energía máximo
            obstacles: Lista de obstáculos
            
        Returns:
            Trayectoria optimizada o None si no es factible
        """
        logger.debug(f"Optimizing trajectory with energy budget: {energy_budget}")
        
        # Generar trayectoria base
        trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        # Calcular energía actual
        current_energy = 0.0
        for point in trajectory:
            if point.velocity is not None and point.acceleration is not None:
                kinetic = 0.5 * np.linalg.norm(point.velocity) ** 2
                accel_energy = np.linalg.norm(point.acceleration)
                current_energy += kinetic + accel_energy
        
        if current_energy <= energy_budget:
            return trajectory
        
        # Reducir energía ajustando velocidades y aceleraciones
        energy_scale = energy_budget / current_energy
        adjusted_trajectory = []
        
        for point in trajectory:
            # Reducir velocidades proporcionalmente
            new_velocity = point.velocity * np.sqrt(energy_scale) if point.velocity is not None else None
            new_acceleration = point.acceleration * energy_scale if point.acceleration is not None else None
            
            adjusted_point = TrajectoryPoint(
                position=point.position,
                orientation=point.orientation,
                velocity=new_velocity,
                acceleration=new_acceleration,
                timestamp=point.timestamp
            )
            adjusted_trajectory.append(adjusted_point)
        
        # Verificar que cumple presupuesto
        final_energy = 0.0
        for point in adjusted_trajectory:
            if point.velocity is not None and point.acceleration is not None:
                kinetic = 0.5 * np.linalg.norm(point.velocity) ** 2
                accel_energy = np.linalg.norm(point.acceleration)
                final_energy += kinetic + accel_energy
        
        if final_energy > energy_budget * 1.1:  # 10% de tolerancia
            logger.warning(f"Energy budget may not be feasible: {final_energy} > {energy_budget}")
            return None
        
        return adjusted_trajectory
    
    def get_trajectory_statistics_detailed(
        self,
        trajectory: List[TrajectoryPoint]
    ) -> Dict[str, Any]:
        """
        Obtener estadísticas detalladas de la trayectoria.
        
        Args:
            trajectory: Trayectoria a analizar
            
        Returns:
            Diccionario con estadísticas detalladas
        """
        if not trajectory:
            return {}
        
        analysis = self.analyze_trajectory(trajectory)
        
        # Calcular estadísticas adicionales
        velocities = [np.linalg.norm(p.velocity) if p.velocity is not None else 0.0 for p in trajectory]
        accelerations = [np.linalg.norm(p.acceleration) if p.acceleration is not None else 0.0 for p in trajectory]
        
        # Calcular jerks (cambio de aceleración)
        jerks = []
        for i in range(len(trajectory) - 1):
            if trajectory[i].acceleration is not None and trajectory[i+1].acceleration is not None:
                jerk = np.linalg.norm(trajectory[i+1].acceleration - trajectory[i].acceleration)
                jerks.append(jerk)
        
        return {
            **analysis,
            "velocity_stats": {
                "mean": float(np.mean(velocities)),
                "std": float(np.std(velocities)),
                "min": float(np.min(velocities)),
                "max": float(np.max(velocities))
            },
            "acceleration_stats": {
                "mean": float(np.mean(accelerations)),
                "std": float(np.std(accelerations)),
                "min": float(np.min(accelerations)),
                "max": float(np.max(accelerations))
            },
            "jerk_stats": {
                "mean": float(np.mean(jerks)) if jerks else 0.0,
                "max": float(np.max(jerks)) if jerks else 0.0
            },
            "energy_consumption": self._calculate_total_energy(trajectory)
        }
    
    def _calculate_total_energy(self, trajectory: List[TrajectoryPoint]) -> float:
        """Calcular consumo total de energía."""
        total_energy = 0.0
        
        for point in trajectory:
            if point.velocity is not None:
                kinetic = 0.5 * np.linalg.norm(point.velocity) ** 2
                total_energy += kinetic
            
            if point.acceleration is not None:
                accel_energy = np.linalg.norm(point.acceleration)
                total_energy += accel_energy
        
        return total_energy
    
    def optimize_multi_robot(
        self,
        robot_starts: List[TrajectoryPoint],
        robot_goals: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]] = None,
        avoid_collisions: bool = True
    ) -> List[List[TrajectoryPoint]]:
        """
        Optimizar trayectorias para múltiples robots simultáneamente.
        
        Args:
            robot_starts: Lista de puntos iniciales para cada robot
            robot_goals: Lista de puntos objetivos para cada robot
            obstacles: Lista de obstáculos estáticos
            avoid_collisions: Si evitar colisiones entre robots
            
        Returns:
            Lista de trayectorias optimizadas, una por robot
        """
        logger.debug(f"Optimizing trajectories for {len(robot_starts)} robots")
        
        if len(robot_starts) != len(robot_goals):
            raise ValueError("Number of starts must match number of goals")
        
        # Optimizar trayectorias iniciales
        trajectories = []
        for start, goal in zip(robot_starts, robot_goals):
            trajectory = self.optimize_trajectory(start, goal, obstacles)
            trajectories.append(trajectory)
        
        if not avoid_collisions:
            return trajectories
        
        # Resolver colisiones entre robots
        max_iterations = 20
        for iteration in range(max_iterations):
            collisions_found = False
            
            for i in range(len(trajectories)):
                for j in range(i + 1, len(trajectories)):
                    traj1, traj2 = trajectories[i], trajectories[j]
                    
                    # Verificar colisiones entre trayectorias
                    for point1 in traj1:
                        for point2 in traj2:
                            # Verificar si están cerca en el mismo tiempo
                            time_diff = abs(point1.timestamp - point2.timestamp)
                            if time_diff < 0.1:  # Mismo tiempo aproximado
                                distance = np.linalg.norm(point1.position - point2.position)
                                if distance < 0.2:  # Muy cerca
                                    collisions_found = True
                                    
                                    # Ajustar trayectoria del robot j
                                    # Mover ligeramente para evitar colisión
                                    direction = (point2.position - point1.position)
                                    if np.linalg.norm(direction) > 0:
                                        direction = direction / np.linalg.norm(direction)
                                        offset = direction * 0.25  # Margen de seguridad
                                        
                                        # Ajustar punto en traj2
                                        idx = traj2.index(point2)
                                        new_position = point2.position + offset
                                        traj2[idx] = TrajectoryPoint(
                                            position=new_position,
                                            orientation=point2.orientation,
                                            velocity=point2.velocity,
                                            acceleration=point2.acceleration,
                                            timestamp=point2.timestamp
                                        )
            
            if not collisions_found:
                break
            
            # Suavizar trayectorias después de ajustes
            for i in range(len(trajectories)):
                trajectories[i] = self._compensate_vibrations(trajectories[i])
        
        return trajectories
    
    def optimize_with_sensor_feedback(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        sensor_data: Optional[Dict[str, Any]] = None,
        obstacles: Optional[List[np.ndarray]] = None,
        update_frequency: float = 10.0
    ) -> List[TrajectoryPoint]:
        """
        Optimizar trayectoria con retroalimentación de sensores en tiempo real.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            sensor_data: Datos de sensores (LIDAR, cámaras, etc.)
            obstacles: Obstáculos conocidos inicialmente
            update_frequency: Frecuencia de actualización en Hz
            
        Returns:
            Trayectoria optimizada con retroalimentación de sensores
        """
        logger.debug("Optimizing trajectory with sensor feedback")
        
        # Generar trayectoria inicial
        trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        if not sensor_data:
            return trajectory
        
        # Actualizar obstáculos basado en datos de sensores
        updated_obstacles = obstacles.copy() if obstacles else []
        
        # Procesar datos de LIDAR si están disponibles
        if "lidar" in sensor_data:
            lidar_points = sensor_data["lidar"]
            # Convertir puntos LIDAR a obstáculos
            for point in lidar_points:
                # Crear bounding box pequeño alrededor del punto
                obstacle = np.array([
                    point[0] - 0.1, point[1] - 0.1, point[2] - 0.1,
                    point[0] + 0.1, point[1] + 0.1, point[2] + 0.1
                ])
                updated_obstacles.append(obstacle)
        
        # Re-optimizar con obstáculos actualizados
        if updated_obstacles:
            trajectory = self._avoid_obstacles(trajectory, updated_obstacles)
        
        return trajectory
    
    def optimize_predictive(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        prediction_horizon: float = 5.0,
        obstacles: Optional[List[np.ndarray]] = None,
        obstacle_predictions: Optional[List[Callable]] = None
    ) -> List[TrajectoryPoint]:
        """
        Optimización predictiva considerando evolución futura del entorno.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            prediction_horizon: Horizonte de predicción en segundos
            obstacles: Obstáculos actuales
            obstacle_predictions: Funciones de predicción para cada obstáculo
            
        Returns:
            Trayectoria optimizada con planificación predictiva
        """
        logger.debug(f"Predictive optimization with {prediction_horizon}s horizon")
        
        # Generar trayectoria base
        trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        if not obstacle_predictions:
            return trajectory
        
        # Ajustar trayectoria considerando predicciones
        adjusted_trajectory = []
        for point in trajectory:
            adjusted_point = point
            t = point.timestamp
            
            if t <= prediction_horizon:
                # Predecir posiciones de obstáculos
                predicted_obstacles = []
                for i, pred_func in enumerate(obstacle_predictions):
                    if i < len(obstacles):
                        predicted_pos = pred_func(t)
                        # Crear bounding box predicho
                        size = obstacles[i][3:] - obstacles[i][:3]
                        predicted_obstacle = np.concatenate([
                            predicted_pos - size / 2,
                            predicted_pos + size / 2
                        ])
                        predicted_obstacles.append(predicted_obstacle)
                
                # Verificar colisiones con obstáculos predichos
                for pred_obstacle in predicted_obstacles:
                    if point_in_obstacle(point.position, pred_obstacle):
                        # Ajustar para evitar colisión futura
                        obstacle_center = (pred_obstacle[:3] + pred_obstacle[3:]) / 2
                        direction = (point.position - obstacle_center)
                        if np.linalg.norm(direction) > 0:
                            direction = direction / np.linalg.norm(direction)
                            new_position = obstacle_center + direction * 0.2
                            
                            adjusted_point = TrajectoryPoint(
                                position=new_position,
                                orientation=point.orientation,
                                velocity=point.velocity,
                                acceleration=point.acceleration,
                                timestamp=point.timestamp
                            )
            
            adjusted_trajectory.append(adjusted_point)
        
        return self._compensate_vibrations(adjusted_trajectory)
    
    def optimize_adaptive(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        learning_rate: float = 0.1
    ) -> List[TrajectoryPoint]:
        """
        Optimización adaptativa que aprende de trayectorias anteriores.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            learning_rate: Tasa de aprendizaje para adaptación
            
        Returns:
            Trayectoria optimizada usando aprendizaje adaptativo
        """
        logger.debug("Adaptive optimization with learning from history")
        
        # Buscar trayectorias similares en el historial
        similar_trajectories = []
        start_pos = start.position
        goal_pos = goal.position
        
        for hist_traj in self.trajectory_history:
            if len(hist_traj) > 0:
                hist_start = hist_traj[0].position
                hist_goal = hist_traj[-1].position
                
                # Calcular similitud
                start_dist = np.linalg.norm(start_pos - hist_start)
                goal_dist = np.linalg.norm(goal_pos - hist_goal)
                
                if start_dist < 0.5 and goal_dist < 0.5:
                    similar_trajectories.append(hist_traj)
        
        # Si hay trayectorias similares, usar como base
        if similar_trajectories:
            # Promediar trayectorias similares
            avg_trajectory = self._average_trajectories(similar_trajectories)
            # Refinar
            trajectory = self.refine_trajectory(avg_trajectory, iterations=3, obstacles=obstacles)
        else:
            # Optimizar desde cero
            trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        return trajectory
    
    def _average_trajectories(
        self,
        trajectories: List[List[TrajectoryPoint]]
    ) -> List[TrajectoryPoint]:
        """Promediar múltiples trayectorias."""
        if not trajectories:
            return []
        
        # Encontrar longitud mínima
        min_length = min(len(traj) for traj in trajectories)
        
        averaged = []
        for i in range(min_length):
            # Promediar posiciones
            positions = [traj[i].position for traj in trajectories]
            avg_position = np.mean(positions, axis=0)
            
            # Promediar orientaciones (simplificado)
            avg_orientation = trajectories[0][i].orientation
            
            # Promediar velocidades
            velocities = [traj[i].velocity if traj[i].velocity is not None else np.zeros(3) 
                         for traj in trajectories]
            avg_velocity = np.mean(velocities, axis=0)
            
            # Promediar timestamps
            avg_timestamp = np.mean([traj[i].timestamp for traj in trajectories])
            
            point = TrajectoryPoint(
                position=avg_position,
                orientation=avg_orientation,
                velocity=avg_velocity,
                acceleration=None,
                timestamp=avg_timestamp
            )
            averaged.append(point)
        
        return averaged
    
    def optimize_with_fallback(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        fallback_algorithms: Optional[List[OptimizationAlgorithm]] = None
    ) -> List[TrajectoryPoint]:
        """
        Optimización con sistema de fallback si el algoritmo principal falla.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            fallback_algorithms: Lista de algoritmos de respaldo en orden de preferencia
            
        Returns:
            Trayectoria optimizada usando algoritmo principal o fallback
        """
        if fallback_algorithms is None:
            fallback_algorithms = [
                OptimizationAlgorithm.HEURISTIC,
                OptimizationAlgorithm.A_STAR,
                OptimizationAlgorithm.RRT
            ]
        
        # Intentar con algoritmo principal
        try:
            trajectory = self.optimize_trajectory(start, goal, obstacles)
            if trajectory and len(trajectory) > 0:
                return trajectory
        except Exception as e:
            logger.warning(f"Primary algorithm failed: {e}, trying fallback")
        
        # Intentar con algoritmos de fallback
        original_algorithm = self.algorithm
        for fallback_alg in fallback_algorithms:
            try:
                self.algorithm = fallback_alg
                trajectory = self.optimize_trajectory(start, goal, obstacles)
                if trajectory and len(trajectory) > 0:
                    logger.info(f"Successfully used fallback algorithm: {fallback_alg.value}")
                    self.algorithm = original_algorithm
                    return trajectory
            except Exception as e:
                logger.warning(f"Fallback algorithm {fallback_alg.value} failed: {e}")
                continue
        
        # Restaurar algoritmo original
        self.algorithm = original_algorithm
        
        # Último recurso: trayectoria lineal simple
        logger.warning("All algorithms failed, using simple linear trajectory")
        return self._generate_initial_trajectory(start, goal)
    
    def validate_trajectory_comprehensive(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]] = None,
        max_velocity: Optional[float] = None,
        max_acceleration: Optional[float] = None,
        min_safety_distance: float = 0.1
    ) -> Dict[str, Any]:
        """
        Validación comprehensiva de trayectoria con múltiples criterios.
        
        Args:
            trajectory: Trayectoria a validar
            obstacles: Lista de obstáculos
            max_velocity: Velocidad máxima permitida
            max_acceleration: Aceleración máxima permitida
            min_safety_distance: Distancia mínima de seguridad
            
        Returns:
            Diccionario con resultados de validación
        """
        validation_result = {
            "valid": True,
            "errors": [],
            "warnings": [],
            "metrics": {}
        }
        
        if not trajectory:
            validation_result["valid"] = False
            validation_result["errors"].append("Trajectory is empty")
            return validation_result
        
        # Validar continuidad
        try:
            validate_trajectory_continuity(trajectory)
        except Exception as e:
            validation_result["valid"] = False
            validation_result["errors"].append(f"Continuity error: {str(e)}")
        
        # Validar colisiones
        if obstacles:
            collision_count = 0
            min_distance = float('inf')
            
            for point in trajectory:
                for obstacle in obstacles:
                    if point_in_obstacle(point.position, obstacle):
                        collision_count += 1
                    else:
                        obstacle_center = (obstacle[:3] + obstacle[3:]) / 2
                        distance = np.linalg.norm(point.position - obstacle_center)
                        min_distance = min(min_distance, distance)
            
            if collision_count > 0:
                validation_result["valid"] = False
                validation_result["errors"].append(f"Found {collision_count} collision points")
            
            if min_distance < min_safety_distance:
                validation_result["warnings"].append(
                    f"Minimum distance to obstacle ({min_distance:.3f}m) is below safety threshold"
                )
            
            validation_result["metrics"]["collision_count"] = collision_count
            validation_result["metrics"]["min_distance_to_obstacle"] = min_distance
        
        # Validar velocidades
        if max_velocity:
            max_vel = 0.0
            for point in trajectory:
                if point.velocity is not None:
                    vel = np.linalg.norm(point.velocity)
                    max_vel = max(max_vel, vel)
            
            if max_vel > max_velocity:
                validation_result["valid"] = False
                validation_result["errors"].append(
                    f"Maximum velocity ({max_vel:.3f}m/s) exceeds limit ({max_velocity}m/s)"
                )
            
            validation_result["metrics"]["max_velocity"] = max_vel
        
        # Validar aceleraciones
        if max_acceleration:
            max_accel = 0.0
            for point in trajectory:
                if point.acceleration is not None:
                    accel = np.linalg.norm(point.acceleration)
                    max_accel = max(max_accel, accel)
            
            if max_accel > max_acceleration:
                validation_result["valid"] = False
                validation_result["errors"].append(
                    f"Maximum acceleration ({max_accel:.3f}m/s²) exceeds limit ({max_acceleration}m/s²)"
                )
            
            validation_result["metrics"]["max_acceleration"] = max_accel
        
        # Validar suavidad
        smoothness = self._calculate_smoothness(trajectory)
        if smoothness < 0.3:
            validation_result["warnings"].append("Trajectory has low smoothness")
        validation_result["metrics"]["smoothness"] = smoothness
        
        return validation_result
    
    def get_performance_metrics_realtime(
        self,
        trajectory: List[TrajectoryPoint],
        execution_data: Optional[Dict[str, Any]] = None
    ) -> Dict[str, Any]:
        """
        Obtener métricas de rendimiento en tiempo real durante ejecución.
        
        Args:
            trajectory: Trayectoria planificada
            execution_data: Datos de ejecución real (opcional)
            
        Returns:
            Diccionario con métricas de rendimiento
        """
        metrics = {
            "planned": self.analyze_trajectory(trajectory),
            "execution": None,
            "deviation": None
        }
        
        if execution_data:
            # Calcular desviación entre planificado y ejecutado
            planned_positions = np.array([p.position for p in trajectory])
            executed_positions = np.array(execution_data.get("positions", []))
            
            if len(executed_positions) > 0:
                # Interpolar para comparar
                min_len = min(len(planned_positions), len(executed_positions))
                planned_subset = planned_positions[:min_len]
                executed_subset = executed_positions[:min_len]
                
                # Calcular desviación promedio
                deviations = np.linalg.norm(planned_subset - executed_subset, axis=1)
                avg_deviation = np.mean(deviations)
                max_deviation = np.max(deviations)
                
                metrics["execution"] = {
                    "positions": executed_positions.tolist(),
                    "timestamps": execution_data.get("timestamps", [])
                }
                
                metrics["deviation"] = {
                    "average": float(avg_deviation),
                    "maximum": float(max_deviation),
                    "within_tolerance": max_deviation < 0.1  # 10cm de tolerancia
                }
        
        return metrics
    
    def optimize_with_uncertainty(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        uncertainty_radius: float = 0.1
    ) -> List[TrajectoryPoint]:
        """
        Optimizar trayectoria considerando incertidumbre en posiciones.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            uncertainty_radius: Radio de incertidumbre
            
        Returns:
            Trayectoria optimizada con margen de seguridad para incertidumbre
        """
        logger.debug(f"Optimizing trajectory with uncertainty radius: {uncertainty_radius}")
        
        # Expandir obstáculos por incertidumbre
        expanded_obstacles = []
        if obstacles:
            for obstacle in obstacles:
                # Expandir bounding box
                expanded = obstacle.copy()
                expanded[:3] -= uncertainty_radius  # Mínimos
                expanded[3:] += uncertainty_radius  # Máximos
                expanded_obstacles.append(expanded)
        
        # Optimizar con obstáculos expandidos
        trajectory = self.optimize_trajectory(start, goal, expanded_obstacles)
        
        return trajectory
    
    def optimize_with_reinforcement_learning(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 100,
        exploration_rate: float = 0.3
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Reinforcement Learning mejorado.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            episodes: Número de episodios de entrenamiento
            exploration_rate: Tasa de exploración
            
        Returns:
            Trayectoria optimizada usando RL
        """
        logger.debug(f"RL optimization with {episodes} episodes")
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for episode in range(episodes):
            # Generar trayectoria candidata
            if episode == 0:
                trajectory = self._generate_initial_trajectory(start, goal)
            else:
                # Mutar trayectoria anterior
                trajectory = self._mutate_trajectory(best_trajectory, exploration_rate)
            
            # Aplicar optimizaciones básicas
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Calcular recompensa
            reward = self.calculate_reward(trajectory, obstacles)
            
            # Guardar mejor trayectoria
            if reward > best_reward:
                best_reward = reward
                best_trajectory = trajectory.copy()
                
                # Guardar en experiencia
                self.experience_buffer.append({
                    "trajectory": trajectory,
                    "reward": reward,
                    "start": start,
                    "goal": goal
                })
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _mutate_trajectory(
        self,
        trajectory: List[TrajectoryPoint],
        mutation_rate: float = 0.1
    ) -> List[TrajectoryPoint]:
        """Mutación de trayectoria para exploración en RL."""
        mutated = []
        
        for point in trajectory:
            # Mutar posición con probabilidad mutation_rate
            if np.random.random() < mutation_rate:
                noise = np.random.normal(0, 0.05, 3)  # Ruido pequeño
                new_position = point.position + noise
            else:
                new_position = point.position
            
            # Mutar velocidad
            if point.velocity is not None and np.random.random() < mutation_rate:
                noise = np.random.normal(0, 0.02, 3)
                new_velocity = point.velocity + noise
            else:
                new_velocity = point.velocity
            
            mutated_point = TrajectoryPoint(
                position=new_position,
                orientation=point.orientation,
                velocity=new_velocity,
                acceleration=point.acceleration,
                timestamp=point.timestamp
            )
            mutated.append(mutated_point)
        
        return mutated
    
    def optimize_with_genetic_algorithm(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 50,
        generations: int = 100,
        mutation_rate: float = 0.1,
        crossover_rate: float = 0.7
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Algoritmo Genético.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            generations: Número de generaciones
            mutation_rate: Tasa de mutación
            crossover_rate: Tasa de cruce
            
        Returns:
            Mejor trayectoria encontrada
        """
        logger.debug(f"Genetic algorithm optimization: {population_size} individuals, {generations} generations")
        
        # Inicializar población
        population = []
        for _ in range(population_size):
            trajectory = self._generate_initial_trajectory(start, goal)
            population.append(trajectory)
        
        # Evolución
        for generation in range(generations):
            # Evaluar fitness
            fitness_scores = []
            for trajectory in population:
                reward = self.calculate_reward(trajectory, obstacles)
                fitness_scores.append(reward)
            
            # Seleccionar mejores
            sorted_indices = np.argsort(fitness_scores)[::-1]
            elite_size = int(population_size * 0.2)  # 20% elite
            elite = [population[i] for i in sorted_indices[:elite_size]]
            
            # Nueva generación
            new_population = elite.copy()
            
            # Reproducción
            while len(new_population) < population_size:
                # Selección de padres
                parent1 = self._tournament_selection(population, fitness_scores)
                parent2 = self._tournament_selection(population, fitness_scores)
                
                # Cruce
                if np.random.random() < crossover_rate:
                    child = self._crossover_trajectories(parent1, parent2)
                else:
                    child = parent1.copy()
                
                # Mutación
                if np.random.random() < mutation_rate:
                    child = self._mutate_trajectory(child, 0.2)
                
                new_population.append(child)
            
            population = new_population
        
        # Retornar mejor individuo
        best_idx = np.argmax([self.calculate_reward(t, obstacles) for t in population])
        return population[best_idx]
    
    def _tournament_selection(
        self,
        population: List[List[TrajectoryPoint]],
        fitness_scores: List[float],
        tournament_size: int = 3
    ) -> List[TrajectoryPoint]:
        """Selección por torneo."""
        tournament_indices = np.random.choice(len(population), tournament_size, replace=False)
        tournament_fitness = [fitness_scores[i] for i in tournament_indices]
        winner_idx = tournament_indices[np.argmax(tournament_fitness)]
        return population[winner_idx]
    
    def _crossover_trajectories(
        self,
        parent1: List[TrajectoryPoint],
        parent2: List[TrajectoryPoint]
    ) -> List[TrajectoryPoint]:
        """Cruzar dos trayectorias."""
        min_len = min(len(parent1), len(parent2))
        crossover_point = np.random.randint(1, min_len)
        
        child = parent1[:crossover_point] + parent2[crossover_point:]
        return child
    
    def optimize_with_particle_swarm(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_particles: int = 30,
        iterations: int = 100,
        w: float = 0.7,  # Inercia
        c1: float = 1.5,  # Cognitivo
        c2: float = 1.5   # Social
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Particle Swarm Optimization (PSO).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_particles: Número de partículas
            iterations: Número de iteraciones
            w: Peso de inercia
            c1: Peso cognitivo
            c2: Peso social
            
        Returns:
            Mejor trayectoria encontrada
        """
        logger.debug(f"PSO optimization: {num_particles} particles, {iterations} iterations")
        
        # Inicializar partículas (waypoints)
        particles = []
        velocities = []
        personal_best = []
        personal_best_scores = []
        
        num_waypoints = 5
        for _ in range(num_particles):
            waypoints = []
            for i in range(num_waypoints):
                alpha = (i + 1) / (num_waypoints + 1)
                position = start.position + alpha * (goal.position - start.position)
                # Agregar ruido
                position += np.random.normal(0, 0.1, 3)
                waypoints.append(position)
            particles.append(waypoints)
            velocities.append([np.random.normal(0, 0.05, 3) for _ in range(num_waypoints)])
            personal_best.append(waypoints.copy())
            personal_best_scores.append(float('-inf'))
        
        global_best = None
        global_best_score = float('-inf')
        
        # Iteraciones
        for iteration in range(iterations):
            for i, particle in enumerate(particles):
                # Construir trayectoria desde waypoints
                trajectory = self._waypoints_to_trajectory(start, goal, particle)
                
                # Evaluar
                score = self.calculate_reward(trajectory, obstacles)
                
                # Actualizar mejor personal
                if score > personal_best_scores[i]:
                    personal_best_scores[i] = score
                    personal_best[i] = particle.copy()
                
                # Actualizar mejor global
                if score > global_best_score:
                    global_best_score = score
                    global_best = particle.copy()
            
            # Actualizar velocidades y posiciones
            for i in range(num_particles):
                for j in range(num_waypoints):
                    r1, r2 = np.random.random(2)
                    
                    # Actualizar velocidad
                    cognitive = c1 * r1 * (personal_best[i][j] - particles[i][j])
                    social = c2 * r2 * (global_best[j] - particles[i][j])
                    velocities[i][j] = w * velocities[i][j] + cognitive + social
                    
                    # Actualizar posición
                    particles[i][j] += velocities[i][j]
        
        # Construir trayectoria final
        if global_best:
            trajectory = self._waypoints_to_trajectory(start, goal, global_best)
            return trajectory
        
        return self._generate_initial_trajectory(start, goal)
    
    def _waypoints_to_trajectory(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        waypoints: List[np.ndarray]
    ) -> List[TrajectoryPoint]:
        """Convertir waypoints a trayectoria completa."""
        points = [start]
        for wp in waypoints:
            waypoint = TrajectoryPoint(
                position=wp,
                orientation=start.orientation,
                velocity=None,
                acceleration=None,
                timestamp=0.0
            )
            points.append(waypoint)
        points.append(goal)
        
        return self.optimize_with_splines(start, goal, points[1:-1] if len(points) > 2 else None)
    
    def optimize_with_ant_colony(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_ants: int = 20,
        iterations: int = 50,
        alpha: float = 1.0,  # Importancia de feromona
        beta: float = 2.0,   # Importancia de heurística
        evaporation: float = 0.1
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Ant Colony Optimization (ACO).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_ants: Número de hormigas
            iterations: Número de iteraciones
            alpha: Peso de feromona
            beta: Peso de heurística
            evaporation: Tasa de evaporación
            
        Returns:
            Mejor trayectoria encontrada
        """
        logger.debug(f"ACO optimization: {num_ants} ants, {iterations} iterations")
        
        # Crear grid de waypoints
        num_waypoints = 10
        waypoint_grid = []
        for i in range(num_waypoints):
            alpha_val = (i + 1) / (num_waypoints + 1)
            base_pos = start.position + alpha_val * (goal.position - start.position)
            # Crear variaciones
            for dx in [-0.2, 0, 0.2]:
                for dy in [-0.2, 0, 0.2]:
                    waypoint_grid.append(base_pos + np.array([dx, dy, 0]))
        
        # Inicializar feromonas
        pheromones = np.ones(len(waypoint_grid))
        
        best_trajectory = None
        best_score = float('-inf')
        
        for iteration in range(iterations):
            trajectories = []
            scores = []
            
            for ant in range(num_ants):
                # Construir trayectoria
                selected_waypoints = []
                current_pos = start.position
                
                for step in range(num_waypoints):
                    # Calcular probabilidades
                    probs = []
                    for i, wp in enumerate(waypoint_grid):
                        # Distancia heurística
                        dist = np.linalg.norm(wp - current_pos)
                        heuristic = 1.0 / (dist + 0.1)
                        
                        # Probabilidad
                        prob = (pheromones[i] ** alpha) * (heuristic ** beta)
                        probs.append(prob)
                    
                    # Normalizar
                    probs = np.array(probs)
                    probs = probs / (probs.sum() + 1e-6)
                    
                    # Seleccionar waypoint
                    selected_idx = np.random.choice(len(waypoint_grid), p=probs)
                    selected_waypoints.append(waypoint_grid[selected_idx])
                    current_pos = waypoint_grid[selected_idx]
                
                # Construir trayectoria
                trajectory = self._waypoints_to_trajectory(start, goal, selected_waypoints)
                score = self.calculate_reward(trajectory, obstacles)
                
                trajectories.append(trajectory)
                scores.append(score)
                
                # Actualizar mejor
                if score > best_score:
                    best_score = score
                    best_trajectory = trajectory.copy()
            
            # Actualizar feromonas
            pheromones *= (1 - evaporation)  # Evaporación
            
            # Depositar feromonas
            for i, score in enumerate(scores):
                if score > 0:
                    # Encontrar waypoints usados (simplificado)
                    pheromones += score * 0.01
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_simulated_annealing(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        initial_temp: float = 100.0,
        cooling_rate: float = 0.95,
        iterations: int = 1000
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Simulated Annealing.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            initial_temp: Temperatura inicial
            cooling_rate: Tasa de enfriamiento
            iterations: Número de iteraciones
            
        Returns:
            Mejor trayectoria encontrada
        """
        logger.debug(f"Simulated annealing: initial_temp={initial_temp}, iterations={iterations}")
        
        # Solución inicial
        current_trajectory = self._generate_initial_trajectory(start, goal)
        current_score = self.calculate_reward(current_trajectory, obstacles)
        
        best_trajectory = current_trajectory.copy()
        best_score = current_score
        
        temperature = initial_temp
        
        for iteration in range(iterations):
            # Generar vecino
            neighbor = self._mutate_trajectory(current_trajectory, 0.2)
            neighbor = self._compensate_vibrations(neighbor)
            if obstacles:
                neighbor = self._avoid_obstacles(neighbor, obstacles)
            
            neighbor_score = self.calculate_reward(neighbor, obstacles)
            
            # Aceptar o rechazar
            delta = neighbor_score - current_score
            if delta > 0 or np.random.random() < np.exp(delta / temperature):
                current_trajectory = neighbor
                current_score = neighbor_score
                
                if current_score > best_score:
                    best_trajectory = current_trajectory.copy()
                    best_score = current_score
            
            # Enfriar
            temperature *= cooling_rate
        
        return best_trajectory
    
    def get_optimization_comparison(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        algorithms: Optional[List[OptimizationAlgorithm]] = None
    ) -> Dict[str, Any]:
        """
        Comparar diferentes algoritmos de optimización.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            algorithms: Lista de algoritmos a comparar
            
        Returns:
            Diccionario con comparación de algoritmos
        """
        if algorithms is None:
            algorithms = [
                OptimizationAlgorithm.PPO,
                OptimizationAlgorithm.A_STAR,
                OptimizationAlgorithm.RRT,
                OptimizationAlgorithm.HEURISTIC
            ]
        
        results = {}
        original_algorithm = self.algorithm
        
        for alg in algorithms:
            try:
                self.algorithm = alg
                start_time = time.time()
                trajectory = self.optimize_trajectory(start, goal, obstacles)
                execution_time = time.time() - start_time
                
                analysis = self.analyze_trajectory(trajectory)
                reward = self.calculate_reward(trajectory, obstacles)
                safety = self.calculate_safety_metrics(trajectory, obstacles)
                
                results[alg.value] = {
                    "trajectory": trajectory,
                    "execution_time": execution_time,
                    "analysis": analysis,
                    "reward": reward,
                    "safety": safety,
                    "success": True
                }
            except Exception as e:
                results[alg.value] = {
                    "success": False,
                    "error": str(e)
                }
        
        # Restaurar algoritmo original
        self.algorithm = original_algorithm
        
        # Encontrar mejor algoritmo
        best_alg = None
        best_reward = float('-inf')
        for alg_name, result in results.items():
            if result.get("success") and result.get("reward", float('-inf')) > best_reward:
                best_reward = result["reward"]
                best_alg = alg_name
        
        return {
            "results": results,
            "best_algorithm": best_alg,
            "best_reward": best_reward,
            "recommendation": f"Best algorithm: {best_alg} with reward {best_reward:.2f}"
        }
    
    def optimize_hybrid(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        primary_algorithm: OptimizationAlgorithm = OptimizationAlgorithm.PPO,
        refinement_algorithm: OptimizationAlgorithm = OptimizationAlgorithm.HEURISTIC,
        use_genetic_refinement: bool = True
    ) -> List[TrajectoryPoint]:
        """
        Optimización híbrida combinando múltiples algoritmos.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            primary_algorithm: Algoritmo principal
            refinement_algorithm: Algoritmo de refinamiento
            use_genetic_refinement: Si usar refinamiento genético
            
        Returns:
            Trayectoria optimizada con enfoque híbrido
        """
        logger.debug("Hybrid optimization combining multiple algorithms")
        
        # Paso 1: Optimización inicial con algoritmo principal
        original_algorithm = self.algorithm
        self.algorithm = primary_algorithm
        
        trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        # Paso 2: Refinamiento con segundo algoritmo
        self.algorithm = refinement_algorithm
        refined = self.refine_trajectory(trajectory, iterations=5, obstacles=obstacles)
        
        # Paso 3: Refinamiento genético opcional
        if use_genetic_refinement:
            # Usar GA para refinamiento final
            final_refined = self.optimize_with_genetic_algorithm(
                start, goal, obstacles,
                population_size=20,
                generations=30
            )
            
            # Comparar y elegir mejor
            refined_reward = self.calculate_reward(refined, obstacles)
            genetic_reward = self.calculate_reward(final_refined, obstacles)
            
            if genetic_reward > refined_reward:
                refined = final_refined
        
        # Restaurar algoritmo original
        self.algorithm = original_algorithm
        
        return refined
    
    def optimize_adaptive_algorithm_selection(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None
    ) -> Tuple[List[TrajectoryPoint], OptimizationAlgorithm]:
        """
        Selección adaptativa del mejor algoritmo basado en características del problema.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            
        Returns:
            Tupla (trayectoria optimizada, algoritmo seleccionado)
        """
        # Analizar características del problema
        distance = np.linalg.norm(goal.position - start.position)
        num_obstacles = len(obstacles) if obstacles else 0
        complexity = distance * (1 + num_obstacles * 0.1)
        
        # Seleccionar algoritmo basado en complejidad
        if complexity < 1.0:
            # Problema simple: usar heurístico rápido
            selected_algorithm = OptimizationAlgorithm.HEURISTIC
        elif complexity < 5.0:
            # Problema medio: usar A* o RRT
            if num_obstacles > 5:
                selected_algorithm = OptimizationAlgorithm.RRT
            else:
                selected_algorithm = OptimizationAlgorithm.A_STAR
        else:
            # Problema complejo: usar PPO o GA
            if len(self.trajectory_history) > 10:
                selected_algorithm = OptimizationAlgorithm.PPO
            else:
                selected_algorithm = OptimizationAlgorithm.HEURISTIC
        
        logger.debug(f"Adaptive algorithm selection: {selected_algorithm.value} for complexity {complexity:.2f}")
        
        # Optimizar con algoritmo seleccionado
        original_algorithm = self.algorithm
        self.algorithm = selected_algorithm
        
        trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        self.algorithm = original_algorithm
        
        return trajectory, selected_algorithm
    
    def optimize_multi_objective_advanced(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        objectives: Dict[str, float],
        obstacles: Optional[List[np.ndarray]] = None,
        pareto_front_size: int = 10
    ) -> List[Dict[str, Any]]:
        """
        Optimización multi-objetivo avanzada generando frente de Pareto.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            objectives: Diccionario con objetivos y pesos
            obstacles: Lista de obstáculos
            pareto_front_size: Tamaño del frente de Pareto
            
        Returns:
            Lista de soluciones en el frente de Pareto
        """
        logger.debug(f"Advanced multi-objective optimization with {len(objectives)} objectives")
        
        # Generar población inicial
        population = []
        for _ in range(pareto_front_size * 3):
            trajectory = self._generate_initial_trajectory(start, goal)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            population.append(trajectory)
        
        # Evaluar objetivos
        def evaluate_objectives(traj):
            scores = {}
            for obj_name, weight in objectives.items():
                if obj_name == "time":
                    duration = traj[-1].timestamp - traj[0].timestamp
                    scores[obj_name] = 1.0 / (duration + 0.1)
                elif obj_name == "energy":
                    scores[obj_name] = self._calculate_energy_efficiency(traj)
                elif obj_name == "smoothness":
                    scores[obj_name] = self._calculate_smoothness(traj)
                elif obj_name == "safety":
                    if obstacles:
                        safety_metrics = self.calculate_safety_metrics(traj, obstacles)
                        scores[obj_name] = 1.0 - safety_metrics.get("collision_risk", 0.0)
                    else:
                        scores[obj_name] = 1.0
                else:
                    scores[obj_name] = 0.0
            return scores
        
        # Encontrar frente de Pareto
        pareto_front = []
        
        for trajectory in population:
            scores = evaluate_objectives(trajectory)
            is_dominated = False
            
            # Verificar si es dominado
            for other_traj in population:
                if other_traj == trajectory:
                    continue
                other_scores = evaluate_objectives(other_traj)
                
                # Verificar dominancia
                all_worse = all(other_scores.get(obj, 0) <= scores.get(obj, 0) for obj in objectives.keys())
                some_better = any(other_scores.get(obj, 0) > scores.get(obj, 0) for obj in objectives.keys())
                
                if all_worse and some_better:
                    is_dominated = True
                    break
            
            if not is_dominated:
                pareto_front.append({
                    "trajectory": trajectory,
                    "scores": scores,
                    "weighted_sum": sum(scores.get(obj, 0) * objectives.get(obj, 0) for obj in objectives.keys())
                })
        
        # Ordenar por suma ponderada
        pareto_front.sort(key=lambda x: x["weighted_sum"], reverse=True)
        
        # Retornar mejores soluciones
        return pareto_front[:pareto_front_size]
    
    def optimize_distributed(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_workers: int = 4,
        algorithm_per_worker: Optional[List[OptimizationAlgorithm]] = None
    ) -> List[TrajectoryPoint]:
        """
        Optimización distribuida usando múltiples workers con diferentes algoritmos.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_workers: Número de workers
            algorithm_per_worker: Algoritmo para cada worker (opcional)
            
        Returns:
            Mejor trayectoria encontrada por todos los workers
        """
        logger.debug(f"Distributed optimization with {num_workers} workers")
        
        if algorithm_per_worker is None:
            algorithms = [
                OptimizationAlgorithm.PPO,
                OptimizationAlgorithm.A_STAR,
                OptimizationAlgorithm.RRT,
                OptimizationAlgorithm.HEURISTIC
            ]
            algorithm_per_worker = [algorithms[i % len(algorithms)] for i in range(num_workers)]
        
        try:
            from concurrent.futures import ProcessPoolExecutor, as_completed
            
            def optimize_worker(alg):
                worker_optimizer = TrajectoryOptimizer()
                worker_optimizer.algorithm = alg
                return worker_optimizer.optimize_trajectory(start, goal, obstacles)
            
            results = []
            with ProcessPoolExecutor(max_workers=num_workers) as executor:
                futures = {executor.submit(optimize_worker, alg): alg for alg in algorithm_per_worker}
                
                for future in as_completed(futures):
                    try:
                        trajectory = future.result()
                        reward = self.calculate_reward(trajectory, obstacles)
                        results.append((trajectory, reward))
                    except Exception as e:
                        logger.error(f"Worker failed: {e}", exc_info=True)
            
            # Retornar mejor resultado
            if results:
                best_trajectory, _ = max(results, key=lambda x: x[1])
                return best_trajectory
            
        except ImportError:
            logger.warning("ProcessPoolExecutor not available, using sequential")
        
        # Fallback secuencial
        best_trajectory = None
        best_reward = float('-inf')
        
        for alg in algorithm_per_worker:
            original_algorithm = self.algorithm
            self.algorithm = alg
            trajectory = self.optimize_trajectory(start, goal, obstacles)
            reward = self.calculate_reward(trajectory, obstacles)
            
            if reward > best_reward:
                best_reward = reward
                best_trajectory = trajectory
            
            self.algorithm = original_algorithm
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_machine_learning(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        use_pretrained: bool = True
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando modelos de Machine Learning pre-entrenados.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            use_pretrained: Si usar modelo pre-entrenado
            
        Returns:
            Trayectoria optimizada usando ML
        """
        logger.debug("ML-based trajectory optimization")
        
        if use_pretrained and self.model is not None:
            # Usar modelo pre-entrenado
            try:
                # Extraer características
                features = self._extract_features(start, goal, obstacles)
                
                # Predecir waypoints usando modelo
                # (placeholder - requeriría modelo real)
                waypoints = self._predict_waypoints_ml(features)
                
                # Construir trayectoria desde waypoints
                trajectory = self.optimize_with_splines(start, goal, waypoints, obstacles)
                return trajectory
            except Exception as e:
                logger.warning(f"ML model failed: {e}, using fallback")
        
        # Fallback a optimización estándar
        return self.optimize_trajectory(start, goal, obstacles)
    
    def _extract_features(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]]
    ) -> np.ndarray:
        """Extraer características para modelo ML."""
        features = []
        
        # Distancia
        distance = np.linalg.norm(goal.position - start.position)
        features.append(distance)
        
        # Número de obstáculos
        num_obstacles = len(obstacles) if obstacles else 0
        features.append(num_obstacles)
        
        # Complejidad del espacio
        if obstacles:
            avg_obstacle_size = np.mean([np.linalg.norm(obs[3:] - obs[:3]) for obs in obstacles])
            features.append(avg_obstacle_size)
        else:
            features.append(0.0)
        
        # Dirección
        direction = (goal.position - start.position) / (distance + 1e-6)
        features.extend(direction.tolist())
        
        return np.array(features)
    
    def _predict_waypoints_ml(self, features: np.ndarray) -> List[TrajectoryPoint]:
        """Predecir waypoints usando modelo ML (placeholder)."""
        # Placeholder - en producción usaría modelo real
        num_waypoints = 3
        waypoints = []
        
        # Generar waypoints basados en características (simplificado)
        for i in range(num_waypoints):
            alpha = (i + 1) / (num_waypoints + 1)
            # Usar características para ajustar posición
            position = np.array([alpha * features[0], 0, 0])  # Simplificado
            waypoint = TrajectoryPoint(
                position=position,
                orientation=np.array([0, 0, 0, 1]),
                velocity=None,
                acceleration=None,
                timestamp=0.0
            )
            waypoints.append(waypoint)
        
        return waypoints
    
    def optimize_with_online_learning(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        learning_rate: float = 0.01
    ) -> List[TrajectoryPoint]:
        """
        Optimización con aprendizaje online que mejora con cada ejecución.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            learning_rate: Tasa de aprendizaje
            
        Returns:
            Trayectoria optimizada con aprendizaje online
        """
        logger.debug("Online learning optimization")
        
        # Buscar trayectorias similares en historial
        similar_trajectories = self._find_similar_trajectories(start, goal, threshold=0.5)
        
        if similar_trajectories:
            # Aprender de trayectorias previas
            learned_trajectory = self._learn_from_history(similar_trajectories, learning_rate)
            
            # Refinar con optimización estándar
            trajectory = self.refine_trajectory(learned_trajectory, iterations=3, obstacles=obstacles)
        else:
            # Optimizar desde cero
            trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        # Actualizar modelo de aprendizaje
        self._update_learning_model(trajectory, start, goal, obstacles)
        
        return trajectory
    
    def _find_similar_trajectories(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        threshold: float = 0.5
    ) -> List[List[TrajectoryPoint]]:
        """Encontrar trayectorias similares en el historial."""
        similar = []
        start_pos = start.position
        goal_pos = goal.position
        
        for hist_traj in self.trajectory_history:
            if len(hist_traj) > 0:
                hist_start = hist_traj[0].position
                hist_goal = hist_traj[-1].position
                
                start_dist = np.linalg.norm(start_pos - hist_start)
                goal_dist = np.linalg.norm(goal_pos - hist_goal)
                
                if start_dist < threshold and goal_dist < threshold:
                    similar.append(hist_traj)
        
        return similar
    
    def _learn_from_history(
        self,
        similar_trajectories: List[List[TrajectoryPoint]],
        learning_rate: float
    ) -> List[TrajectoryPoint]:
        """Aprender trayectoria promedio de historial similar."""
        if not similar_trajectories:
            return []
        
        return self._average_trajectories(similar_trajectories)
    
    def _update_learning_model(
        self,
        trajectory: List[TrajectoryPoint],
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]]
    ):
        """Actualizar modelo de aprendizaje con nueva experiencia."""
        # Guardar en historial
        self.trajectory_history.append(trajectory)
        
        # Limitar tamaño del historial
        if len(self.trajectory_history) > MAX_TRAJECTORY_HISTORY:
            self.trajectory_history = self.trajectory_history[-MAX_TRAJECTORY_HISTORY:]
        
        # Actualizar parámetros adaptativos
        if self.params.adaptive_learning:
            self._adaptive_learning_update()
    
    def optimize_with_constraint_satisfaction(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        constraints: Dict[str, Any],
        obstacles: Optional[List[np.ndarray]] = None
    ) -> Optional[List[TrajectoryPoint]]:
        """
        Optimización con satisfacción de restricciones múltiples.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            constraints: Diccionario con restricciones
            obstacles: Lista de obstáculos
            
        Returns:
            Trayectoria que satisface todas las restricciones o None
        """
        logger.debug("Constraint satisfaction optimization")
        
        # Generar trayectoria inicial
        trajectory = self.optimize_trajectory(start, goal, obstacles)
        
        # Verificar y ajustar para satisfacer restricciones
        max_iterations = 50
        for iteration in range(max_iterations):
            violations = self._check_constraints(trajectory, constraints)
            
            if not violations:
                return trajectory
            
            # Ajustar trayectoria para satisfacer restricciones
            trajectory = self._adjust_for_constraints(trajectory, constraints, violations)
            
            # Re-optimizar
            trajectory = self.refine_trajectory(trajectory, iterations=2, obstacles=obstacles)
        
        # Si no se pueden satisfacer todas, retornar None
        final_violations = self._check_constraints(trajectory, constraints)
        if final_violations:
            logger.warning("Could not satisfy all constraints")
            return None
        
        return trajectory
    
    def _check_constraints(
        self,
        trajectory: List[TrajectoryPoint],
        constraints: Dict[str, Any]
    ) -> List[str]:
        """Verificar qué restricciones se violan."""
        violations = []
        
        # Verificar velocidad máxima
        if "max_velocity" in constraints:
            max_vel = constraints["max_velocity"]
            for point in trajectory:
                if point.velocity is not None:
                    vel = np.linalg.norm(point.velocity)
                    if vel > max_vel:
                        violations.append("max_velocity")
                        break
        
        # Verificar aceleración máxima
        if "max_acceleration" in constraints:
            max_accel = constraints["max_acceleration"]
            for point in trajectory:
                if point.acceleration is not None:
                    accel = np.linalg.norm(point.acceleration)
                    if accel > max_accel:
                        violations.append("max_acceleration")
                        break
        
        # Verificar tiempo máximo
        if "max_time" in constraints:
            duration = trajectory[-1].timestamp - trajectory[0].timestamp
            if duration > constraints["max_time"]:
                violations.append("max_time")
        
        # Verificar energía máxima
        if "max_energy" in constraints:
            energy = self._calculate_total_energy(trajectory)
            if energy > constraints["max_energy"]:
                violations.append("max_energy")
        
        return violations
    
    def _adjust_for_constraints(
        self,
        trajectory: List[TrajectoryPoint],
        constraints: Dict[str, Any],
        violations: List[str]
    ) -> List[TrajectoryPoint]:
        """Ajustar trayectoria para satisfacer restricciones."""
        adjusted = trajectory.copy()
        
        for violation in violations:
            if violation == "max_velocity":
                max_vel = constraints["max_velocity"]
                for point in adjusted:
                    if point.velocity is not None:
                        vel_mag = np.linalg.norm(point.velocity)
                        if vel_mag > max_vel:
                            point.velocity = point.velocity / vel_mag * max_vel
            
            elif violation == "max_acceleration":
                max_accel = constraints["max_acceleration"]
                for point in adjusted:
                    if point.acceleration is not None:
                        accel_mag = np.linalg.norm(point.acceleration)
                        if accel_mag > max_accel:
                            point.acceleration = point.acceleration / accel_mag * max_accel
            
            elif violation == "max_time":
                max_time = constraints["max_time"]
                current_time = adjusted[-1].timestamp - adjusted[0].timestamp
                if current_time > max_time:
                    scale = max_time / current_time
                    for point in adjusted:
                        point.timestamp *= scale
                        if point.velocity is not None:
                            point.velocity *= scale
            
            elif violation == "max_energy":
                max_energy = constraints["max_energy"]
                current_energy = self._calculate_total_energy(adjusted)
                if current_energy > max_energy:
                    scale = np.sqrt(max_energy / current_energy)
                    for point in adjusted:
                        if point.velocity is not None:
                            point.velocity *= scale
                        if point.acceleration is not None:
                            point.acceleration *= scale
        
        return adjusted
    
    def get_smart_cache_statistics(self) -> Dict[str, Any]:
        """Obtener estadísticas avanzadas del caché inteligente."""
        cache_stats = {
            "size": len(self.trajectory_cache),
            "hits": self.cache_hits,
            "misses": self.cache_misses,
            "hit_rate": self.cache_hits / (self.cache_hits + self.cache_misses) if (self.cache_hits + self.cache_misses) > 0 else 0.0,
            "efficiency": "high" if self.cache_hits > self.cache_misses * 2 else "medium" if self.cache_hits > self.cache_misses else "low"
        }
        
        # Análisis de patrones en caché
        if len(self.trajectory_cache) > 0:
            # Calcular diversidad de trayectorias en caché
            cache_keys = list(self.trajectory_cache.keys())
            cache_stats["diversity"] = len(cache_keys) / max(len(self.trajectory_cache), 1)
        
        return cache_stats
    
    def optimize_with_evolution_strategy(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        generations: int = 50,
        sigma: float = 0.1
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Evolution Strategy (ES).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            generations: Número de generaciones
            sigma: Desviación estándar para mutación
            
        Returns:
            Mejor trayectoria encontrada
        """
        logger.debug(f"Evolution Strategy: {population_size} individuals, {generations} generations")
        
        # Inicializar población
        population = []
        for _ in range(population_size):
            trajectory = self._generate_initial_trajectory(start, goal)
            population.append(trajectory)
        
        # Evolución
        for generation in range(generations):
            # Evaluar fitness
            fitness_scores = [self.calculate_reward(t, obstacles) for t in population]
            
            # Seleccionar mejores (top 50%)
            sorted_indices = np.argsort(fitness_scores)[::-1]
            elite_size = population_size // 2
            elite = [population[i] for i in sorted_indices[:elite_size]]
            
            # Generar nueva población
            new_population = []
            
            # Mantener elite
            new_population.extend(elite)
            
            # Generar descendientes
            while len(new_population) < population_size:
                # Seleccionar padre aleatorio del elite
                parent = elite[np.random.randint(0, len(elite))]
                
                # Mutar
                child = self._mutate_trajectory_es(parent, sigma)
                child = self._compensate_vibrations(child)
                if obstacles:
                    child = self._avoid_obstacles(child, obstacles)
                
                new_population.append(child)
            
            population = new_population
        
        # Retornar mejor
        best_idx = np.argmax([self.calculate_reward(t, obstacles) for t in population])
        return population[best_idx]
    
    def _mutate_trajectory_es(
        self,
        trajectory: List[TrajectoryPoint],
        sigma: float
    ) -> List[TrajectoryPoint]:
        """Mutación para Evolution Strategy."""
        mutated = []
        
        for point in trajectory:
            # Mutación gaussiana
            noise = np.random.normal(0, sigma, 3)
            new_position = point.position + noise
            
            mutated_point = TrajectoryPoint(
                position=new_position,
                orientation=point.orientation,
                velocity=point.velocity,
                acceleration=point.acceleration,
                timestamp=point.timestamp
            )
            mutated.append(mutated_point)
        
        return mutated
    
    def optimize_with_deep_reinforcement_learning(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 200,
        use_pretrained: bool = True
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Deep Reinforcement Learning (DQN/PPO mejorado).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            episodes: Número de episodios
            use_pretrained: Si usar modelo pre-entrenado
            
        Returns:
            Trayectoria optimizada usando DRL
        """
        logger.debug(f"Deep RL optimization with {episodes} episodes")
        
        if use_pretrained and self.model is not None:
            # Usar modelo pre-entrenado
            try:
                # Extraer estado
                state = self._extract_state(start, goal, obstacles)
                
                # Predecir acción usando modelo
                # (placeholder - requeriría modelo DRL real)
                trajectory = self._predict_trajectory_drl(state)
                return trajectory
            except Exception as e:
                logger.warning(f"DRL model failed: {e}, using training")
        
        # Entrenamiento online
        best_trajectory = None
        best_reward = float('-inf')
        
        for episode in range(episodes):
            # Generar trayectoria
            if episode == 0:
                trajectory = self._generate_initial_trajectory(start, goal)
            else:
                # Usar política para generar trayectoria
                trajectory = self._generate_trajectory_with_policy(start, goal, obstacles)
            
            # Aplicar optimizaciones
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Calcular recompensa
            reward = self.calculate_reward(trajectory, obstacles)
            
            # Guardar mejor
            if reward > best_reward:
                best_reward = reward
                best_trajectory = trajectory.copy()
            
            # Actualizar política (simplificado)
            self._update_policy(trajectory, reward)
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _extract_state(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]]
    ) -> np.ndarray:
        """Extraer estado para DRL."""
        state = []
        
        # Posición relativa
        relative_pos = goal.position - start.position
        state.extend(relative_pos.tolist())
        
        # Distancia
        distance = np.linalg.norm(relative_pos)
        state.append(distance)
        
        # Información de obstáculos
        if obstacles:
            state.append(len(obstacles))
            for obs in obstacles[:5]:  # Máximo 5 obstáculos
                center = (obs[:3] + obs[3:]) / 2
                relative_obs = center - start.position
                state.extend(relative_obs.tolist())
        else:
            state.append(0)
        
        return np.array(state)
    
    def _predict_trajectory_drl(self, state: np.ndarray) -> List[TrajectoryPoint]:
        """Predecir trayectoria usando modelo DRL (placeholder)."""
        # Placeholder - en producción usaría modelo DRL real
        num_points = DEFAULT_TRAJECTORY_POINTS
        trajectory = []
        
        # Generar trayectoria basada en estado (simplificado)
        for i in range(num_points):
            alpha = i / (num_points - 1)
            position = np.array([alpha * state[3], 0, 0])  # Simplificado
            
            point = TrajectoryPoint(
                position=position,
                orientation=np.array([0, 0, 0, 1]),
                velocity=None,
                acceleration=None,
                timestamp=i * DEFAULT_TIMESTEP
            )
            trajectory.append(point)
        
        return trajectory
    
    def _generate_trajectory_with_policy(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]]
    ) -> List[TrajectoryPoint]:
        """Generar trayectoria usando política aprendida."""
        # Usar epsilon-greedy
        if np.random.random() < self.epsilon:
            # Exploración: mutar trayectoria anterior
            if self.trajectory_history:
                base = self.trajectory_history[-1]
                return self._mutate_trajectory(base, 0.2)
        
        # Explotación: usar mejor trayectoria conocida
        if self.trajectory_history:
            best_traj = max(
                self.trajectory_history,
                key=lambda t: self.calculate_reward(t, obstacles) if t else float('-inf')
            )
            return self._mutate_trajectory(best_traj, 0.1)
        
        return self._generate_initial_trajectory(start, goal)
    
    def _update_policy(self, trajectory: List[TrajectoryPoint], reward: float):
        """Actualizar política de RL."""
        # Guardar en buffer de experiencia
        self.experience_buffer.append({
            "trajectory": trajectory,
            "reward": reward
        })
        
        # Actualizar epsilon
        self.epsilon = max(self.min_epsilon, self.epsilon * self.epsilon_decay)
    
    def optimize_with_quantum_inspired(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_qubits: int = 10,
        iterations: int = 100
    ) -> List[TrajectoryPoint]:
        """
        Optimización inspirada en computación cuántica (simulada).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_qubits: Número de qubits simulados
            iterations: Número de iteraciones
            
        Returns:
            Trayectoria optimizada usando algoritmo cuántico simulado
        """
        logger.debug(f"Quantum-inspired optimization: {num_qubits} qubits, {iterations} iterations")
        
        # Simular superposición cuántica con múltiples trayectorias
        superposition = []
        for _ in range(num_qubits):
            trajectory = self._generate_initial_trajectory(start, goal)
            superposition.append(trajectory)
        
        # Evolución cuántica
        for iteration in range(iterations):
            # Evaluar todas las trayectorias en superposición
            amplitudes = []
            for traj in superposition:
                reward = self.calculate_reward(traj, obstacles)
                amplitudes.append(reward)
            
            # Normalizar amplitudes (probabilidades)
            total = sum(amplitudes)
            if total > 0:
                probabilities = [a / total for a in amplitudes]
            else:
                probabilities = [1.0 / len(amplitudes)] * len(amplitudes)
            
            # Medición cuántica (colapsar a mejor trayectoria)
            best_idx = np.argmax(amplitudes)
            best_trajectory = superposition[best_idx]
            
            # Interferencia cuántica (combinar trayectorias)
            new_superposition = []
            for i, traj in enumerate(superposition):
                # Interferencia con mejor trayectoria
                if i != best_idx:
                    # Combinar con mejor
                    combined = self._quantum_interference(traj, best_trajectory, probabilities[i])
                    new_superposition.append(combined)
                else:
                    new_superposition.append(traj)
            
            superposition = new_superposition
        
        # Retornar mejor trayectoria
        best_idx = np.argmax([self.calculate_reward(t, obstacles) for t in superposition])
        return superposition[best_idx]
    
    def _quantum_interference(
        self,
        traj1: List[TrajectoryPoint],
        traj2: List[TrajectoryPoint],
        amplitude: float
    ) -> List[TrajectoryPoint]:
        """Simular interferencia cuántica entre dos trayectorias."""
        min_len = min(len(traj1), len(traj2))
        interfered = []
        
        for i in range(min_len):
            # Interferencia constructiva/destructiva
            pos1 = traj1[i].position
            pos2 = traj2[i].position
            
            # Combinar con amplitud
            new_position = pos1 * (1 - amplitude) + pos2 * amplitude
            
            interfered_point = TrajectoryPoint(
                position=new_position,
                orientation=traj1[i].orientation,
                velocity=traj1[i].velocity,
                acceleration=traj1[i].acceleration,
                timestamp=traj1[i].timestamp
            )
            interfered.append(interfered_point)
        
        return interfered
    
