    def optimize_with_graph_neural_network(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_nodes: int = 20
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Graph Neural Networks (GNN).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_nodes: Número de nodos en el grafo
            
        Returns:
            Trayectoria optimizada usando GNN
        """
        logger.debug(f"Graph Neural Network optimization with {num_nodes} nodes")
        
        # Construir grafo del espacio de configuración
        graph_nodes = []
        for i in range(num_nodes):
            alpha = i / (num_nodes - 1) if num_nodes > 1 else 0
            position = start.position + (goal.position - start.position) * alpha
            # Agregar variación
            noise = np.random.normal(0, 0.2, 3)
            position += noise
            
            graph_nodes.append({
                "position": position,
                "features": np.array([alpha, 0, 0])  # Simplificado
            })
        
        # Simular procesamiento GNN (placeholder)
        # En producción usaría GNN real para propagar información
        processed_nodes = self._gnn_process(graph_nodes, obstacles)
        
        # Construir trayectoria desde nodos procesados
        waypoints = []
        for node in processed_nodes:
            waypoint = TrajectoryPoint(
                position=node["position"],
                orientation=np.array([0, 0, 0, 1]),
                velocity=None,
                acceleration=None,
                timestamp=0.0
            )
            waypoints.append(waypoint)
        
        return self.optimize_with_splines(start, goal, waypoints, obstacles)
    
    def _gnn_process(
        self,
        nodes: List[Dict[str, Any]],
        obstacles: Optional[List[np.ndarray]]
    ) -> List[Dict[str, Any]]:
        """Procesar nodos usando GNN (simplificado)."""
        processed = []
        
        for node in nodes:
            # Simular propagación de mensajes (simplificado)
            # En producción usaría capas GNN reales
            position = node["position"]
            
            # Ajustar posición basado en obstáculos cercanos
            if obstacles:
                for obs in obstacles:
                    obs_center = (obs[:3] + obs[3:]) / 2
                    dist = np.linalg.norm(position - obs_center)
                    if dist < 1.0:
                        direction = (position - obs_center) / (dist + 1e-6)
                        position += direction * 0.3
            
            processed.append({
                "position": position,
                "features": node["features"]
            })
        
        return processed
    
    def optimize_with_differential_evolution(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        generations: int = 50,
        F: float = 0.5,
        CR: float = 0.7
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Differential Evolution.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            generations: Número de generaciones
            F: Factor de mutación
            CR: Probabilidad de cruce
            
        Returns:
            Trayectoria optimizada usando DE
        """
        logger.debug(f"Differential Evolution: pop={population_size}, gen={generations}, F={F}, CR={CR}")
        
        # Inicializar población
        population = []
        for _ in range(population_size):
            trajectory = self._generate_initial_trajectory(start, goal)
            population.append(trajectory)
        
        # Evolución
        for generation in range(generations):
            new_population = []
            
            for i, target in enumerate(population):
                # Seleccionar 3 individuos diferentes
                candidates = [j for j in range(population_size) if j != i]
                a, b, c = np.random.choice(candidates, 3, replace=False)
                
                # Mutación: donor = a + F * (b - c)
                donor = self._differential_mutation(
                    population[a], population[b], population[c], F
                )
                
                # Cruce
                trial = self._differential_crossover(target, donor, CR)
                
                # Selección
                target_fitness = self.calculate_reward(target, obstacles)
                trial_fitness = self.calculate_reward(trial, obstacles)
                
                if trial_fitness > target_fitness:
                    new_population.append(trial)
                else:
                    new_population.append(target)
            
            population = new_population
        
        # Retornar mejor
        best_idx = np.argmax([self.calculate_reward(t, obstacles) for t in population])
        return population[best_idx]
    
    def _differential_mutation(
        self,
        a: List[TrajectoryPoint],
        b: List[TrajectoryPoint],
        c: List[TrajectoryPoint],
        F: float
    ) -> List[TrajectoryPoint]:
        """Mutación diferencial."""
        min_len = min(len(a), len(b), len(c))
        donor = []
        
        for i in range(min_len):
            position = a[i].position + F * (b[i].position - c[i].position)
            
            donor_point = TrajectoryPoint(
                position=position,
                orientation=a[i].orientation,
                velocity=a[i].velocity,
                acceleration=a[i].acceleration,
                timestamp=a[i].timestamp
            )
            donor.append(donor_point)
        
        return donor
    
    def _differential_crossover(
        self,
        target: List[TrajectoryPoint],
        donor: List[TrajectoryPoint],
        CR: float
    ) -> List[TrajectoryPoint]:
        """Cruce diferencial."""
        min_len = min(len(target), len(donor))
        trial = []
        
        for i in range(min_len):
            if np.random.random() < CR or i == np.random.randint(0, min_len):
                trial.append(donor[i])
            else:
                trial.append(target[i])
        
        return trial
    
    def optimize_with_firefly_algorithm(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_fireflies: int = 30,
        iterations: int = 50,
        alpha: float = 0.2,
        beta0: float = 1.0,
        gamma: float = 1.0
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Firefly Algorithm.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_fireflies: Número de luciérnagas
            iterations: Número de iteraciones
            alpha: Parámetro de aleatoriedad
            beta0: Atractividad inicial
            gamma: Coeficiente de absorción
            
        Returns:
            Trayectoria optimizada usando algoritmo de luciérnagas
        """
        logger.debug(f"Firefly algorithm: {num_fireflies} fireflies, {iterations} iterations")
        
        # Inicializar luciérnagas
        fireflies = []
        for _ in range(num_fireflies):
            trajectory = self._generate_initial_trajectory(start, goal)
            intensity = self.calculate_reward(trajectory, obstacles)
            fireflies.append({
                "trajectory": trajectory,
                "intensity": intensity
            })
        
        # Iteraciones
        for iteration in range(iterations):
            for i in range(num_fireflies):
                for j in range(num_fireflies):
                    if fireflies[j]["intensity"] > fireflies[i]["intensity"]:
                        # Mover luciérnaga i hacia j
                        distance = self._trajectory_distance(
                            fireflies[i]["trajectory"],
                            fireflies[j]["trajectory"]
                        )
                        
                        # Atractividad
                        beta = beta0 * np.exp(-gamma * distance ** 2)
                        
                        # Mover
                        fireflies[i]["trajectory"] = self._firefly_move(
                            fireflies[i]["trajectory"],
                            fireflies[j]["trajectory"],
                            beta,
                            alpha
                        )
                        
                        # Actualizar intensidad
                        fireflies[i]["intensity"] = self.calculate_reward(
                            fireflies[i]["trajectory"],
                            obstacles
                        )
        
        # Retornar mejor
        best_firefly = max(fireflies, key=lambda f: f["intensity"])
        return best_firefly["trajectory"]
    
    def _trajectory_distance(
        self,
        traj1: List[TrajectoryPoint],
        traj2: List[TrajectoryPoint]
    ) -> float:
        """Calcular distancia entre trayectorias."""
        min_len = min(len(traj1), len(traj2))
        if min_len == 0:
            return float('inf')
        
        distances = [
            np.linalg.norm(traj1[i].position - traj2[i].position)
            for i in range(min_len)
        ]
        return np.mean(distances)
    
    def _firefly_move(
        self,
        current: List[TrajectoryPoint],
        target: List[TrajectoryPoint],
        beta: float,
        alpha: float
    ) -> List[TrajectoryPoint]:
        """Mover luciérnaga hacia otra."""
        min_len = min(len(current), len(target))
        moved = []
        
        for i in range(min_len):
            # Movimiento hacia target
            direction = target[i].position - current[i].position
            movement = beta * direction
            
            # Aleatoriedad
            noise = np.random.normal(0, alpha, 3)
            
            new_position = current[i].position + movement + noise
            
            moved_point = TrajectoryPoint(
                position=new_position,
                orientation=current[i].orientation,
                velocity=current[i].velocity,
                acceleration=current[i].acceleration,
                timestamp=current[i].timestamp
            )
            moved.append(moved_point)
        
        return moved
    
    def optimize_with_cuckoo_search(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_nests: int = 25,
        iterations: int = 50,
        pa: float = 0.25
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Cuckoo Search Algorithm.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_nests: Número de nidos
            iterations: Número de iteraciones
            pa: Probabilidad de abandono
            
        Returns:
            Trayectoria optimizada usando búsqueda de cuco
        """
        logger.debug(f"Cuckoo search: {num_nests} nests, {iterations} iterations, pa={pa}")
        
        # Inicializar nidos
        nests = []
        for _ in range(num_nests):
            trajectory = self._generate_initial_trajectory(start, goal)
            fitness = self.calculate_reward(trajectory, obstacles)
            nests.append({
                "trajectory": trajectory,
                "fitness": fitness
            })
        
        # Mejor nido
        best_nest = max(nests, key=lambda n: n["fitness"])
        
        # Iteraciones
        for iteration in range(iterations):
            # Generar nuevo cuco usando Lévy flight
            i = np.random.randint(0, num_nests)
            new_trajectory = self._levy_flight(nests[i]["trajectory"], start, goal)
            new_fitness = self.calculate_reward(new_trajectory, obstacles)
            
            # Reemplazar si es mejor
            if new_fitness > nests[i]["fitness"]:
                nests[i]["trajectory"] = new_trajectory
                nests[i]["fitness"] = new_fitness
            
            # Actualizar mejor
            if new_fitness > best_nest["fitness"]:
                best_nest = {
                    "trajectory": new_trajectory,
                    "fitness": new_fitness
                }
            
            # Abandonar peores nidos
            for i in range(num_nests):
                if np.random.random() < pa:
                    nests[i]["trajectory"] = self._generate_initial_trajectory(start, goal)
                    nests[i]["fitness"] = self.calculate_reward(nests[i]["trajectory"], obstacles)
        
        return best_nest["trajectory"]
    
    def _levy_flight(
        self,
        trajectory: List[TrajectoryPoint],
        start: TrajectoryPoint,
        goal: TrajectoryPoint
    ) -> List[TrajectoryPoint]:
        """Vuelo de Lévy para búsqueda de cuco."""
        new_trajectory = []
        
        for point in trajectory:
            # Distribución de Lévy (simplificada)
            step_size = np.random.exponential(0.1)
            direction = np.random.normal(0, 1, 3)
            direction = direction / (np.linalg.norm(direction) + 1e-6)
            
            new_position = point.position + step_size * direction
            
            new_point = TrajectoryPoint(
                position=new_position,
                orientation=point.orientation,
                velocity=point.velocity,
                acceleration=point.acceleration,
                timestamp=point.timestamp
            )
            new_trajectory.append(new_point)
        
        return new_trajectory
    
    def optimize_with_bat_algorithm(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_bats: int = 30,
        iterations: int = 50,
        A: float = 0.9,
        r: float = 0.5,
        alpha: float = 0.9,
        gamma: float = 0.9
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Bat Algorithm.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_bats: Número de murciélagos
            iterations: Número de iteraciones
            A: Amplitud inicial
            r: Tasa de pulso inicial
            alpha: Factor de atenuación de amplitud
            gamma: Factor de aumento de tasa de pulso
            
        Returns:
            Trayectoria optimizada usando algoritmo de murciélagos
        """
        logger.debug(f"Bat algorithm: {num_bats} bats, {iterations} iterations")
        
        # Inicializar murciélagos
        bats = []
        for _ in range(num_bats):
            trajectory = self._generate_initial_trajectory(start, goal)
            fitness = self.calculate_reward(trajectory, obstacles)
            velocity = [np.zeros(3) for _ in trajectory]
            
            bats.append({
                "trajectory": trajectory,
                "velocity": velocity,
                "fitness": fitness,
                "A": A,
                "r": r,
                "freq": np.random.uniform(0, 2)
            })
        
        best_bat = max(bats, key=lambda b: b["fitness"])
        
        # Iteraciones
        for iteration in range(iterations):
            for bat in bats:
                # Actualizar frecuencia
                bat["freq"] = np.random.uniform(0, 2)
                
                # Actualizar velocidad
                for i in range(len(bat["trajectory"])):
                    bat["velocity"][i] = bat["velocity"][i] + (
                        bat["trajectory"][i].position - best_bat["trajectory"][i].position
                    ) * bat["freq"]
                
                # Actualizar posición
                new_trajectory = []
                for i, point in enumerate(bat["trajectory"]):
                    new_position = point.position + bat["velocity"][i]
                    new_point = TrajectoryPoint(
                        position=new_position,
                        orientation=point.orientation,
                        velocity=point.velocity,
                        acceleration=point.acceleration,
                        timestamp=point.timestamp
                    )
                    new_trajectory.append(new_point)
                
                # Búsqueda local aleatoria
                if np.random.random() > bat["r"]:
                    new_trajectory = self._local_search(new_trajectory, bat["A"])
                
                # Evaluar
                new_fitness = self.calculate_reward(new_trajectory, obstacles)
                
                # Aceptar si es mejor y ruido bajo
                if new_fitness > bat["fitness"] and np.random.random() < bat["A"]:
                    bat["trajectory"] = new_trajectory
                    bat["fitness"] = new_fitness
                    
                    # Actualizar amplitud y tasa
                    bat["A"] *= alpha
                    bat["r"] = r * (1 - np.exp(-gamma * iteration))
                    
                    # Actualizar mejor
                    if new_fitness > best_bat["fitness"]:
                        best_bat = bat
        
        return best_bat["trajectory"]
    
    def _local_search(
        self,
        trajectory: List[TrajectoryPoint],
        A: float
    ) -> List[TrajectoryPoint]:
        """Búsqueda local aleatoria."""
        searched = []
        for point in trajectory:
            noise = np.random.normal(0, A, 3)
            new_position = point.position + noise
            
            searched_point = TrajectoryPoint(
                position=new_position,
                orientation=point.orientation,
                velocity=point.velocity,
                acceleration=point.acceleration,
                timestamp=point.timestamp
            )
            searched.append(searched_point)
        
        return searched
    
    def optimize_with_grey_wolf(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_wolves: int = 30,
        iterations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Grey Wolf Optimizer.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_wolves: Número de lobos
            iterations: Número de iteraciones
            
        Returns:
            Trayectoria optimizada usando optimizador de lobos grises
        """
        logger.debug(f"Grey wolf optimizer: {num_wolves} wolves, {iterations} iterations")
        
        # Inicializar lobos
        wolves = []
        for _ in range(num_wolves):
            trajectory = self._generate_initial_trajectory(start, goal)
            fitness = self.calculate_reward(trajectory, obstacles)
            wolves.append({
                "trajectory": trajectory,
                "fitness": fitness
            })
        
        # Ordenar: alpha, beta, delta, omega
        wolves.sort(key=lambda w: w["fitness"], reverse=True)
        alpha = wolves[0]
        beta = wolves[1] if len(wolves) > 1 else alpha
        delta = wolves[2] if len(wolves) > 2 else beta
        
        # Iteraciones
        for iteration in range(iterations):
            a = 2 - 2 * (iteration / iterations)  # Decrece linealmente
            
            for i, wolf in enumerate(wolves):
                if i < 3:  # Alpha, beta, delta no se mueven
                    continue
                
                # Calcular posiciones respecto a alpha, beta, delta
                r1, r2 = np.random.random(2)
                A1 = 2 * a * r1 - a
                C1 = 2 * r2
                
                D_alpha = abs(C1 * alpha["trajectory"][0].position - wolf["trajectory"][0].position)
                X1 = alpha["trajectory"][0].position - A1 * D_alpha
                
                r1, r2 = np.random.random(2)
                A2 = 2 * a * r1 - a
                C2 = 2 * r2
                
                D_beta = abs(C2 * beta["trajectory"][0].position - wolf["trajectory"][0].position)
                X2 = beta["trajectory"][0].position - A2 * D_beta
                
                r1, r2 = np.random.random(2)
                A3 = 2 * a * r1 - a
                C3 = 2 * r2
                
                D_delta = abs(C3 * delta["trajectory"][0].position - wolf["trajectory"][0].position)
                X3 = delta["trajectory"][0].position - A3 * D_delta
                
                # Nueva posición (promedio)
                new_position = (X1 + X2 + X3) / 3
                
                # Actualizar trayectoria
                new_trajectory = []
                for j, point in enumerate(wolf["trajectory"]):
                    if j == 0:
                        new_pos = new_position
                    else:
                        # Interpolar
                        alpha_pos = alpha["trajectory"][j].position if j < len(alpha["trajectory"]) else new_position
                        new_pos = point.position + 0.1 * (alpha_pos - point.position)
                    
                    new_point = TrajectoryPoint(
                        position=new_pos,
                        orientation=point.orientation,
                        velocity=point.velocity,
                        acceleration=point.acceleration,
                        timestamp=point.timestamp
                    )
                    new_trajectory.append(new_point)
                
                new_trajectory = self._compensate_vibrations(new_trajectory)
                if obstacles:
                    new_trajectory = self._avoid_obstacles(new_trajectory, obstacles)
                
                new_fitness = self.calculate_reward(new_trajectory, obstacles)
                
                if new_fitness > wolf["fitness"]:
                    wolf["trajectory"] = new_trajectory
                    wolf["fitness"] = new_fitness
            
            # Reordenar
            wolves.sort(key=lambda w: w["fitness"], reverse=True)
            alpha = wolves[0]
            beta = wolves[1] if len(wolves) > 1 else alpha
            delta = wolves[2] if len(wolves) > 2 else beta
        
        return alpha["trajectory"]
    
    def optimize_with_whale_optimization(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_whales: int = 30,
        iterations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Whale Optimization Algorithm.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_whales: Número de ballenas
            iterations: Número de iteraciones
            
        Returns:
            Trayectoria optimizada usando algoritmo de ballenas
        """
        logger.debug(f"Whale optimization: {num_whales} whales, {iterations} iterations")
        
        # Inicializar ballenas
        whales = []
        for _ in range(num_whales):
            trajectory = self._generate_initial_trajectory(start, goal)
            fitness = self.calculate_reward(trajectory, obstacles)
            whales.append({
                "trajectory": trajectory,
                "fitness": fitness
            })
        
        best_whale = max(whales, key=lambda w: w["fitness"])
        
        # Iteraciones
        for iteration in range(iterations):
            a = 2 - 2 * (iteration / iterations)
            a2 = -1 + iteration * (-1 / iterations)
            
            for whale in whales:
                r = np.random.random()
                A = 2 * a * r - a
                C = 2 * r
                
                p = np.random.random()
                
                if p < 0.5:
                    if abs(A) >= 1:
                        # Búsqueda aleatoria
                        rand_whale = whales[np.random.randint(0, len(whales))]
                        D = abs(C * rand_whale["trajectory"][0].position - whale["trajectory"][0].position)
                        new_position = rand_whale["trajectory"][0].position - A * D
                    else:
                        # Atacar presa (espiral)
                        D = abs(best_whale["trajectory"][0].position - whale["trajectory"][0].position)
                        b = 1
                        l = np.random.uniform(-1, 1)
                        new_position = D * np.exp(b * l) * np.cos(l * 2 * np.pi) + best_whale["trajectory"][0].position
                else:
                    # Atacar presa (encogimiento)
                    D = abs(best_whale["trajectory"][0].position - whale["trajectory"][0].position)
                    new_position = best_whale["trajectory"][0].position - A * D
                
                # Actualizar trayectoria
                new_trajectory = []
                for j, point in enumerate(whale["trajectory"]):
                    if j == 0:
                        new_pos = new_position
                    else:
                        new_pos = point.position + 0.1 * (new_position - point.position)
                    
                    new_point = TrajectoryPoint(
                        position=new_pos,
                        orientation=point.orientation,
                        velocity=point.velocity,
                        acceleration=point.acceleration,
                        timestamp=point.timestamp
                    )
                    new_trajectory.append(new_point)
                
                new_trajectory = self._compensate_vibrations(new_trajectory)
                if obstacles:
                    new_trajectory = self._avoid_obstacles(new_trajectory, obstacles)
                
                new_fitness = self.calculate_reward(new_trajectory, obstacles)
                
                if new_fitness > whale["fitness"]:
                    whale["trajectory"] = new_trajectory
                    whale["fitness"] = new_fitness
                    
                    if new_fitness > best_whale["fitness"]:
                        best_whale = whale
        
        return best_whale["trajectory"]
    
    def optimize_with_model_predictive_control(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        horizon: int = 10,
        dt: float = 0.1
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Model Predictive Control (MPC).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            horizon: Horizonte de predicción
            dt: Paso de tiempo
            
        Returns:
            Trayectoria optimizada usando MPC
        """
        logger.debug(f"Model Predictive Control: horizon={horizon}, dt={dt}")
        
        trajectory = []
        current = start
        
        # MPC loop
        for step in range(horizon * 2):
            # Predecir trayectoria futura
            predicted_trajectory = self._mpc_predict(current, goal, horizon, dt, obstacles)
            
            # Aplicar primer paso
            if predicted_trajectory:
                next_point = predicted_trajectory[0]
                trajectory.append(next_point)
                current = next_point
                
                # Verificar si llegamos al objetivo
                if np.linalg.norm(current.position - goal.position) < 0.1:
                    trajectory.append(goal)
                    break
            else:
                break
        
        if not trajectory or np.linalg.norm(trajectory[-1].position - goal.position) > 0.1:
            trajectory.append(goal)
        
        return trajectory
    
    def _mpc_predict(
        self,
        current: TrajectoryPoint,
        goal: TrajectoryPoint,
        horizon: int,
        dt: float,
        obstacles: Optional[List[np.ndarray]]
    ) -> List[TrajectoryPoint]:
        """Predecir trayectoria usando MPC."""
        predicted = []
        
        # Modelo simple: movimiento hacia objetivo
        direction = (goal.position - current.position)
        distance = np.linalg.norm(direction)
        
        if distance < 0.01:
            return []
        
        direction = direction / distance
        speed = min(1.0, distance / (horizon * dt))
        
        for i in range(horizon):
            position = current.position + direction * speed * dt * (i + 1)
            
            # Evitar obstáculos
            if obstacles:
                for obs in obstacles:
                    obs_center = (obs[:3] + obs[3:]) / 2
                    dist = np.linalg.norm(position - obs_center)
                    if dist < 0.5:
                        direction_away = (position - obs_center) / (dist + 1e-6)
                        position += direction_away * 0.3
            
            point = TrajectoryPoint(
                position=position,
                orientation=current.orientation,
                velocity=direction * speed,
                acceleration=None,
                timestamp=current.timestamp + dt * (i + 1)
            )
            predicted.append(point)
        
        return predicted
    
    def optimize_with_dynamic_window(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        max_velocity: float = 1.0,
        max_angular_velocity: float = 1.0,
        dt: float = 0.1
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Dynamic Window Approach (DWA).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            max_velocity: Velocidad máxima
            max_angular_velocity: Velocidad angular máxima
            dt: Paso de tiempo
            
        Returns:
            Trayectoria optimizada usando DWA
        """
        logger.debug(f"Dynamic Window Approach: max_vel={max_velocity}, max_ang_vel={max_angular_velocity}")
        
        trajectory = []
        current = start
        current_velocity = np.array([0.0, 0.0, 0.0])
        
        # DWA loop
        for step in range(100):  # Límite de pasos
            # Calcular ventana dinámica
            v_min = max(0, np.linalg.norm(current_velocity) - max_velocity * dt)
            v_max = min(max_velocity, np.linalg.norm(current_velocity) + max_velocity * dt)
            
            # Generar muestras de velocidad
            best_trajectory = None
            best_score = float('-inf')
            
            for v in np.linspace(v_min, v_max, 10):
                for omega in np.linspace(-max_angular_velocity, max_angular_velocity, 10):
                    # Simular trayectoria corta
                    sim_trajectory = self._dwa_simulate(current, v, omega, dt, 5)
                    
                    # Evaluar
                    score = self._dwa_evaluate(sim_trajectory, goal, obstacles)
                    
                    if score > best_score:
                        best_score = score
                        best_trajectory = sim_trajectory
            
            if best_trajectory:
                # Aplicar primer paso
                next_point = best_trajectory[0]
                trajectory.append(next_point)
                current = next_point
                if next_point.velocity is not None:
                    current_velocity = next_point.velocity
                
                # Verificar llegada
                if np.linalg.norm(current.position - goal.position) < 0.1:
                    trajectory.append(goal)
                    break
            else:
                break
        
        if not trajectory or np.linalg.norm(trajectory[-1].position - goal.position) > 0.1:
            trajectory.append(goal)
        
        return trajectory
    
    def _dwa_simulate(
        self,
        start: TrajectoryPoint,
        v: float,
        omega: float,
        dt: float,
        steps: int
    ) -> List[TrajectoryPoint]:
        """Simular trayectoria corta para DWA."""
        trajectory = []
        current = start
        
        for i in range(steps):
            # Actualizar posición
            direction = np.array([np.cos(omega * i * dt), np.sin(omega * i * dt), 0])
            new_position = current.position + direction * v * dt
            
            point = TrajectoryPoint(
                position=new_position,
                orientation=current.orientation,
                velocity=direction * v,
                acceleration=None,
                timestamp=current.timestamp + dt
            )
            trajectory.append(point)
            current = point
        
        return trajectory
    
    def _dwa_evaluate(
        self,
        trajectory: List[TrajectoryPoint],
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]]
    ) -> float:
        """Evaluar trayectoria para DWA."""
        if not trajectory:
            return float('-inf')
        
        # Distancia al objetivo
        dist_to_goal = np.linalg.norm(trajectory[-1].position - goal.position)
        goal_score = 1.0 / (dist_to_goal + 0.1)
        
        # Penalización por obstáculos
        obstacle_penalty = 0.0
        if obstacles:
            for point in trajectory:
                for obs in obstacles:
                    obs_center = (obs[:3] + obs[3:]) / 2
                    dist = np.linalg.norm(point.position - obs_center)
                    if dist < 0.5:
                        obstacle_penalty += 1.0 / (dist + 0.1)
        
        return goal_score - obstacle_penalty * 0.5
    
    def optimize_with_rrt_star(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        max_iterations: int = 1000,
        step_size: float = 0.5,
        goal_sample_rate: float = 0.1,
        rewire_radius: float = 1.0
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando RRT* (RRT con rewire para optimalidad).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            max_iterations: Máximo de iteraciones
            step_size: Tamaño del paso
            goal_sample_rate: Tasa de muestreo del objetivo
            rewire_radius: Radio de rewire
            
        Returns:
            Trayectoria optimizada usando RRT*
        """
        logger.debug(f"RRT*: max_iter={max_iterations}, step_size={step_size}, rewire_radius={rewire_radius}")
        
        # Árbol RRT*
        nodes = [{"point": start, "parent": None, "cost": 0.0}]
        
        for iteration in range(max_iterations):
            # Muestrear
            if np.random.random() < goal_sample_rate:
                sample = goal
            else:
                sample = self._sample_random_point(start, goal)
            
            # Encontrar nodo más cercano
            nearest_idx = self._find_nearest_node(nodes, sample)
            nearest = nodes[nearest_idx]
            
            # Extender hacia muestra
            new_point = self._steer(nearest["point"], sample, step_size)
            
            # Verificar colisión
            if not self._check_collision(nearest["point"], new_point, obstacles):
                # Encontrar vecinos en radio
                neighbors = self._find_neighbors(nodes, new_point, rewire_radius)
                
                # Encontrar mejor padre
                best_parent = nearest_idx
                best_cost = nearest["cost"] + np.linalg.norm(
                    new_point.position - nearest["point"].position
                )
                
                for neighbor_idx in neighbors:
                    neighbor = nodes[neighbor_idx]
                    cost = neighbor["cost"] + np.linalg.norm(
                        new_point.position - neighbor["point"].position
                    )
                    if cost < best_cost and not self._check_collision(
                        neighbor["point"], new_point, obstacles
                    ):
                        best_cost = cost
                        best_parent = neighbor_idx
                
                # Agregar nodo
                new_node = {
                    "point": new_point,
                    "parent": best_parent,
                    "cost": best_cost
                }
                nodes.append(new_node)
                
                # Rewire vecinos
                for neighbor_idx in neighbors:
                    neighbor = nodes[neighbor_idx]
                    new_cost = best_cost + np.linalg.norm(
                        new_point.position - neighbor["point"].position
                    )
                    if new_cost < neighbor["cost"] and not self._check_collision(
                        new_point, neighbor["point"], obstacles
                    ):
                        neighbor["parent"] = len(nodes) - 1
                        neighbor["cost"] = new_cost
        
        # Construir trayectoria desde goal
        goal_idx = self._find_nearest_node(nodes, goal)
        trajectory = []
        current_idx = goal_idx
        
        while current_idx is not None:
            trajectory.insert(0, nodes[current_idx]["point"])
            current_idx = nodes[current_idx]["parent"]
        
        return trajectory if trajectory else self._generate_initial_trajectory(start, goal)
    
    def _sample_random_point(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint
    ) -> TrajectoryPoint:
        """Muestrear punto aleatorio en espacio."""
        # Muestrear en caja entre start y goal
        min_pos = np.minimum(start.position, goal.position) - 1.0
        max_pos = np.maximum(start.position, goal.position) + 1.0
        
        position = np.random.uniform(min_pos, max_pos)
        
        return TrajectoryPoint(
            position=position,
            orientation=np.array([0, 0, 0, 1]),
            velocity=None,
            acceleration=None,
            timestamp=0.0
        )
    
    def _find_nearest_node(
        self,
        nodes: List[Dict[str, Any]],
        point: TrajectoryPoint
    ) -> int:
        """Encontrar nodo más cercano."""
        distances = [
            np.linalg.norm(node["point"].position - point.position)
            for node in nodes
        ]
        return np.argmin(distances)
    
    def _steer(
        self,
        from_point: TrajectoryPoint,
        to_point: TrajectoryPoint,
        step_size: float
    ) -> TrajectoryPoint:
        """Extender desde from_point hacia to_point."""
        direction = to_point.position - from_point.position
        distance = np.linalg.norm(direction)
        
        if distance < step_size:
            return to_point
        
        direction = direction / distance
        new_position = from_point.position + direction * step_size
        
        return TrajectoryPoint(
            position=new_position,
            orientation=from_point.orientation,
            velocity=None,
            acceleration=None,
            timestamp=from_point.timestamp
        )
    
    def _check_collision(
        self,
        p1: TrajectoryPoint,
        p2: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]]
    ) -> bool:
        """Verificar colisión entre dos puntos."""
        if not obstacles:
            return False
        
        # Verificar puntos intermedios
        num_checks = 10
        for i in range(num_checks + 1):
            alpha = i / num_checks
            position = p1.position + (p2.position - p1.position) * alpha
            
            for obs in obstacles:
                if point_in_obstacle(position, obs):
                    return True
        
        return False
    
    def _find_neighbors(
        self,
        nodes: List[Dict[str, Any]],
        point: TrajectoryPoint,
        radius: float
    ) -> List[int]:
        """Encontrar vecinos en radio."""
        neighbors = []
        for i, node in enumerate(nodes):
            dist = np.linalg.norm(node["point"].position - point.position)
            if dist <= radius:
                neighbors.append(i)
        return neighbors
    
    def optimize_with_informed_rrt_star(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        max_iterations: int = 1000,
        step_size: float = 0.5
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Informed RRT* (muestreo en elipse informada).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            max_iterations: Máximo de iteraciones
            step_size: Tamaño del paso
            
        Returns:
            Trayectoria optimizada usando Informed RRT*
        """
        logger.debug(f"Informed RRT*: max_iter={max_iterations}, step_size={step_size}")
        
        # Primero ejecutar RRT* básico
        initial_trajectory = self.optimize_with_rrt_star(
            start, goal, obstacles, max_iterations // 2, step_size
        )
        
        if not initial_trajectory:
            return self._generate_initial_trajectory(start, goal)
        
        # Calcular costo inicial
        initial_cost = sum(
            np.linalg.norm(initial_trajectory[i+1].position - initial_trajectory[i].position)
            for i in range(len(initial_trajectory) - 1)
        )
        
        # Continuar con muestreo informado
        nodes = [{"point": start, "parent": None, "cost": 0.0}]
        best_cost = initial_cost
        
        for iteration in range(max_iterations // 2):
            # Muestrear en elipse informada
            sample = self._sample_informed_ellipse(start, goal, best_cost)
            
            # Continuar con RRT*
            nearest_idx = self._find_nearest_node(nodes, sample)
            nearest = nodes[nearest_idx]
            new_point = self._steer(nearest["point"], sample, step_size)
            
            if not self._check_collision(nearest["point"], new_point, obstacles):
                neighbors = self._find_neighbors(nodes, new_point, 1.0)
                
                best_parent = nearest_idx
                best_node_cost = nearest["cost"] + np.linalg.norm(
                    new_point.position - nearest["point"].position
                )
                
                for neighbor_idx in neighbors:
                    neighbor = nodes[neighbor_idx]
                    cost = neighbor["cost"] + np.linalg.norm(
                        new_point.position - neighbor["point"].position
                    )
                    if cost < best_node_cost:
                        best_node_cost = cost
                        best_parent = neighbor_idx
                
                nodes.append({
                    "point": new_point,
                    "parent": best_parent,
                    "cost": best_node_cost
                })
                
                # Actualizar mejor costo si llegamos al goal
                if np.linalg.norm(new_point.position - goal.position) < step_size:
                    goal_cost = best_node_cost + np.linalg.norm(
                        new_point.position - goal.position
                    )
                    if goal_cost < best_cost:
                        best_cost = goal_cost
        
        # Construir mejor trayectoria
        goal_idx = self._find_nearest_node(nodes, goal)
        trajectory = []
        current_idx = goal_idx
        
        while current_idx is not None:
            trajectory.insert(0, nodes[current_idx]["point"])
            current_idx = nodes[current_idx]["parent"]
        
        return trajectory if trajectory else initial_trajectory
    
    def _sample_informed_ellipse(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        best_cost: float
    ) -> TrajectoryPoint:
        """Muestrear en elipse informada."""
        # Calcular elipse
        c_min = np.linalg.norm(goal.position - start.position)
        
        if best_cost < c_min:
            return self._sample_random_point(start, goal)
        
        # Centro de elipse
        center = (start.position + goal.position) / 2
        
        # Ejes de elipse
        direction = goal.position - start.position
        direction = direction / (np.linalg.norm(direction) + 1e-6)
        
        # Muestrear en elipse (simplificado)
        angle = np.random.uniform(0, 2 * np.pi)
        radius = np.random.uniform(0, best_cost / 2)
        
        # Rotar y trasladar
        rotation = np.array([
            [np.cos(angle), -np.sin(angle), 0],
            [np.sin(angle), np.cos(angle), 0],
            [0, 0, 1]
        ])
        
        position = center + rotation @ (direction * radius)
        
        return TrajectoryPoint(
            position=position,
            orientation=np.array([0, 0, 0, 1]),
            velocity=None,
            acceleration=None,
            timestamp=0.0
        )
    
    def optimize_with_bit_star(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        max_iterations: int = 1000,
        step_size: float = 0.5
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Batch Informed Trees (BIT*).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            max_iterations: Máximo de iteraciones
            step_size: Tamaño del paso
            
        Returns:
            Trayectoria optimizada usando BIT*
        """
        logger.debug(f"BIT*: max_iter={max_iterations}, step_size={step_size}")
        
        # BIT* combina muestreo por lotes con búsqueda en árbol
        # Simplificado aquí
        nodes = [{"point": start, "parent": None, "cost": 0.0}]
        best_cost = float('inf')
        
        for iteration in range(max_iterations):
            # Muestrear batch de puntos
            batch_size = 10
            samples = [self._sample_random_point(start, goal) for _ in range(batch_size)]
            
            # Procesar batch
            for sample in samples:
                nearest_idx = self._find_nearest_node(nodes, sample)
                nearest = nodes[nearest_idx]
                new_point = self._steer(nearest["point"], sample, step_size)
                
                if not self._check_collision(nearest["point"], new_point, obstacles):
                    cost = nearest["cost"] + np.linalg.norm(
                        new_point.position - nearest["point"].position
                    )
                    
                    # Agregar si mejora
                    if cost < best_cost or len(nodes) < 10:
                        nodes.append({
                            "point": new_point,
                            "parent": nearest_idx,
                            "cost": cost
                        })
                        
                        if np.linalg.norm(new_point.position - goal.position) < step_size:
                            goal_cost = cost + np.linalg.norm(
                                new_point.position - goal.position
                            )
                            if goal_cost < best_cost:
                                best_cost = goal_cost
        
        # Construir trayectoria
        goal_idx = self._find_nearest_node(nodes, goal)
        trajectory = []
        current_idx = goal_idx
        
        while current_idx is not None:
            trajectory.insert(0, nodes[current_idx]["point"])
            current_idx = nodes[current_idx]["parent"]
        
        return trajectory if trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_stomp(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_waypoints: int = 20,
        num_iterations: int = 50,
        num_samples: int = 100
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando STOMP (Stochastic Trajectory Optimization for Motion Planning).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_waypoints: Número de waypoints
            num_iterations: Número de iteraciones
            num_samples: Número de muestras por iteración
            
        Returns:
            Trayectoria optimizada usando STOMP
        """
        logger.debug(f"STOMP: waypoints={num_waypoints}, iterations={num_iterations}, samples={num_samples}")
        
        # Inicializar waypoints
        waypoints = []
        for i in range(num_waypoints):
            alpha = i / (num_waypoints - 1) if num_waypoints > 1 else 0
            position = start.position + (goal.position - start.position) * alpha
            waypoint = TrajectoryPoint(
                position=position,
                orientation=np.array([0, 0, 0, 1]),
                velocity=None,
                acceleration=None,
                timestamp=0.0
            )
            waypoints.append(waypoint)
        
        # Optimización STOMP
        for iteration in range(num_iterations):
            # Generar muestras ruidosas
            samples = []
            for _ in range(num_samples):
                noisy_waypoints = []
                for waypoint in waypoints:
                    noise = np.random.normal(0, 0.1, 3)
                    new_position = waypoint.position + noise
                    noisy_waypoint = TrajectoryPoint(
                        position=new_position,
                        orientation=waypoint.orientation,
                        velocity=waypoint.velocity,
                        acceleration=waypoint.acceleration,
                        timestamp=waypoint.timestamp
                    )
                    noisy_waypoints.append(noisy_waypoint)
                samples.append(noisy_waypoints)
            
            # Evaluar muestras
            costs = []
            for sample in samples:
                cost = self._stomp_cost(sample, start, goal, obstacles)
                costs.append(cost)
            
            # Calcular pesos (inverso de costo)
            max_cost = max(costs) if costs else 1.0
            weights = [np.exp(-cost / max_cost) for cost in costs]
            total_weight = sum(weights)
            if total_weight > 0:
                weights = [w / total_weight for w in weights]
            else:
                weights = [1.0 / len(weights)] * len(weights)
            
            # Actualizar waypoints (promedio ponderado)
            for i in range(num_waypoints):
                weighted_pos = sum(
                    sample[i].position * weight
                    for sample, weight in zip(samples, weights)
                )
                waypoints[i].position = weighted_pos
        
        # Construir trayectoria desde waypoints
        return self.optimize_with_splines(start, goal, waypoints, obstacles)
    
    def _stomp_cost(
        self,
        waypoints: List[TrajectoryPoint],
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]]
    ) -> float:
        """Calcular costo para STOMP."""
        cost = 0.0
        
        # Costo de distancia al objetivo
        cost += np.linalg.norm(waypoints[-1].position - goal.position)
        
        # Costo de suavidad
        for i in range(len(waypoints) - 1):
            cost += np.linalg.norm(
                waypoints[i+1].position - waypoints[i].position
            ) ** 2
        
        # Penalización por obstáculos
        if obstacles:
            for waypoint in waypoints:
                for obs in obstacles:
                    obs_center = (obs[:3] + obs[3:]) / 2
                    dist = np.linalg.norm(waypoint.position - obs_center)
                    if dist < 0.5:
                        cost += 10.0 / (dist + 0.1)
        
        return cost
    
    def optimize_with_chomp(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_waypoints: int = 20,
        num_iterations: int = 50,
        lambda_smooth: float = 0.1,
        lambda_obs: float = 1.0
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando CHOMP (Covariant Hamiltonian Optimization for Motion Planning).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_waypoints: Número de waypoints
            num_iterations: Número de iteraciones
            lambda_smooth: Peso de suavidad
            lambda_obs: Peso de obstáculos
            
        Returns:
            Trayectoria optimizada usando CHOMP
        """
        logger.debug(f"CHOMP: waypoints={num_waypoints}, iterations={num_iterations}")
        
        # Inicializar waypoints
        waypoints = []
        for i in range(num_waypoints):
            alpha = i / (num_waypoints - 1) if num_waypoints > 1 else 0
            position = start.position + (goal.position - start.position) * alpha
            waypoint = TrajectoryPoint(
                position=position,
                orientation=np.array([0, 0, 0, 1]),
                velocity=None,
                acceleration=None,
                timestamp=0.0
            )
            waypoints.append(waypoint)
        
        # Optimización CHOMP
        for iteration in range(num_iterations):
            # Calcular gradiente
            gradient = self._chomp_gradient(waypoints, obstacles, lambda_smooth, lambda_obs)
            
            # Actualizar waypoints (descenso de gradiente)
            learning_rate = 0.1 / (iteration + 1)  # Learning rate adaptativo
            
            for i in range(1, num_waypoints - 1):  # No mover start y goal
                waypoints[i].position -= learning_rate * gradient[i]
        
        # Construir trayectoria desde waypoints
        return self.optimize_with_splines(start, goal, waypoints, obstacles)
    
    def _chomp_gradient(
        self,
        waypoints: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]],
        lambda_smooth: float,
        lambda_obs: float
    ) -> List[np.ndarray]:
        """Calcular gradiente para CHOMP."""
        num_waypoints = len(waypoints)
        gradient = [np.zeros(3) for _ in range(num_waypoints)]
        
        # Gradiente de suavidad
        for i in range(1, num_waypoints - 1):
            # Laplaciano (segunda derivada)
            laplacian = waypoints[i-1].position - 2 * waypoints[i].position + waypoints[i+1].position
            gradient[i] += lambda_smooth * laplacian
        
        # Gradiente de obstáculos
        if obstacles:
            for i in range(num_waypoints):
                for obs in obstacles:
                    obs_center = (obs[:3] + obs[3:]) / 2
                    dist = np.linalg.norm(waypoints[i].position - obs_center)
                    
                    if dist < 1.0:
                        # Gradiente de distancia
                        direction = (waypoints[i].position - obs_center) / (dist + 1e-6)
                        gradient[i] += lambda_obs * direction / (dist + 0.1) ** 2
        
        return gradient
    
    def optimize_with_trajopt(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_waypoints: int = 20,
        num_iterations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando TrajOpt (optimización de trayectorias).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_waypoints: Número de waypoints
            num_iterations: Número de iteraciones
            
        Returns:
            Trayectoria optimizada usando TrajOpt
        """
        logger.debug(f"TrajOpt: waypoints={num_waypoints}, iterations={num_iterations}")
        
        # Inicializar waypoints
        waypoints = []
        for i in range(num_waypoints):
            alpha = i / (num_waypoints - 1) if num_waypoints > 1 else 0
            position = start.position + (goal.position - start.position) * alpha
            waypoint = TrajectoryPoint(
                position=position,
                orientation=np.array([0, 0, 0, 1]),
                velocity=None,
                acceleration=None,
                timestamp=0.0
            )
            waypoints.append(waypoint)
        
        # Optimización TrajOpt
        for iteration in range(num_iterations):
            # Calcular costos y gradientes
            costs = []
            gradients = []
            
            for i in range(1, num_waypoints - 1):
                # Costo de suavidad
                smooth_cost = np.linalg.norm(
                    waypoints[i+1].position - 2 * waypoints[i].position + waypoints[i-1].position
                ) ** 2
                
                # Costo de obstáculos
                obs_cost = 0.0
                obs_gradient = np.zeros(3)
                
                if obstacles:
                    for obs in obstacles:
                        obs_center = (obs[:3] + obs[3:]) / 2
                        dist = np.linalg.norm(waypoints[i].position - obs_center)
                        
                        if dist < 1.0:
                            obs_cost += 1.0 / (dist + 0.1)
                            direction = (waypoints[i].position - obs_center) / (dist + 1e-6)
                            obs_gradient += direction / (dist + 0.1) ** 2
                
                total_cost = smooth_cost + obs_cost
                costs.append(total_cost)
                
                # Gradiente
                smooth_gradient = 2 * (
                    waypoints[i+1].position - 2 * waypoints[i].position + waypoints[i-1].position
                )
                gradients.append(smooth_gradient + obs_gradient)
            
            # Actualizar waypoints
            learning_rate = 0.05
            for i, grad in enumerate(gradients, 1):
                waypoints[i].position -= learning_rate * grad
        
        # Construir trayectoria
        return self.optimize_with_splines(start, goal, waypoints, obstacles)
    
    def optimize_with_gan(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_samples: int = 100
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Generative Adversarial Networks (GANs).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_samples: Número de muestras del generador
            
        Returns:
            Trayectoria optimizada usando GAN
        """
        logger.debug(f"GAN optimization: {num_samples} samples")
        
        # Generar muestras del generador (simplificado)
        # En producción usaría GAN real
        generated_trajectories = []
        
        for _ in range(num_samples):
            # Generar trayectoria (simulando generador)
            trajectory = self._gan_generate(start, goal)
            generated_trajectories.append(trajectory)
        
        # Evaluar con discriminador (simplificado)
        # En producción usaría discriminador real
        scores = []
        for traj in generated_trajectories:
            score = self._gan_discriminate(traj, obstacles)
            scores.append(score)
        
        # Seleccionar mejor
        best_idx = np.argmax(scores)
        return generated_trajectories[best_idx]
    
    def _gan_generate(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint
    ) -> List[TrajectoryPoint]:
        """Generar trayectoria usando generador GAN (simplificado)."""
        num_points = DEFAULT_TRAJECTORY_POINTS
        trajectory = []
        
        # Generar con ruido (simulando entrada del generador)
        noise = np.random.normal(0, 0.1, (num_points, 3))
        
        for i in range(num_points):
            alpha = i / (num_points - 1) if num_points > 1 else 0
            base_position = start.position + (goal.position - start.position) * alpha
            position = base_position + noise[i]
            
            point = TrajectoryPoint(
                position=position,
                orientation=np.array([0, 0, 0, 1]),
                velocity=None,
                acceleration=None,
                timestamp=i * DEFAULT_TIMESTEP
            )
            trajectory.append(point)
        
        return trajectory
    
    def _gan_discriminate(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]]
    ) -> float:
        """Evaluar trayectoria usando discriminador GAN (simplificado)."""
        # Score basado en calidad de trayectoria
        score = 1.0
        
        # Penalizar colisiones
        if obstacles:
            for point in trajectory:
                for obs in obstacles:
                    obs_center = (obs[:3] + obs[3:]) / 2
                    dist = np.linalg.norm(point.position - obs_center)
                    if dist < 0.5:
                        score -= 0.1
        
        # Recompensar suavidad
        smoothness = self._calculate_smoothness(trajectory)
        score += smoothness * 0.5
        
        return score
    
    def optimize_with_vae(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        latent_dim: int = 10
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Variational Autoencoder (VAE).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            latent_dim: Dimensión del espacio latente
            
        Returns:
            Trayectoria optimizada usando VAE
        """
        logger.debug(f"VAE optimization: latent_dim={latent_dim}")
        
        # Codificar problema en espacio latente
        features = self._extract_features(start, goal, obstacles)
        
        # Codificar a espacio latente (simplificado)
        # En producción usaría encoder VAE real
        latent = self._vae_encode(features, latent_dim)
        
        # Decodificar a trayectoria
        trajectory = self._vae_decode(latent, start, goal)
        
        return trajectory
    
    def _vae_encode(
        self,
        features: np.ndarray,
        latent_dim: int
    ) -> np.ndarray:
        """Codificar a espacio latente VAE (simplificado)."""
        # Placeholder - en producción usaría encoder VAE real
        latent = np.random.normal(0, 1, latent_dim)
        latent[:min(len(features), latent_dim)] = features[:min(len(features), latent_dim)]
        return latent
    
    def _vae_decode(
        self,
        latent: np.ndarray,
        start: TrajectoryPoint,
        goal: TrajectoryPoint
    ) -> List[TrajectoryPoint]:
        """Decodificar desde espacio latente VAE (simplificado)."""
        num_points = DEFAULT_TRAJECTORY_POINTS
        trajectory = []
        
        for i in range(num_points):
            alpha = i / (num_points - 1) if num_points > 1 else 0
            # Usar latente para ajustar
            adjustment = latent[:3] * 0.1 if len(latent) >= 3 else np.zeros(3)
            position = start.position + (goal.position - start.position) * alpha + adjustment
            
            point = TrajectoryPoint(
                position=position,
                orientation=np.array([0, 0, 0, 1]),
                velocity=None,
                acceleration=None,
                timestamp=i * DEFAULT_TIMESTEP
            )
            trajectory.append(point)
        
        return trajectory
    
    def optimize_with_multi_objective_rl(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        objectives: Dict[str, float],
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 200
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Multi-Objective Reinforcement Learning.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            objectives: Diccionario con objetivos y pesos
            obstacles: Lista de obstáculos
            episodes: Número de episodios
            
        Returns:
            Trayectoria optimizada usando MORL
        """
        logger.debug(f"Multi-objective RL: {len(objectives)} objectives, {episodes} episodes")
        
        best_trajectory = None
        best_multi_reward = float('-inf')
        
        for episode in range(episodes):
            # Generar trayectoria
            if episode == 0:
                trajectory = self._generate_initial_trajectory(start, goal)
            else:
                trajectory = self._generate_trajectory_with_policy(start, goal, obstacles)
            
            # Aplicar optimizaciones
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Calcular recompensa multi-objetivo
            multi_reward = self._calculate_multi_objective_reward(trajectory, objectives, obstacles)
            
            if multi_reward > best_multi_reward:
                best_multi_reward = multi_reward
                best_trajectory = trajectory.copy()
            
            # Actualizar política
            self._update_policy(trajectory, multi_reward)
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _calculate_multi_objective_reward(
        self,
        trajectory: List[TrajectoryPoint],
        objectives: Dict[str, float],
        obstacles: Optional[List[np.ndarray]]
    ) -> float:
        """Calcular recompensa multi-objetivo."""
        total_reward = 0.0
        
        for obj_name, weight in objectives.items():
            if obj_name == "time":
                duration = trajectory[-1].timestamp - trajectory[0].timestamp
                reward = 1.0 / (duration + 0.1)
            elif obj_name == "energy":
                reward = self._calculate_energy_efficiency(trajectory)
            elif obj_name == "smoothness":
                reward = self._calculate_smoothness(trajectory)
            elif obj_name == "safety":
                if obstacles:
                    safety_metrics = self.calculate_safety_metrics(trajectory, obstacles)
                    reward = 1.0 - safety_metrics.get("collision_risk", 0.0)
                else:
                    reward = 1.0
            else:
                reward = 0.0
            
            total_reward += weight * reward
        
        return total_reward
    
    def optimize_with_imitation_rl(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        expert_trajectories: List[List[TrajectoryPoint]],
        obstacles: Optional[List[np.ndarray]] = None,
        alpha: float = 0.5
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Imitation Reinforcement Learning.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            expert_trajectories: Trayectorias de expertos
            obstacles: Lista de obstáculos
            alpha: Peso entre imitación y RL
            
        Returns:
            Trayectoria optimizada usando Imitation RL
        """
        logger.debug(f"Imitation RL: {len(expert_trajectories)} expert trajectories, alpha={alpha}")
        
        # Aprender de expertos
        imitation_trajectory = self.optimize_with_imitation_learning(
            start, goal, expert_trajectories, obstacles
        )
        
        # Refinar con RL
        rl_trajectory = self.optimize_with_reinforcement_learning(
            start, goal, obstacles
        )
        
        # Combinar
        if alpha > 0.5:
            # Más peso a imitación
            combined = self._interpolate_trajectories(imitation_trajectory, rl_trajectory, alpha)
        else:
            # Más peso a RL
            combined = self._interpolate_trajectories(rl_trajectory, imitation_trajectory, 1 - alpha)
        
        return combined
    
    def _interpolate_trajectories(
        self,
        traj1: List[TrajectoryPoint],
        traj2: List[TrajectoryPoint],
        alpha: float
    ) -> List[TrajectoryPoint]:
        """Interpolar entre dos trayectorias."""
        min_len = min(len(traj1), len(traj2))
        interpolated = []
        
        for i in range(min_len):
            position = traj1[i].position * alpha + traj2[i].position * (1 - alpha)
            
            point = TrajectoryPoint(
                position=position,
                orientation=traj1[i].orientation,
                velocity=traj1[i].velocity,
                acceleration=traj1[i].acceleration,
                timestamp=traj1[i].timestamp
            )
            interpolated.append(point)
        
        return interpolated
    
    def optimize_with_curiosity_driven(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        curiosity_weight: float = 0.1,
        episodes: int = 200
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Curiosity-Driven Learning.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            curiosity_weight: Peso de curiosidad
            episodes: Número de episodios
            
        Returns:
            Trayectoria optimizada usando curiosidad
        """
        logger.debug(f"Curiosity-driven: weight={curiosity_weight}, episodes={episodes}")
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for episode in range(episodes):
            # Generar trayectoria
            trajectory = self._generate_initial_trajectory(start, goal)
            
            # Aplicar optimizaciones
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Calcular recompensa con curiosidad
            base_reward = self.calculate_reward(trajectory, obstacles)
            curiosity_reward = self._calculate_curiosity(trajectory)
            total_reward = base_reward + curiosity_weight * curiosity_reward
            
            if total_reward > best_reward:
                best_reward = total_reward
                best_trajectory = trajectory.copy()
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _calculate_curiosity(
        self,
        trajectory: List[TrajectoryPoint]
    ) -> float:
        """Calcular recompensa de curiosidad (exploración de regiones nuevas)."""
        # Curiosidad basada en diversidad de trayectoria
        if len(trajectory) < 2:
            return 0.0
        
        # Calcular variación en la trayectoria
        positions = np.array([p.position for p in trajectory])
        variances = np.var(positions, axis=0)
        curiosity = np.sum(variances)
        
        return curiosity
    
    def optimize_with_hindsight_experience_replay(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        buffer_size: int = 1000,
        episodes: int = 200
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Hindsight Experience Replay (HER).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            buffer_size: Tamaño del buffer
            episodes: Número de episodios
            
        Returns:
            Trayectoria optimizada usando HER
        """
        logger.debug(f"HER: buffer_size={buffer_size}, episodes={episodes}")
        
        # Buffer de experiencia
        experience_buffer = []
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for episode in range(episodes):
            # Generar trayectoria
            trajectory = self._generate_initial_trajectory(start, goal)
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Calcular recompensa
            reward = self.calculate_reward(trajectory, obstacles)
            
            # Guardar experiencia
            experience = {
                "trajectory": trajectory,
                "start": start,
                "goal": goal,
                "reward": reward
            }
            experience_buffer.append(experience)
            
            # Hindsight: usar punto final como objetivo virtual
            if len(trajectory) > 0:
                virtual_goal = trajectory[-1]
                virtual_reward = self.calculate_reward(trajectory, obstacles)
                
                # Agregar experiencia hindsight
                hindsight_experience = {
                    "trajectory": trajectory,
                    "start": start,
                    "goal": virtual_goal,
                    "reward": virtual_reward
                }
                experience_buffer.append(hindsight_experience)
            
            # Limitar buffer
            if len(experience_buffer) > buffer_size:
                experience_buffer = experience_buffer[-buffer_size:]
            
            # Actualizar mejor
            if reward > best_reward:
                best_reward = reward
                best_trajectory = trajectory
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_prioritized_experience_replay(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        buffer_size: int = 1000,
        episodes: int = 200,
        alpha: float = 0.6,
        beta: float = 0.4
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Prioritized Experience Replay (PER).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            buffer_size: Tamaño del buffer
            episodes: Número de episodios
            alpha: Exponente de prioridad
            beta: Exponente de importancia
            
        Returns:
            Trayectoria optimizada usando PER
        """
        logger.debug(f"PER: buffer_size={buffer_size}, episodes={episodes}, alpha={alpha}, beta={beta}")
        
        # Buffer con prioridades
        experience_buffer = []
        priorities = []
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for episode in range(episodes):
            # Generar trayectoria
            trajectory = self._generate_initial_trajectory(start, goal)
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Calcular recompensa y error TD (simplificado)
            reward = self.calculate_reward(trajectory, obstacles)
            td_error = abs(reward - (best_reward if best_reward > float('-inf') else 0))
            
            # Prioridad
            priority = (td_error + 1e-6) ** alpha
            
            # Guardar
            experience_buffer.append({
                "trajectory": trajectory,
                "reward": reward,
                "td_error": td_error
            })
            priorities.append(priority)
            
            # Limitar buffer
            if len(experience_buffer) > buffer_size:
                # Eliminar experiencia con menor prioridad
                min_idx = np.argmin(priorities)
                experience_buffer.pop(min_idx)
                priorities.pop(min_idx)
            
            # Muestrear según prioridad
            if len(priorities) > 0:
                total_priority = sum(priorities)
                probabilities = [p / total_priority for p in priorities]
                sampled_idx = np.random.choice(len(experience_buffer), p=probabilities)
                
                # Aprender de experiencia muestreada
                sampled_experience = experience_buffer[sampled_idx]
                
                # Actualizar mejor
                if sampled_experience["reward"] > best_reward:
                    best_reward = sampled_experience["reward"]
                    best_trajectory = sampled_experience["trajectory"].copy()
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_sac(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 200,
        alpha: float = 0.2
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Soft Actor-Critic (SAC).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            episodes: Número de episodios
            alpha: Temperatura de entropía
            
        Returns:
            Trayectoria optimizada usando SAC
        """
        logger.debug(f"SAC: {episodes} episodes, alpha={alpha}")
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for episode in range(episodes):
            # Generar trayectoria
            trajectory = self._generate_initial_trajectory(start, goal)
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Calcular recompensa
            reward = self.calculate_reward(trajectory, obstacles)
            
            # Entropía (diversidad de acciones)
            entropy = self._calculate_entropy(trajectory)
            
            # Recompensa con entropía (SAC)
            sac_reward = reward + alpha * entropy
            
            if sac_reward > best_reward:
                best_reward = sac_reward
                best_trajectory = trajectory.copy()
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _calculate_entropy(self, trajectory: List[TrajectoryPoint]) -> float:
        """Calcular entropía de la trayectoria."""
        if len(trajectory) < 2:
            return 0.0
        
        # Calcular variación en direcciones
        directions = []
        for i in range(len(trajectory) - 1):
            direction = trajectory[i+1].position - trajectory[i].position
            direction = direction / (np.linalg.norm(direction) + 1e-6)
            directions.append(direction)
        
        # Entropía basada en diversidad de direcciones
        if directions:
            directions_array = np.array(directions)
            cov = np.cov(directions_array.T)
            if cov.size > 0:
                entropy = np.log(np.linalg.det(cov + np.eye(cov.shape[0]) * 1e-6))
                return float(entropy)
        
        return 0.0
    
    def optimize_with_trpo(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 200,
        max_kl: float = 0.01
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Trust Region Policy Optimization (TRPO).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            episodes: Número de episodios
            max_kl: Máxima divergencia KL
            
        Returns:
            Trayectoria optimizada usando TRPO
        """
        logger.debug(f"TRPO: {episodes} episodes, max_kl={max_kl}")
        
        best_trajectory = None
        best_reward = float('-inf')
        old_policy_trajectory = None
        
        for episode in range(episodes):
            # Generar trayectoria con política actual
            trajectory = self._generate_initial_trajectory(start, goal)
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Calcular recompensa
            reward = self.calculate_reward(trajectory, obstacles)
            
            # Verificar divergencia KL si hay política anterior
            if old_policy_trajectory is not None:
                kl_div = self._calculate_kl_divergence(old_policy_trajectory, trajectory)
                
                # Solo actualizar si KL está dentro del límite
                if kl_div <= max_kl:
                    if reward > best_reward:
                        best_reward = reward
                        best_trajectory = trajectory.copy()
                    old_policy_trajectory = trajectory
                else:
                    # Rechazar actualización
                    continue
            else:
                if reward > best_reward:
                    best_reward = reward
                    best_trajectory = trajectory.copy()
                old_policy_trajectory = trajectory
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _calculate_kl_divergence(
        self,
        traj1: List[TrajectoryPoint],
        traj2: List[TrajectoryPoint]
    ) -> float:
        """Calcular divergencia KL entre dos trayectorias."""
        min_len = min(len(traj1), len(traj2))
        if min_len == 0:
            return float('inf')
        
        # Calcular distancia promedio
        distances = [
            np.linalg.norm(traj1[i].position - traj2[i].position)
            for i in range(min_len)
        ]
        
        # KL simplificado basado en distancia
        avg_dist = np.mean(distances)
        return avg_dist
    
    def optimize_with_ddpg(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 200,
        tau: float = 0.005
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Deep Deterministic Policy Gradient (DDPG).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            episodes: Número de episodios
            tau: Parámetro de suavizado para target networks
            
        Returns:
            Trayectoria optimizada usando DDPG
        """
        logger.debug(f"DDPG: {episodes} episodes, tau={tau}")
        
        best_trajectory = None
        best_reward = float('-inf')
        
        # Actor y Critic (simplificado)
        actor_trajectory = None
        
        for episode in range(episodes):
            # Generar trayectoria con actor
            if actor_trajectory is None:
                trajectory = self._generate_initial_trajectory(start, goal)
            else:
                # Usar actor con ruido para exploración
                trajectory = self._ddpg_actor_action(actor_trajectory, start, goal, obstacles)
            
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Evaluar con critic
            reward = self.calculate_reward(trajectory, obstacles)
            
            # Actualizar actor (target network con tau)
            if actor_trajectory is None:
                actor_trajectory = trajectory
            else:
                # Soft update
                actor_trajectory = self._interpolate_trajectories(
                    actor_trajectory, trajectory, 1 - tau
                )
            
            if reward > best_reward:
                best_reward = reward
                best_trajectory = trajectory.copy()
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _ddpg_actor_action(
        self,
        actor_trajectory: List[TrajectoryPoint],
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]]
    ) -> List[TrajectoryPoint]:
        """Acción del actor DDPG con ruido."""
        # Aplicar ruido para exploración
        noisy_trajectory = []
        for point in actor_trajectory:
            noise = np.random.normal(0, 0.1, 3)
            new_position = point.position + noise
            
            noisy_point = TrajectoryPoint(
                position=new_position,
                orientation=point.orientation,
                velocity=point.velocity,
                acceleration=point.acceleration,
                timestamp=point.timestamp
            )
            noisy_trajectory.append(noisy_point)
        
        return noisy_trajectory
    
    def optimize_with_td3(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 200,
        policy_delay: int = 2
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Twin Delayed DDPG (TD3).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            episodes: Número de episodios
            policy_delay: Retraso de actualización de política
            
        Returns:
            Trayectoria optimizada usando TD3
        """
        logger.debug(f"TD3: {episodes} episodes, policy_delay={policy_delay}")
        
        best_trajectory = None
        best_reward = float('-inf')
        
        # Dos críticos (simplificado)
        critic1_trajectory = None
        critic2_trajectory = None
        actor_trajectory = None
        
        for episode in range(episodes):
            # Generar trayectoria
            if actor_trajectory is None:
                trajectory = self._generate_initial_trajectory(start, goal)
            else:
                trajectory = self._ddpg_actor_action(actor_trajectory, start, goal, obstacles)
            
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Evaluar con ambos críticos
            reward = self.calculate_reward(trajectory, obstacles)
            
            # Actualizar críticos
            if critic1_trajectory is None:
                critic1_trajectory = trajectory
            if critic2_trajectory is None:
                critic2_trajectory = trajectory
            
            # Usar mínimo de dos críticos (clipped double Q-learning)
            critic1_reward = self.calculate_reward(critic1_trajectory, obstacles)
            critic2_reward = self.calculate_reward(critic2_trajectory, obstacles)
            min_critic_reward = min(critic1_reward, critic2_reward)
            
            if reward > min_critic_reward:
                if critic1_reward < critic2_reward:
                    critic1_trajectory = trajectory
                else:
                    critic2_trajectory = trajectory
            
            # Actualizar actor con delay
            if episode % policy_delay == 0:
                if actor_trajectory is None:
                    actor_trajectory = trajectory
                else:
                    # Usar mejor crítico
                    if critic1_reward > critic2_reward:
                        actor_trajectory = critic1_trajectory
                    else:
                        actor_trajectory = critic2_trajectory
            
            if reward > best_reward:
                best_reward = reward
                best_trajectory = trajectory.copy()
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_rainbow_dqn(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 200
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Rainbow DQN (combinación de mejoras de DQN).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            episodes: Número de episodios
            
        Returns:
            Trayectoria optimizada usando Rainbow DQN
        """
        logger.debug(f"Rainbow DQN: {episodes} episodes")
        
        # Rainbow combina: DQN, Double DQN, Dueling DQN, PER, Distributional RL, Noisy Nets, Multi-step
        # Simplificado aquí
        best_trajectory = None
        best_reward = float('-inf')
        
        for episode in range(episodes):
            # Generar trayectoria
            trajectory = self._generate_initial_trajectory(start, goal)
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Calcular recompensa
            reward = self.calculate_reward(trajectory, obstacles)
            
            # Distributional: considerar distribución de recompensas
            reward_distribution = self._calculate_reward_distribution(trajectory, obstacles)
            expected_reward = np.mean(reward_distribution)
            
            if expected_reward > best_reward:
                best_reward = expected_reward
                best_trajectory = trajectory.copy()
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _calculate_reward_distribution(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]]
    ) -> List[float]:
        """Calcular distribución de recompensas."""
        # Generar múltiples evaluaciones con ruido
        rewards = []
        for _ in range(10):
            noisy_trajectory = []
            for point in trajectory:
                noise = np.random.normal(0, 0.01, 3)
                noisy_point = TrajectoryPoint(
                    position=point.position + noise,
                    orientation=point.orientation,
                    velocity=point.velocity,
                    acceleration=point.acceleration,
                    timestamp=point.timestamp
                )
                noisy_trajectory.append(noisy_point)
            
            reward = self.calculate_reward(noisy_trajectory, obstacles)
            rewards.append(reward)
        
        return rewards
    
    def optimize_with_a3c(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        num_workers: int = 4,
        episodes: int = 200
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Asynchronous Advantage Actor-Critic (A3C).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            num_workers: Número de workers asíncronos
            episodes: Número de episodios por worker
            
        Returns:
            Trayectoria optimizada usando A3C
        """
        logger.debug(f"A3C: {num_workers} workers, {episodes} episodes per worker")
        
        # Workers asíncronos (simplificado - en producción usaría threading real)
        best_trajectory = None
        best_reward = float('-inf')
        
        for worker in range(num_workers):
            for episode in range(episodes):
                # Generar trayectoria
                trajectory = self._generate_initial_trajectory(start, goal)
                trajectory = self._compensate_vibrations(trajectory)
                if obstacles:
                    trajectory = self._avoid_obstacles(trajectory, obstacles)
                
                # Calcular recompensa y ventaja
                reward = self.calculate_reward(trajectory, obstacles)
                advantage = reward - (best_reward if best_reward > float('-inf') else 0)
                
                # Actualizar con ventaja
                if advantage > 0:
                    if reward > best_reward:
                        best_reward = reward
                        best_trajectory = trajectory.copy()
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_ppo2(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 200,
        clip_epsilon: float = 0.2
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Proximal Policy Optimization 2 (PPO2 mejorado).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            episodes: Número de episodios
            clip_epsilon: Épsilon para clipping
            
        Returns:
            Trayectoria optimizada usando PPO2
        """
        logger.debug(f"PPO2: {episodes} episodes, clip_epsilon={clip_epsilon}")
        
        best_trajectory = None
        best_reward = float('-inf')
        old_policy_trajectory = None
        
        for episode in range(episodes):
            # Generar trayectoria
            trajectory = self._generate_initial_trajectory(start, goal)
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            reward = self.calculate_reward(trajectory, obstacles)
            
            # Calcular ratio de políticas
            if old_policy_trajectory is not None:
                ratio = self._calculate_policy_ratio(old_policy_trajectory, trajectory)
                
                # Clipping PPO
                clipped_ratio = np.clip(ratio, 1 - clip_epsilon, 1 + clip_epsilon)
                
                # Usar mínimo de ratio y clipped ratio
                ppo_reward = reward * min(ratio, clipped_ratio)
                
                if ppo_reward > best_reward:
                    best_reward = ppo_reward
                    best_trajectory = trajectory.copy()
                    old_policy_trajectory = trajectory
            else:
                if reward > best_reward:
                    best_reward = reward
                    best_trajectory = trajectory.copy()
                old_policy_trajectory = trajectory
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _calculate_policy_ratio(
        self,
        old_traj: List[TrajectoryPoint],
        new_traj: List[TrajectoryPoint]
    ) -> float:
        """Calcular ratio de políticas."""
        min_len = min(len(old_traj), len(new_traj))
        if min_len == 0:
            return 1.0
        
        # Ratio basado en similitud
        distances = [
            np.linalg.norm(new_traj[i].position - old_traj[i].position)
            for i in range(min_len)
        ]
        avg_distance = np.mean(distances)
        
        # Ratio inverso a distancia
        ratio = 1.0 / (avg_distance + 0.1)
        return ratio
    
    def optimize_with_actor_critic(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 200,
        gamma: float = 0.99
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Actor-Critic.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            episodes: Número de episodios
            gamma: Factor de descuento
            
        Returns:
            Trayectoria optimizada usando Actor-Critic
        """
        logger.debug(f"Actor-Critic: {episodes} episodes, gamma={gamma}")
        
        best_trajectory = None
        best_reward = float('-inf')
        actor_trajectory = None
        critic_value = 0.0
        
        for episode in range(episodes):
            # Actor: generar acción
            if actor_trajectory is None:
                trajectory = self._generate_initial_trajectory(start, goal)
            else:
                trajectory = self._ddpg_actor_action(actor_trajectory, start, goal, obstacles)
            
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Critic: evaluar valor
            reward = self.calculate_reward(trajectory, obstacles)
            td_error = reward - critic_value
            
            # Actualizar actor y critic
            if td_error > 0:
                actor_trajectory = trajectory
            critic_value = gamma * critic_value + (1 - gamma) * reward
            
            if reward > best_reward:
                best_reward = reward
                best_trajectory = trajectory.copy()
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_dueling_dqn(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        episodes: int = 200
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Dueling DQN.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            episodes: Número de episodios
            
        Returns:
            Trayectoria optimizada usando Dueling DQN
        """
        logger.debug(f"Dueling DQN: {episodes} episodes")
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for episode in range(episodes):
            trajectory = self._generate_initial_trajectory(start, goal)
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Dueling: separar valor y ventaja
            value = self._calculate_state_value(trajectory, obstacles)
            advantage = self._calculate_advantage(trajectory, obstacles)
            
            # Q = V + A
            q_value = value + advantage
            reward = self.calculate_reward(trajectory, obstacles)
            
            if q_value > best_reward:
                best_reward = q_value
                best_trajectory = trajectory.copy()
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _calculate_state_value(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]]
    ) -> float:
        """Calcular valor del estado."""
        return self.calculate_reward(trajectory, obstacles) * 0.5
    
    def _calculate_advantage(
        self,
        trajectory: List[TrajectoryPoint],
        obstacles: Optional[List[np.ndarray]]
    ) -> float:
        """Calcular ventaja de la acción."""
        return self.calculate_reward(trajectory, obstacles) * 0.5
    
    def optimize_with_hyperband(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        max_iter: int = 81,
        eta: int = 3
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Hyperband (búsqueda eficiente de hiperparámetros).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            max_iter: Máximo de iteraciones
            eta: Factor de reducción
            
        Returns:
            Trayectoria optimizada usando Hyperband
        """
        logger.debug(f"Hyperband: max_iter={max_iter}, eta={eta}")
        
        # Calcular número de brackets
        s_max = int(np.log(max_iter) / np.log(eta))
        
        best_trajectory = None
        best_reward = float('-inf')
        
        # Ejecutar Hyperband
        for s in range(s_max, -1, -1):
            n = int(np.ceil((s_max + 1) * (eta ** s) / (s + 1)))
            r = max_iter * (eta ** (-s))
            
            # Configuraciones aleatorias
            configs = []
            for _ in range(n):
                # Parámetros aleatorios
                config = {
                    "algorithm": np.random.choice([
                        OptimizationAlgorithm.PPO,
                        OptimizationAlgorithm.A_STAR,
                        OptimizationAlgorithm.RRT,
                        OptimizationAlgorithm.HEURISTIC
                    ]),
                    "iterations": int(r)
                }
                configs.append(config)
            
            # Evaluar configuraciones
            for config in configs:
                original_algorithm = self.algorithm
                self.algorithm = config["algorithm"]
                
                trajectory = self.optimize_trajectory(start, goal, obstacles)
                reward = self.calculate_reward(trajectory, obstacles)
                
                if reward > best_reward:
                    best_reward = reward
                    best_trajectory = trajectory
                
                self.algorithm = original_algorithm
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_bayesian_optimization(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        n_iterations: int = 50,
        acquisition_func: str = "ucb"
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Bayesian Optimization.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            n_iterations: Número de iteraciones
            acquisition_func: Función de adquisición ("ucb", "ei", "pi")
            
        Returns:
            Trayectoria optimizada usando Bayesian Optimization
        """
        logger.debug(f"Bayesian Optimization: {n_iterations} iterations, acquisition={acquisition_func}")
        
        # Observaciones previas
        X_observed = []
        y_observed = []
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for iteration in range(n_iterations):
            # Seleccionar siguiente punto usando función de adquisición
            if len(X_observed) == 0:
                # Primera iteración: muestrear aleatoriamente
                trajectory = self._generate_initial_trajectory(start, goal)
            else:
                # Usar función de adquisición para seleccionar
                trajectory = self._bayesian_acquisition(
                    X_observed, y_observed, start, goal, acquisition_func
                )
            
            trajectory = self._compensate_vibrations(trajectory)
            if obstacles:
                trajectory = self._avoid_obstacles(trajectory, obstacles)
            
            # Evaluar
            reward = self.calculate_reward(trajectory, obstacles)
            
            # Guardar observación
            X_observed.append(trajectory)
            y_observed.append(reward)
            
            if reward > best_reward:
                best_reward = reward
                best_trajectory = trajectory
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def _bayesian_acquisition(
        self,
        X_observed: List[List[TrajectoryPoint]],
        y_observed: List[float],
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        acquisition_func: str
    ) -> List[TrajectoryPoint]:
        """Seleccionar siguiente punto usando función de adquisición."""
        # Generar candidatos
        candidates = []
        for _ in range(10):
            candidate = self._generate_initial_trajectory(start, goal)
            candidates.append(candidate)
        
        # Calcular valores de adquisición
        acquisition_values = []
        for candidate in candidates:
            if acquisition_func == "ucb":
                # Upper Confidence Bound
                mean, std = self._gaussian_process_predict(candidate, X_observed, y_observed)
                value = mean + 2 * std
            elif acquisition_func == "ei":
                # Expected Improvement
                mean, std = self._gaussian_process_predict(candidate, X_observed, y_observed)
                best_y = max(y_observed) if y_observed else 0
                z = (mean - best_y) / (std + 1e-6)
                value = std * (z * 0.5 * (1 + np.math.erf(z / np.sqrt(2))) + 
                              (1 / np.sqrt(2 * np.pi)) * np.exp(-0.5 * z ** 2))
            else:  # pi
                # Probability of Improvement
                mean, std = self._gaussian_process_predict(candidate, X_observed, y_observed)
                best_y = max(y_observed) if y_observed else 0
                z = (mean - best_y) / (std + 1e-6)
                value = 0.5 * (1 + np.math.erf(z / np.sqrt(2)))
            
            acquisition_values.append(value)
        
        # Seleccionar mejor candidato
        best_idx = np.argmax(acquisition_values)
        return candidates[best_idx]
    
    def _gaussian_process_predict(
        self,
        candidate: List[TrajectoryPoint],
        X_observed: List[List[TrajectoryPoint]],
        y_observed: List[float]
    ) -> Tuple[float, float]:
        """Predecir usando proceso gaussiano (simplificado)."""
        if len(X_observed) == 0:
            return 0.0, 1.0
        
        # Calcular distancias
        distances = []
        for obs_traj in X_observed:
            dist = self._trajectory_distance(candidate, obs_traj)
            distances.append(dist)
        
        # Kernel RBF simplificado
        distances = np.array(distances)
        kernel = np.exp(-distances ** 2 / 2)
        
        # Predicción
        mean = np.dot(kernel, y_observed) / (np.sum(kernel) + 1e-6)
        std = np.sqrt(1.0 - np.sum(kernel ** 2) / (len(X_observed) + 1e-6))
        
        return float(mean), float(std)
    
    def optimize_with_evolutionary_strategy_cma(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        generations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando CMA-ES (Covariance Matrix Adaptation Evolution Strategy).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            generations: Número de generaciones
            
        Returns:
            Trayectoria optimizada usando CMA-ES
        """
        logger.debug(f"CMA-ES: pop={population_size}, gen={generations}")
        
        # Inicializar
        trajectory = self._generate_initial_trajectory(start, goal)
        mean = np.array([p.position for p in trajectory])
        sigma = 0.5
        cov = np.eye(mean.shape[0] * mean.shape[1]) * sigma ** 2
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for generation in range(generations):
            # Generar población
            population = []
            for _ in range(population_size):
                # Muestrear de distribución normal multivariada
                noise = np.random.multivariate_normal(
                    mean.flatten(), cov
                ).reshape(mean.shape)
                
                # Construir trayectoria
                traj_points = []
                for i, pos in enumerate(noise):
                    point = TrajectoryPoint(
                        position=pos,
                        orientation=trajectory[i].orientation if i < len(trajectory) else np.array([0, 0, 0, 1]),
                        velocity=None,
                        acceleration=None,
                        timestamp=trajectory[i].timestamp if i < len(trajectory) else i * DEFAULT_TIMESTEP
                    )
                    traj_points.append(point)
                
                population.append(traj_points)
            
            # Evaluar
            fitness_scores = [self.calculate_reward(t, obstacles) for t in population]
            
            # Seleccionar mejores
            elite_size = population_size // 2
            sorted_indices = np.argsort(fitness_scores)[::-1]
            elite = [population[i] for i in sorted_indices[:elite_size]]
            
            # Actualizar media y covarianza
            elite_positions = np.array([[p.position for p in traj] for traj in elite])
            mean = np.mean(elite_positions, axis=0)
            
            # Actualizar covarianza (simplificado)
            cov = np.cov(elite_positions.reshape(elite_positions.shape[0], -1).T)
            if cov.size == 0:
                cov = np.eye(mean.shape[0] * mean.shape[1]) * sigma ** 2
            
            # Actualizar mejor
            best_idx = sorted_indices[0]
            if fitness_scores[best_idx] > best_reward:
                best_reward = fitness_scores[best_idx]
                best_trajectory = population[best_idx]
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_differential_evolution_strategy(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        generations: int = 50,
        strategy: str = "rand1"
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Differential Evolution con diferentes estrategias.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            generations: Número de generaciones
            strategy: Estrategia ("rand1", "best1", "rand2", "best2")
            
        Returns:
            Trayectoria optimizada usando DE con estrategia
        """
        logger.debug(f"DE Strategy: pop={population_size}, gen={generations}, strategy={strategy}")
        
        # Inicializar población
        population = []
        for _ in range(population_size):
            trajectory = self._generate_initial_trajectory(start, goal)
            population.append(trajectory)
        
        best_trajectory = None
        best_reward = float('-inf')
        
        # Evolución
        for generation in range(generations):
            new_population = []
            
            for i, target in enumerate(population):
                # Seleccionar individuos según estrategia
                candidates = [j for j in range(population_size) if j != i]
                
                if strategy == "rand1":
                    a, b, c = np.random.choice(candidates, 3, replace=False)
                    donor = self._differential_mutation(
                        population[a], population[b], population[c], 0.5
                    )
                elif strategy == "best1":
                    best_idx = np.argmax([self.calculate_reward(t, obstacles) for t in population])
                    a, b = np.random.choice(candidates, 2, replace=False)
                    donor = self._differential_mutation(
                        population[best_idx], population[a], population[b], 0.5
                    )
                elif strategy == "rand2":
                    a, b, c, d, e = np.random.choice(candidates, 5, replace=False)
                    donor1 = self._differential_mutation(
                        population[a], population[b], population[c], 0.5
                    )
                    donor2 = self._differential_mutation(
                        population[d], population[e], donor1, 0.5
                    )
                    donor = donor2
                else:  # best2
                    best_idx = np.argmax([self.calculate_reward(t, obstacles) for t in population])
                    a, b, c, d = np.random.choice(candidates, 4, replace=False)
                    donor1 = self._differential_mutation(
                        population[best_idx], population[a], population[b], 0.5
                    )
                    donor2 = self._differential_mutation(
                        donor1, population[c], population[d], 0.5
                    )
                    donor = donor2
                
                # Cruce
                trial = self._differential_crossover(target, donor, 0.7)
                
                # Selección
                target_fitness = self.calculate_reward(target, obstacles)
                trial_fitness = self.calculate_reward(trial, obstacles)
                
                if trial_fitness > target_fitness:
                    new_population.append(trial)
                    if trial_fitness > best_reward:
                        best_reward = trial_fitness
                        best_trajectory = trial
                else:
                    new_population.append(target)
            
            population = new_population
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_adaptive_differential_evolution(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        generations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Adaptive Differential Evolution (JADE).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            generations: Número de generaciones
            
        Returns:
            Trayectoria optimizada usando JADE
        """
        logger.debug(f"JADE: pop={population_size}, gen={generations}")
        
        # Inicializar
        population = []
        for _ in range(population_size):
            trajectory = self._generate_initial_trajectory(start, goal)
            population.append(trajectory)
        
        # Parámetros adaptativos
        mu_F = 0.5
        mu_CR = 0.5
        c = 0.1
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for generation in range(generations):
            F_list = []
            CR_list = []
            new_population = []
            
            for i, target in enumerate(population):
                # Generar F y CR adaptativamente
                F = np.random.normal(mu_F, 0.1)
                F = np.clip(F, 0.1, 1.0)
                CR = np.random.normal(mu_CR, 0.1)
                CR = np.clip(CR, 0, 1)
                
                # Mutación y cruce
                candidates = [j for j in range(population_size) if j != i]
                best_idx = np.argmax([self.calculate_reward(population[j], obstacles) for j in candidates])
                a, b = np.random.choice(candidates, 2, replace=False)
                
                donor = self._differential_mutation(
                    population[best_idx], population[a], population[b], F
                )
                trial = self._differential_crossover(target, donor, CR)
                
                # Selección
                target_fitness = self.calculate_reward(target, obstacles)
                trial_fitness = self.calculate_reward(trial, obstacles)
                
                if trial_fitness > target_fitness:
                    new_population.append(trial)
                    F_list.append(F)
                    CR_list.append(CR)
                    
                    if trial_fitness > best_reward:
                        best_reward = trial_fitness
                        best_trajectory = trial
                else:
                    new_population.append(target)
            
            # Actualizar parámetros adaptativos
            if F_list:
                mu_F = (1 - c) * mu_F + c * np.mean(F_list)
            if CR_list:
                mu_CR = (1 - c) * mu_CR + c * np.mean(CR_list)
            
            population = new_population
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_shade(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        generations: int = 50,
        memory_size: int = 5
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando SHADE (Success-History based Adaptive DE).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            generations: Número de generaciones
            memory_size: Tamaño de la memoria
            
        Returns:
            Trayectoria optimizada usando SHADE
        """
        logger.debug(f"SHADE: pop={population_size}, gen={generations}, memory={memory_size}")
        
        # Inicializar
        population = []
        for _ in range(population_size):
            trajectory = self._generate_initial_trajectory(start, goal)
            population.append(trajectory)
        
        # Memoria de parámetros exitosos
        M_F = [0.5] * memory_size
        M_CR = [0.5] * memory_size
        k = 0
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for generation in range(generations):
            S_F = []
            S_CR = []
            new_population = []
            
            for i, target in enumerate(population):
                # Seleccionar de memoria
                r = np.random.randint(0, memory_size)
                F = np.random.normal(M_F[r], 0.1)
                F = np.clip(F, 0.1, 1.0)
                CR = np.random.normal(M_CR[r], 0.1)
                CR = np.clip(CR, 0, 1)
                
                # Mutación y cruce
                candidates = [j for j in range(population_size) if j != i]
                best_idx = np.argmax([self.calculate_reward(population[j], obstacles) for j in candidates])
                a, b = np.random.choice(candidates, 2, replace=False)
                
                donor = self._differential_mutation(
                    population[best_idx], population[a], population[b], F
                )
                trial = self._differential_crossover(target, donor, CR)
                
                # Selección
                target_fitness = self.calculate_reward(target, obstacles)
                trial_fitness = self.calculate_reward(trial, obstacles)
                
                if trial_fitness > target_fitness:
                    new_population.append(trial)
                    S_F.append(F)
                    S_CR.append(CR)
                    
                    if trial_fitness > best_reward:
                        best_reward = trial_fitness
                        best_trajectory = trial
                else:
                    new_population.append(target)
            
            # Actualizar memoria
            if S_F:
                # Lehmer mean
                M_F[k] = np.sum([f ** 2 for f in S_F]) / (np.sum(S_F) + 1e-6)
                M_CR[k] = np.mean(S_CR)
                k = (k + 1) % memory_size
            
            population = new_population
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_self_adaptive_de(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        generations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Self-Adaptive Differential Evolution (SaDE).
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            generations: Número de generaciones
            
        Returns:
            Trayectoria optimizada usando SaDE
        """
        logger.debug(f"SaDE: pop={population_size}, gen={generations}")
        
        # Inicializar
        population = []
        for _ in range(population_size):
            trajectory = self._generate_initial_trajectory(start, goal)
            population.append(trajectory)
        
        # Estrategias y sus probabilidades
        strategies = ["rand1", "rand2", "best1", "best2"]
        strategy_probs = [0.25] * 4
        strategy_success = [0] * 4
        strategy_attempts = [0] * 4
        
        best_trajectory = None
        best_reward = float('-inf')
        
        for generation in range(generations):
            new_population = []
            
            for i, target in enumerate(population):
                # Seleccionar estrategia según probabilidades
                strategy_idx = np.random.choice(len(strategies), p=strategy_probs)
                strategy = strategies[strategy_idx]
                strategy_attempts[strategy_idx] += 1
                
                # Aplicar estrategia
                trajectory = self.optimize_with_differential_evolution_strategy(
                    start, goal, obstacles, 1, 1, strategy
                )
                
                # Evaluar
                target_fitness = self.calculate_reward(target, obstacles)
                trial_fitness = self.calculate_reward(trajectory, obstacles)
                
                if trial_fitness > target_fitness:
                    new_population.append(trajectory)
                    strategy_success[strategy_idx] += 1
                    
                    if trial_fitness > best_reward:
                        best_reward = trial_fitness
                        best_trajectory = trajectory
                else:
                    new_population.append(target)
            
            # Actualizar probabilidades
            for idx in range(len(strategies)):
                if strategy_attempts[idx] > 0:
                    success_rate = strategy_success[idx] / strategy_attempts[idx]
                    strategy_probs[idx] = success_rate
            
            # Normalizar probabilidades
            total_prob = sum(strategy_probs)
            if total_prob > 0:
                strategy_probs = [p / total_prob for p in strategy_probs]
            else:
                strategy_probs = [0.25] * 4
            
            population = new_population
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_composite_de(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        generations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización usando Composite Differential Evolution.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            generations: Número de generaciones
            
        Returns:
            Trayectoria optimizada usando Composite DE
        """
        logger.debug(f"Composite DE: pop={population_size}, gen={generations}")
        
        # Combinar múltiples estrategias DE
        strategies = ["rand1", "best1", "rand2", "best2"]
        results = []
        
        for strategy in strategies:
            trajectory = self.optimize_with_differential_evolution_strategy(
                start, goal, obstacles, population_size, generations // len(strategies), strategy
            )
            reward = self.calculate_reward(trajectory, obstacles)
            results.append((trajectory, reward))
        
        # Seleccionar mejor
        best_idx = np.argmax([r[1] for r in results])
        return results[best_idx][0]
    
