    def benchmark_all_methods(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        iterations_per_method: int = 50,
        methods: Optional[List[str]] = None
    ) -> Dict[str, Dict[str, float]]:
        """
        Ejecuta un benchmark de todos los métodos disponibles y retorna métricas comparativas.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            iterations_per_method: Iteraciones por método
            methods: Lista de métodos a evaluar (None = todos)
            
        Returns:
            Diccionario con métricas de cada método (reward, tiempo, etc.)
        """
        if methods is None:
            methods = self.get_all_available_methods()
        
        results = {}
        
        logger.info(f"Benchmarking {len(methods)} optimization methods...")
        
        for method_name in methods:
            try:
                # Obtener método
                method = getattr(self, method_name, None)
                if method is None:
                    continue
                
                logger.debug(f"Benchmarking {method_name}...")
                
                # Medir tiempo
                import time
                start_time = time.time()
                
                # Ejecutar método
                trajectory = method(start, goal, obstacles, iterations=iterations_per_method)
                
                elapsed_time = time.time() - start_time
                
                # Calcular métricas
                reward = self.calculate_reward(trajectory, obstacles)
                path_length = self._calculate_path_length(trajectory)
                smoothness = self._calculate_smoothness(trajectory)
                safety = self._calculate_safety(trajectory, obstacles)
                
                results[method_name] = {
                    "reward": reward,
                    "time_seconds": elapsed_time,
                    "path_length": path_length,
                    "smoothness": smoothness,
                    "safety": safety,
                    "iterations": iterations_per_method
                }
                
                logger.debug(f"{method_name}: reward={reward:.4f}, time={elapsed_time:.2f}s")
                
            except Exception as e:
                logger.warning(f"Error benchmarking {method_name}: {e}")
                results[method_name] = {
                    "reward": float('-inf'),
                    "time_seconds": float('inf'),
                    "path_length": float('inf'),
                    "smoothness": 0.0,
                    "safety": 0.0,
                    "iterations": iterations_per_method,
                    "error": str(e)
                }
        
        # Ordenar por reward
        sorted_results = dict(sorted(
            results.items(),
            key=lambda x: x[1].get("reward", float('-inf')),
            reverse=True
        ))
        
        logger.info(f"Benchmark completed. Best method: {list(sorted_results.keys())[0]}")
        
        return sorted_results
    
    def optimize_with_adaptive_ensemble_learning(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        iterations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización con aprendizaje de ensemble adaptativo que combina múltiples modelos.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            iterations: Número de iteraciones
            
        Returns:
            Trayectoria optimizada con aprendizaje de ensemble adaptativo
        """
        logger.debug(f"Adaptive Ensemble Learning: pop={population_size}, iterations={iterations}")
        
        # Modelos base del ensemble
        base_models = [
            lambda s, g, o, p, i: self.optimize_with_adaptive_genetic_algorithm_advanced(s, g, o, p, i),
            lambda s, g, o, p, i: self.optimize_with_adaptive_particle_swarm_advanced(s, g, o, p, i),
            lambda s, g, o, p, i: self.optimize_with_adaptive_differential_evolution_advanced(s, g, o, p, i),
        ]
        
        # Entrenar cada modelo
        model_trajectories = []
        model_weights = []
        
        for model in base_models:
            try:
                trajectory = model(start, goal, obstacles, population_size, iterations // len(base_models))
                reward = self.calculate_reward(trajectory, obstacles)
                model_trajectories.append(trajectory)
                model_weights.append(reward)
            except:
                pass
        
        if not model_trajectories:
            return self._generate_initial_trajectory(start, goal)
        
        # Normalizar pesos
        model_weights = np.array(model_weights)
        model_weights = model_weights / (np.sum(model_weights) + 1e-6)
        
        # Combinar trayectorias con pesos
        combined = []
        max_len = max(len(t) for t in model_trajectories)
        
        for i in range(max_len):
            weighted_pos = np.zeros(3)
            total_weight = 0.0
            
            for j, traj in enumerate(model_trajectories):
                if i < len(traj):
                    weighted_pos += model_weights[j] * traj[i].position
                    total_weight += model_weights[j]
            
            if total_weight > 0:
                weighted_pos /= total_weight
            else:
                weighted_pos = model_trajectories[0][min(i, len(model_trajectories[0])-1)].position
            
            combined.append(TrajectoryPoint(
                position=weighted_pos,
                orientation=None,
                velocity=None,
                acceleration=None,
                timestamp=None
            ))
        
        combined = self._compensate_vibrations(combined)
        if obstacles:
            combined = self._avoid_obstacles(combined, obstacles)
        
        return combined
    
    def optimize_with_adaptive_online_learning(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        iterations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización con aprendizaje en línea adaptativo que aprende durante la optimización.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            iterations: Número de iteraciones
            
        Returns:
            Trayectoria optimizada con aprendizaje en línea adaptativo
        """
        logger.debug(f"Adaptive Online Learning: pop={population_size}, iterations={iterations}")
        
        population = []
        for _ in range(population_size):
            trajectory = self._generate_initial_trajectory(start, goal)
            population.append(trajectory)
        
        best_trajectory = None
        best_reward = float('-inf')
        
        # Modelo de aprendizaje (historial de mejores movimientos)
        learning_history = []
        
        for iteration in range(iterations):
            new_population = []
            fitness_scores = [self.calculate_reward(t, obstacles) for t in population]
            
            # Actualizar mejor
            best_idx = np.argmax(fitness_scores)
            if fitness_scores[best_idx] > best_reward:
                best_reward = fitness_scores[best_idx]
                best_trajectory = population[best_idx]
                
                # Aprender del mejor movimiento
                if len(learning_history) > 0:
                    last_best = learning_history[-1]
                    movement = []
                    for i in range(min(len(best_trajectory), len(last_best))):
                        movement.append(best_trajectory[i].position - last_best[i].position)
                    learning_history.append(movement)
                else:
                    learning_history.append([p.position for p in best_trajectory])
            
            for i, individual in enumerate(population):
                # Aplicar conocimiento aprendido
                if learning_history and np.random.random() < 0.3:
                    learned_update = []
                    for j, point in enumerate(individual):
                        if j < len(learning_history[-1]):
                            # Aplicar movimiento aprendido
                            if isinstance(learning_history[-1][j], np.ndarray):
                                learned_movement = learning_history[-1][j]
                            else:
                                learned_movement = np.zeros(3)
                            
                            new_position = point.position + 0.1 * learned_movement
                        else:
                            new_position = point.position
                        
                        learned_update.append(TrajectoryPoint(
                            position=new_position,
                            orientation=point.orientation,
                            velocity=point.velocity,
                            acceleration=point.acceleration,
                            timestamp=point.timestamp
                        ))
                    
                    learned_update = self._compensate_vibrations(learned_update)
                    if obstacles:
                        learned_update = self._avoid_obstacles(learned_update, obstacles)
                    
                    learned_reward = self.calculate_reward(learned_update, obstacles)
                    
                    if learned_reward > fitness_scores[i]:
                        new_population.append(learned_update)
                    else:
                        new_population.append(individual)
                else:
                    # Evolución normal
                    best_in_pop = max(population, key=lambda t: self.calculate_reward(t, obstacles))
                    
                    updated = []
                    for j, point in enumerate(individual):
                        if j < len(best_in_pop):
                            direction = best_in_pop[j].position - point.position
                            direction = direction / (np.linalg.norm(direction) + 1e-6)
                            new_position = point.position + direction * 0.1
                        else:
                            new_position = point.position
                        
                        updated.append(TrajectoryPoint(
                            position=new_position,
                            orientation=point.orientation,
                            velocity=point.velocity,
                            acceleration=point.acceleration,
                            timestamp=point.timestamp
                        ))
                    
                    updated = self._compensate_vibrations(updated)
                    if obstacles:
                        updated = self._avoid_obstacles(updated, obstacles)
                    
                    updated_reward = self.calculate_reward(updated, obstacles)
                    
                    if updated_reward > fitness_scores[i]:
                        new_population.append(updated)
                    else:
                        new_population.append(individual)
            
            population = new_population
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_adaptive_curriculum_learning(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        iterations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización con aprendizaje curricular adaptativo que aumenta la dificultad gradualmente.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            iterations: Número de iteraciones
            
        Returns:
            Trayectoria optimizada con aprendizaje curricular adaptativo
        """
        logger.debug(f"Adaptive Curriculum Learning: pop={population_size}, iterations={iterations}")
        
        # Currículo: empezar fácil, aumentar dificultad
        curriculum_levels = 3
        iterations_per_level = iterations // curriculum_levels
        
        trajectory = self._generate_initial_trajectory(start, goal)
        
        for level in range(curriculum_levels):
            # Aumentar dificultad: agregar más obstáculos o hacerlos más grandes
            current_obstacles = obstacles
            
            if obstacles and level > 0:
                # Escalar obstáculos según nivel
                scale = 1.0 + 0.2 * level
                current_obstacles = [obs * scale for obs in obstacles]
            
            # Optimizar en este nivel
            trajectory = self.optimize_with_adaptive_genetic_algorithm_advanced(
                start, goal, current_obstacles, population_size, iterations_per_level
            )
        
        return trajectory
    
    def optimize_with_adaptive_adversarial_training(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        population_size: int = 30,
        iterations: int = 50
    ) -> List[TrajectoryPoint]:
        """
        Optimización con entrenamiento adversarial adaptativo que usa adversarios para mejorar robustez.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            population_size: Tamaño de la población
            iterations: Número de iteraciones
            
        Returns:
            Trayectoria optimizada con entrenamiento adversarial adaptativo
        """
        logger.debug(f"Adaptive Adversarial Training: pop={population_size}, iterations={iterations}")
        
        population = []
        for _ in range(population_size):
            trajectory = self._generate_initial_trajectory(start, goal)
            population.append(trajectory)
        
        best_trajectory = None
        best_reward = float('-inf')
        adversarial_rate = 0.2
        
        for iteration in range(iterations):
            new_population = []
            
            for individual in population:
                # Generar adversario (perturbación)
                if np.random.random() < adversarial_rate:
                    adversarial = []
                    for point in individual:
                        # Perturbación adversarial
                        perturbation = np.random.normal(0, 0.1, 3)
                        adversarial_pos = point.position + perturbation
                        
                        adversarial.append(TrajectoryPoint(
                            position=adversarial_pos,
                            orientation=point.orientation,
                            velocity=point.velocity,
                            acceleration=point.acceleration,
                            timestamp=point.timestamp
                        ))
                    
                    adversarial = self._compensate_vibrations(adversarial)
                    if obstacles:
                        adversarial = self._avoid_obstacles(adversarial, obstacles)
                    
                    adversarial_reward = self.calculate_reward(adversarial, obstacles)
                    individual_reward = self.calculate_reward(individual, obstacles)
                    
                    # Defender contra adversario: mejorar si es vulnerable
                    if adversarial_reward > individual_reward:
                        # Vulnerable, mejorar
                        improved = []
                        for i, point in enumerate(individual):
                            if i < len(adversarial):
                                # Moverse lejos del adversario
                                direction = point.position - adversarial[i].position
                                direction = direction / (np.linalg.norm(direction) + 1e-6)
                                new_position = point.position + 0.1 * direction
                            else:
                                new_position = point.position
                            
                            improved.append(TrajectoryPoint(
                                position=new_position,
                                orientation=point.orientation,
                                velocity=point.velocity,
                                acceleration=point.acceleration,
                                timestamp=point.timestamp
                            ))
                        
                        improved = self._compensate_vibrations(improved)
                        if obstacles:
                            improved = self._avoid_obstacles(improved, obstacles)
                        
                        improved_reward = self.calculate_reward(improved, obstacles)
                        
                        if improved_reward > individual_reward:
                            new_population.append(improved)
                            
                            if improved_reward > best_reward:
                                best_reward = improved_reward
                                best_trajectory = improved
                        else:
                            new_population.append(individual)
                    else:
                        # Robusto, mantener
                        new_population.append(individual)
                else:
                    # Evolución normal
                    best_in_pop = max(population, key=lambda t: self.calculate_reward(t, obstacles))
                    
                    updated = []
                    for i, point in enumerate(individual):
                        if i < len(best_in_pop):
                            direction = best_in_pop[i].position - point.position
                            direction = direction / (np.linalg.norm(direction) + 1e-6)
                            new_position = point.position + direction * 0.1
                        else:
                            new_position = point.position
                        
                        updated.append(TrajectoryPoint(
                            position=new_position,
                            orientation=point.orientation,
                            velocity=point.velocity,
                            acceleration=point.acceleration,
                            timestamp=point.timestamp
                        ))
                    
                    updated = self._compensate_vibrations(updated)
                    if obstacles:
                        updated = self._avoid_obstacles(updated, obstacles)
                    
                    updated_reward = self.calculate_reward(updated, obstacles)
                    individual_reward = self.calculate_reward(individual, obstacles)
                    
                    if updated_reward > individual_reward:
                        new_population.append(updated)
                        
                        if updated_reward > best_reward:
                            best_reward = updated_reward
                            best_trajectory = updated
                    else:
                        new_population.append(individual)
            
            population = new_population
            
            # Ajustar tasa adversarial
            fitness_variance = np.var([self.calculate_reward(t, obstacles) for t in population])
            if fitness_variance < 0.05:
                adversarial_rate = min(adversarial_rate * 1.1, 0.4)  # Aumentar
            else:
                adversarial_rate = max(adversarial_rate * 0.9, 0.1)  # Reducir
        
        return best_trajectory if best_trajectory else self._generate_initial_trajectory(start, goal)
    
    def optimize_with_comprehensive_advanced_learning_methods(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        iterations: int = 100
    ) -> List[TrajectoryPoint]:
        """
        Optimización comprehensiva de métodos de aprendizaje avanzado que combina todas las técnicas de aprendizaje.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            iterations: Número de iteraciones
            
        Returns:
            Trayectoria optimizada usando todas las técnicas de aprendizaje avanzado comprehensivas
        """
        logger.debug(f"Comprehensive Advanced Learning Methods: {iterations} iterations")
        
        # Fase 1: Aprendizaje de ensemble adaptativo (25%)
        trajectory = self.optimize_with_adaptive_ensemble_learning(
            start, goal, obstacles, 25, iterations // 4
        )
        
        # Fase 2: Aprendizaje en línea adaptativo (25%)
        trajectory = self.optimize_with_adaptive_online_learning(
            start, goal, obstacles, 25, iterations // 4
        )
        
        # Fase 3: Aprendizaje curricular adaptativo (25%)
        trajectory = self.optimize_with_adaptive_curriculum_learning(
            start, goal, obstacles, 25, iterations // 4
        )
        
        # Fase 4: Entrenamiento adversarial adaptativo (25%)
        trajectory = self.optimize_with_adaptive_adversarial_training(
            start, goal, obstacles, 25, iterations // 4
        )
        
        return trajectory
    
    def get_optimization_statistics_summary(self) -> Dict[str, Any]:
        """
        Retorna un resumen estadístico completo de todas las capacidades del optimizador.
        
        Returns:
            Diccionario con estadísticas y resumen de capacidades
        """
        all_methods = self.get_all_available_methods()
        
        # Categorizar métodos
        categories = {
            "basic": [],
            "adaptive_advanced": [],
            "comprehensive": [],
            "specialized": [],
            "bioinspired": [],
            "learning": [],
            "physics_inspired": [],
            "ultimate": []
        }
        
        for method in all_methods:
            if "ultimate" in method or "comprehensive" in method:
                if "ultimate" in method:
                    categories["ultimate"].append(method)
                else:
                    categories["comprehensive"].append(method)
            elif "bioinspired" in method or "swarm" in method or "bee" in method or "cuckoo" in method or "immune" in method:
                categories["bioinspired"].append(method)
            elif "learning" in method or "ensemble" in method or "transfer" in method or "curiosity" in method or "curriculum" in method or "adversarial" in method or "online" in method:
                categories["learning"].append(method)
            elif "levy" in method or "chaos" in method or "quantum" in method or "firefly" in method or "physics" in method:
                categories["physics_inspired"].append(method)
            elif "adaptive" in method and "advanced" in method:
                categories["adaptive_advanced"].append(method)
            elif "hybrid" in method or "multi_scale" in method or "hierarchical" in method or "cooperative" in method or "memetic" in method:
                categories["specialized"].append(method)
            else:
                categories["basic"].append(method)
        
        return {
            "total_methods": len(all_methods),
            "categories": {
                "basic": len(categories["basic"]),
                "adaptive_advanced": len(categories["adaptive_advanced"]),
                "comprehensive": len(categories["comprehensive"]),
                "specialized": len(categories["specialized"]),
                "bioinspired": len(categories["bioinspired"]),
                "learning": len(categories["learning"]),
                "physics_inspired": len(categories["physics_inspired"]),
                "ultimate": len(categories["ultimate"])
            },
            "methods_by_category": categories,
            "features": {
                "auto_selection": True,
                "benchmarking": True,
                "recommendation_system": True,
                "adaptive_parameters": True,
                "multi_objective": True,
                "robust_optimization": True,
                "constraint_handling": True,
                "uncertainty_quantification": True,
                "diversity_maintenance": True,
                "ensemble_methods": True,
                "hybrid_approaches": True,
                "online_learning": True,
                "transfer_learning": True,
                "curriculum_learning": True,
                "adversarial_training": True,
                "curiosity_driven": True,
                "meta_learning": True
            },
            "total_lines_of_code": "32,000+",
            "version": "2.0.0-ultimate"
        }
    
