    def get_method_documentation(self, method_name: str) -> Dict[str, Any]:
        """
        Retorna documentación detallada de un método específico.
        
        Args:
            method_name: Nombre del método
            
        Returns:
            Diccionario con documentación del método
        """
        method = getattr(self, method_name, None)
        if method is None:
            return {"error": f"Method {method_name} not found"}
        
        doc = {
            "name": method_name,
            "docstring": method.__doc__,
            "signature": str(method.__code__.co_varnames[:method.__code__.co_argcount]),
            "available": True
        }
        
        return doc
    
    def compare_methods_performance(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        method_names: Optional[List[str]] = None,
        iterations: int = 50
    ) -> Dict[str, Any]:
        """
        Compara el rendimiento de múltiples métodos específicos.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            method_names: Lista de nombres de métodos a comparar
            iterations: Número de iteraciones por método
            
        Returns:
            Diccionario con comparación de rendimiento
        """
        if method_names is None:
            method_names = [
                "optimize_with_genetic_algorithm",
                "optimize_with_adaptive_genetic_algorithm_advanced",
                "optimize_with_comprehensive_adaptive_metaheuristics",
                "optimize_with_ultimate_comprehensive_optimizer"
            ]
        
        results = {}
        
        for method_name in method_names:
            try:
                method = getattr(self, method_name, None)
                if method is None:
                    continue
                
                import time
                start_time = time.time()
                
                trajectory = method(start, goal, obstacles, iterations=iterations)
                
                elapsed_time = time.time() - start_time
                
                reward = self.calculate_reward(trajectory, obstacles)
                path_length = self._calculate_path_length(trajectory)
                smoothness = self._calculate_smoothness(trajectory)
                safety = self._calculate_safety(trajectory, obstacles)
                
                results[method_name] = {
                    "reward": reward,
                    "time_seconds": elapsed_time,
                    "path_length": path_length,
                    "smoothness": smoothness,
                    "safety": safety,
                    "efficiency": reward / elapsed_time if elapsed_time > 0 else 0
                }
            except Exception as e:
                results[method_name] = {"error": str(e)}
        
        # Encontrar mejor en cada métrica
        if results:
            best_reward = max(results.items(), key=lambda x: x[1].get("reward", float('-inf')))
            fastest = min(results.items(), key=lambda x: x[1].get("time_seconds", float('inf')))
            most_efficient = max(results.items(), key=lambda x: x[1].get("efficiency", float('-inf')))
            
            return {
                "comparison": results,
                "best_reward": {"method": best_reward[0], "value": best_reward[1].get("reward")},
                "fastest": {"method": fastest[0], "value": fastest[1].get("time_seconds")},
                "most_efficient": {"method": most_efficient[0], "value": most_efficient[1].get("efficiency")}
            }
        
        return {"error": "No valid results"}
    
    def optimize_with_smart_auto_tuning(
        self,
        start: TrajectoryPoint,
        goal: TrajectoryPoint,
        obstacles: Optional[List[np.ndarray]] = None,
        time_budget: float = 60.0,
        quality_target: float = 0.9
    ) -> Tuple[List[TrajectoryPoint], Dict[str, Any]]:
        """
        Optimización con auto-ajuste inteligente que selecciona y ajusta métodos automáticamente.
        
        Args:
            start: Punto inicial
            goal: Punto objetivo
            obstacles: Lista de obstáculos
            time_budget: Presupuesto de tiempo en segundos
            quality_target: Objetivo de calidad (0-1)
            
        Returns:
            Tupla con trayectoria optimizada y métricas del proceso
        """
        logger.info(f"Smart Auto-Tuning: time_budget={time_budget}s, quality_target={quality_target}")
        
        import time
        start_time = time.time()
        
        # Fase 1: Evaluación rápida de métodos básicos
        quick_methods = [
            "optimize_with_genetic_algorithm",
            "optimize_with_particle_swarm",
            "optimize_with_differential_evolution"
        ]
        
        quick_results = {}
        for method_name in quick_methods:
            if time.time() - start_time > time_budget * 0.3:
                break
            
            try:
                method = getattr(self, method_name, None)
                if method is None:
                    continue
                
                method_start = time.time()
                trajectory = method(start, goal, obstacles, iterations=20)
                method_time = time.time() - method_start
                
                reward = self.calculate_reward(trajectory, obstacles)
                normalized_reward = (reward + 100) / 200  # Normalizar aproximadamente
                
                quick_results[method_name] = {
                    "reward": reward,
                    "normalized_reward": normalized_reward,
                    "time": method_time,
                    "trajectory": trajectory
                }
            except:
                pass
        
        # Seleccionar mejor método rápido
        if quick_results:
            best_quick = max(quick_results.items(), key=lambda x: x[1]["normalized_reward"])
            
            # Si ya alcanzamos el objetivo de calidad, retornar
            if best_quick[1]["normalized_reward"] >= quality_target:
                return best_quick[1]["trajectory"], {
                    "method_used": best_quick[0],
                    "time_used": time.time() - start_time,
                    "quality_achieved": best_quick[1]["normalized_reward"],
                    "phase": "quick_evaluation"
                }
        
        # Fase 2: Optimización avanzada si hay tiempo
        remaining_time = time_budget - (time.time() - start_time)
        
        if remaining_time > time_budget * 0.3:
            # Usar método comprehensivo
            try:
                advanced_start = time.time()
                trajectory = self.optimize_with_comprehensive_adaptive_metaheuristics(
                    start, goal, obstacles, iterations=int(remaining_time * 10)
                )
                advanced_time = time.time() - advanced_start
                
                reward = self.calculate_reward(trajectory, obstacles)
                normalized_reward = (reward + 100) / 200
                
                return trajectory, {
                    "method_used": "optimize_with_comprehensive_adaptive_metaheuristics",
                    "time_used": time.time() - start_time,
                    "quality_achieved": normalized_reward,
                    "phase": "advanced_optimization"
                }
            except:
                pass
        
        # Fallback: retornar mejor de evaluación rápida
        if quick_results:
            best = max(quick_results.items(), key=lambda x: x[1]["normalized_reward"])
            return best[1]["trajectory"], {
                "method_used": best[0],
                "time_used": time.time() - start_time,
                "quality_achieved": best[1]["normalized_reward"],
                "phase": "quick_evaluation_fallback"
            }
        
        # Último fallback
        trajectory = self._generate_initial_trajectory(start, goal)
        return trajectory, {
            "method_used": "fallback",
            "time_used": time.time() - start_time,
            "quality_achieved": 0.0,
            "phase": "fallback"
        }

